/// Git stash: push all current changes as a named stash. Returns the stash OID.
#[tauri::command]
pub async fn git_stash_create(
    path: String,
    name: String,
    state: tauri::State<'_, AppState>,
) -> Result<String, String> {
    let workspace = state.workspace.lock().await;
    let root = workspace.folders().first().cloned().unwrap_or_else(|| PathBuf::from(&path));
    drop(workspace);
    vibe_core::git::create_stash(&root, &name).map_err(|e| e.to_string())
}

/// Git stash pop: apply + drop the most recent stash.
#[tauri::command]
pub async fn git_stash_pop(
    path: String,
    state: tauri::State<'_, AppState>,
) -> Result<(), String> {
    let workspace = state.workspace.lock().await;
    let root = workspace.folders().first().cloned().unwrap_or_else(|| PathBuf::from(&path));
    drop(workspace);
    vibe_core::git::pop_stash(&root).map_err(|e| e.to_string())
}

/// LSP: notify that a document was opened.
#[tauri::command]
pub async fn lsp_did_open(
    language: String,
    root_path: String,
    uri: String,
    text: String,
    state: tauri::State<'_, AppState>,
) -> Result<(), String> {
    use lsp_types::{DidOpenTextDocumentParams, TextDocumentItem};
    let mut manager = state.lsp_manager.lock().await;
    let client = manager
        .get_client_for_language(&language, &PathBuf::from(&root_path))
        .await
        .map_err(|e| e.to_string())?;
    let doc_uri: lsp_types::Uri = uri.parse().map_err(|_| "Invalid URI".to_string())?;
    client
        .did_open(DidOpenTextDocumentParams {
            text_document: TextDocumentItem {
                uri: doc_uri,
                language_id: language.clone(),
                version: 1,
                text,
            },
        })
        .await
        .map_err(|e| e.to_string())
}

/// LSP: notify that a document's content changed.
#[tauri::command]
pub async fn lsp_did_change(
    language: String,
    root_path: String,
    uri: String,
    text: String,
    version: i32,
    state: tauri::State<'_, AppState>,
) -> Result<(), String> {
    use lsp_types::{DidChangeTextDocumentParams, VersionedTextDocumentIdentifier, TextDocumentContentChangeEvent};
    let mut manager = state.lsp_manager.lock().await;
    let client = manager
        .get_client_for_language(&language, &PathBuf::from(&root_path))
        .await
        .map_err(|e| e.to_string())?;
    let doc_uri: lsp_types::Uri = uri.parse().map_err(|_| "Invalid URI".to_string())?;
    client
        .did_change(DidChangeTextDocumentParams {
            text_document: VersionedTextDocumentIdentifier { uri: doc_uri, version },
            content_changes: vec![TextDocumentContentChangeEvent {
                range: None,
                range_length: None,
                text,
            }],
        })
        .await
        .map_err(|e| e.to_string())
}

/// LSP: notify that a document was saved.
#[tauri::command]
pub async fn lsp_did_save(
    language: String,
    root_path: String,
    uri: String,
    state: tauri::State<'_, AppState>,
) -> Result<(), String> {
    use lsp_types::{DidSaveTextDocumentParams, TextDocumentIdentifier};
    let mut manager = state.lsp_manager.lock().await;
    let client = manager
        .get_client_for_language(&language, &PathBuf::from(&root_path))
        .await
        .map_err(|e| e.to_string())?;
    let doc_uri: lsp_types::Uri = uri.parse().map_err(|_| "Invalid URI".to_string())?;
    client
        .did_save(DidSaveTextDocumentParams {
            text_document: TextDocumentIdentifier { uri: doc_uri },
            text: None,
        })
        .await
        .map_err(|e| e.to_string())
}

/// List all supported LSP servers with their availability status and install instructions.
#[tauri::command]
pub async fn lsp_list_servers(
    state: tauri::State<'_, AppState>,
) -> Result<serde_json::Value, String> {
    let manager = state.lsp_manager.lock().await;
    let servers = manager.check_available();
    let supported = manager.supported_languages();

    let mut result = Vec::new();
    for (lang, cmd, available) in &servers {
        let install = supported.iter().find(|(l, _, _)| l == lang).map(|(_, _, h)| h.as_str()).unwrap_or("");
        result.push(serde_json::json!({
            "language": lang,
            "server": cmd,
            "available": available,
            "install_hint": install,
        }));
    }
    result.sort_by(|a, b| a["language"].as_str().cmp(&b["language"].as_str()));
    Ok(serde_json::json!(result))
}

/// Inline AI completion using FIM format for Ollama or chat prompt for others.
/// Returns the completion text (suffix to insert at cursor).
#[tauri::command]
pub async fn request_inline_completion(
    prefix: String,
    suffix: String,
    language: String,
    provider: String,
    state: tauri::State<'_, AppState>,
) -> Result<String, String> {
    let mut chat_engine = state.chat_engine.lock().await;
    chat_engine.set_provider_by_name(&provider).map_err(|e| e.to_string())?;

    // Use FIM format for Ollama (fill-in-the-middle), chat for others
    let prompt = if provider.to_lowercase().contains("ollama") {
        format!(
            "<|fim_prefix|>{}<|fim_suffix|>{}<|fim_middle|>",
            &prefix, &suffix
        )
    } else {
        format!(
            "Complete the following {} code. Return ONLY the code to insert at the cursor, nothing else.\n\nPrefix:\n```{}\n{}\n```\n\nSuffix:\n```{}\n{}\n```\n\nCompletion:",
            language, language, prefix, language, suffix
        )
    };

    let messages = vec![Message {
        role: vibe_ai::MessageRole::User,
        content: prompt,
    }];
    let result = chat_engine.chat(&messages, None).await.map_err(|e| e.to_string())?;

    // Strip any markdown code fences from the response
    // NOTE: Use strip_prefix (exact literal match), NOT trim_start_matches
    // (which treats the &str as a character set and strips individual chars)
    let mut clean = result.trim();
    if let Some(rest) = clean.strip_prefix("```") {
        clean = rest.strip_prefix(language.as_str()).unwrap_or(rest);
    }
    if let Some(rest) = clean.strip_suffix("```") {
        clean = rest;
    }
    let clean = clean.trim().to_string();

    Ok(clean)
}

/// Flow tracking: record a developer activity event.
#[tauri::command]
pub async fn track_flow_event(
    kind: String,
    data: String,
    state: tauri::State<'_, AppState>,
) -> Result<(), String> {
    state.flow.lock().await.record(&kind, &data);
    Ok(())
}

/// Flow context: return recent developer activity as a formatted context string.
#[tauri::command]
pub async fn get_flow_context(state: tauri::State<'_, AppState>) -> Result<String, String> {
    Ok(state.flow.lock().await.context_string(20))
}

// ─── Phase 4 Commands ─────────────────────────────────────────────────────────

/// Serializable info sent to the frontend when a tool call needs approval.
#[derive(Serialize, Clone)]
pub struct AgentPendingPayload {
    pub name: String,
    pub summary: String,
    pub is_destructive: bool,
}

/// Serializable step info sent to the frontend after a tool call executes.
#[derive(Serialize, Clone)]
pub struct AgentStepPayload {
    pub step_num: usize,
    pub tool_name: String,
    pub tool_summary: String,
    pub output: String,
    pub success: bool,
    pub approved: bool,
}

/// Start an autonomous agent task. Emits Tauri events:
/// - `agent:chunk`   — streaming LLM text (String)
/// - `agent:pending` — tool call needs approval (AgentPendingPayload)
/// - `agent:step`    — step completed (AgentStepPayload)
/// - `agent:complete`— task done (String summary)
/// - `agent:error`   — error (String)
#[tauri::command]
pub async fn start_agent_task(
    task: String,
    approval_policy: String,
    provider: String,
    app_handle: tauri::AppHandle,
    state: tauri::State<'_, AppState>,
) -> Result<(), String> {
    use vibe_ai::{AgentLoop, AgentContext, ApprovalPolicy, AgentEvent};
    use crate::agent_executor::TauriToolExecutor;

    // Get the AI provider
    let provider_arc = {
        let mut engine = state.chat_engine.lock().await;
        engine.set_provider_by_name(&provider).map_err(|e| e.to_string())?;
        engine.active_provider().ok_or("No active provider")?.clone()
    };

    // Get workspace root
    let workspace_root = {
        let ws = state.workspace.lock().await;
        ws.folders().first().cloned().unwrap_or_else(|| PathBuf::from("."))
    };

    // Build agent context
    let git_branch = vibe_core::git::get_current_branch(&workspace_root).ok();
    let git_diff = vibe_core::git::get_repo_diff(&workspace_root).ok().map(|d| {
        if d.len() > 2000 {
            let end = d.char_indices().nth(2000).map(|(i,_)| i).unwrap_or(d.len());
            d[..end].to_string() + "\n…(truncated)"
        } else { d }
    });
    let memory_context = {
        let mem_path = workspace_root.join(".vibe").join("memory.md");
        std::fs::read_to_string(&mem_path).ok().filter(|s| !s.trim().is_empty())
    };
    let context = AgentContext {
        workspace_root: workspace_root.clone(),
        open_files: vec![],
        git_branch,
        git_diff_summary: git_diff,
        flow_context: None,
        approved_plan: None,
        extra_skill_dirs: vec![],
        parent_session_id: None,
        depth: 0,
        active_agent_counter: None,
        team_bus: None,
        team_agent_id: None,
        project_summary: None,
        task_context_files: vec![],
        memory_context,
        auto_commit: false,
    };

    let executor = Arc::new(
        TauriToolExecutor::with_app(workspace_root.clone(), app_handle.clone())
            .with_provider(provider_arc.clone())
            .with_parent_context(context.clone()),
    );
    let approval = ApprovalPolicy::from_str(&approval_policy);
    let agent = AgentLoop::new(provider_arc, approval, executor)
        .with_policy(&workspace_root);

    let (event_tx, mut event_rx) = tokio::sync::mpsc::channel::<AgentEvent>(64);
    let agent_pending = state.agent_pending.clone();
    let abort_handle_slot = state.agent_abort_handle.clone();

    // Register this task in the Agent-OS dashboard tracker
    let agent_task_id = format!("agent-{}", chrono::Utc::now().timestamp_millis());
    let active_mode_for_stats = load_agent_modes_data().active_mode;
    {
        let dto = SubAgentDto {
            id: agent_task_id.clone(),
            role: "agent".to_string(),
            status: "working".to_string(),
            context_files: vec![],
            provider: provider.clone(),
            task_description: Some(task.clone()),
            result_summary: None,
            findings: vec![],
            files_modified: vec![],
            created_at: chrono::Utc::now().to_rfc3339(),
            completed_at: None,
            error: None,
            tokens_used: None,
        };
        let mut agents = state.sub_agents.lock().await;
        agents.push(dto);
    }
    let sub_agents_tracker = state.sub_agents.clone();

    // ── Checkpoint infrastructure ────────────────────────────────────────
    // Persist agent state after every step so we can resume partial runs.
    let checkpoint_dir = workspace_root.join(".vibe").join("agent-runs");
    let _ = std::fs::create_dir_all(&checkpoint_dir);
    let checkpoint_path = checkpoint_dir.join(format!("{}.json", &agent_task_id));
    let checkpoint = Arc::new(tokio::sync::Mutex::new(serde_json::json!({
        "id": agent_task_id,
        "task": task,
        "provider": provider,
        "approval_policy": approval_policy,
        "status": "working",
        "steps": [],
        "plan": null,
        "remaining_plan": [],
        "created_at": chrono::Utc::now().to_rfc3339(),
    })));
    // Write initial checkpoint
    {
        let ck = checkpoint.lock().await;
        let _ = std::fs::write(&checkpoint_path, serde_json::to_string_pretty(&*ck).unwrap_or_default());
    }
    let ck_arc = checkpoint.clone();
    let ck_path = checkpoint_path.clone();

    // Spawn the agent loop and store its abort handle for stop_agent_task.
    // We capture the JoinHandle so the bridge can detect panics / aborts.
    let join = tokio::spawn(async move {
        agent.run(&task, context, event_tx).await
    });
    *abort_handle_slot.lock().await = Some(join.abort_handle());

    // Bridge agent events → Tauri events.
    // When the channel closes without having received Complete/Error/Partial
    // (e.g. the agent task panicked or was aborted), we mark the sub-agent
    // as "failed" instead of leaving it stuck in "working".
    tokio::spawn(async move {
        let mut got_terminal = false;
        while let Some(event) = event_rx.recv().await {
            match event {
                AgentEvent::StreamChunk(text) => {
                    let _ = app_handle.emit("agent:chunk", text);
                }
                AgentEvent::ToolCallPending { call, result_tx } => {
                    let payload = AgentPendingPayload {
                        name: call.name().to_string(),
                        summary: call.summary(),
                        is_destructive: call.is_destructive(),
                    };
                    {
                        let mut slot = agent_pending.lock().await;
                        *slot = Some(PendingAgentCall { call, result_tx });
                    }
                    let _ = app_handle.emit("agent:pending", payload);
                }
                AgentEvent::ToolCallExecuted(step) => {
                    let payload = AgentStepPayload {
                        step_num: step.step_num,
                        tool_name: step.tool_call.name().to_string(),
                        tool_summary: step.tool_call.summary(),
                        output: step.tool_result.output.clone(),
                        success: step.tool_result.success,
                        approved: step.approved,
                    };
                    let _ = app_handle.emit("agent:step", payload);
                    // Checkpoint: persist step
                    {
                        let mut ck = ck_arc.lock().await;
                        if let Some(steps) = ck.get_mut("steps").and_then(|v| v.as_array_mut()) {
                            steps.push(serde_json::json!({
                                "step_num": step.step_num,
                                "tool_name": step.tool_call.name(),
                                "tool_summary": step.tool_call.summary(),
                                "success": step.tool_result.success,
                                "output_preview": &step.tool_result.output[..step.tool_result.output.len().min(500)],
                            }));
                        }
                        // Track plan if this was a plan_task call
                        if step.tool_call.name() == "plan_task" {
                            let plan_lines: Vec<&str> = step.tool_result.output
                                .lines().filter(|l| !l.trim().is_empty()).collect();
                            ck["plan"] = serde_json::json!(plan_lines);
                            ck["remaining_plan"] = serde_json::json!(plan_lines);
                        } else if ck.get("remaining_plan").and_then(|v| v.as_array()).map(|a| !a.is_empty()).unwrap_or(false) {
                            // Pop the first remaining plan item for each non-plan step
                            if let Some(arr) = ck.get_mut("remaining_plan").and_then(|v| v.as_array_mut()) {
                                if !arr.is_empty() { arr.remove(0); }
                            }
                        }
                        let _ = std::fs::write(&ck_path, serde_json::to_string_pretty(&*ck).unwrap_or_default());
                    }
                }
                AgentEvent::Complete(summary) => {
                    got_terminal = true;
                    let _ = app_handle.emit("agent:complete", summary.clone());
                    let estimated_tokens = (summary.len() as u64 / 4).max(1);
                    record_agent_run_stats(&active_mode_for_stats, estimated_tokens);
                    {
                        let mut agents = sub_agents_tracker.lock().await;
                        if let Some(a) = agents.iter_mut().find(|a| a.id == agent_task_id) {
                            a.status = "completed".to_string();
                            a.completed_at = Some(chrono::Utc::now().to_rfc3339());
                            a.result_summary = Some(summary.clone());
                            a.tokens_used = Some(estimated_tokens);
                        }
                    }
                    // Checkpoint: mark completed
                    {
                        let mut ck = ck_arc.lock().await;
                        ck["status"] = serde_json::json!("completed");
                        ck["result_summary"] = serde_json::json!(summary);
                        ck["completed_at"] = serde_json::json!(chrono::Utc::now().to_rfc3339());
                        let _ = std::fs::write(&ck_path, serde_json::to_string_pretty(&*ck).unwrap_or_default());
                    }
                    break;
                }
                AgentEvent::Partial { summary, steps_completed, steps_planned, remaining_plan } => {
                    got_terminal = true;
                    let payload = serde_json::json!({
                        "summary": &summary,
                        "steps_completed": steps_completed,
                        "steps_planned": steps_planned,
                        "remaining_plan": &remaining_plan,
                    });
                    let _ = app_handle.emit("agent:partial", payload);
                    let estimated_tokens = (summary.len() as u64 / 4).max(1);
                    record_agent_run_stats(&active_mode_for_stats, estimated_tokens);
                    {
                        let mut agents = sub_agents_tracker.lock().await;
                        if let Some(a) = agents.iter_mut().find(|a| a.id == agent_task_id) {
                            a.status = "partial".to_string();
                            a.completed_at = Some(chrono::Utc::now().to_rfc3339());
                            a.result_summary = Some(summary.clone());
                            a.tokens_used = Some(estimated_tokens);
                        }
                    }
                    // Checkpoint: mark partial with remaining plan
                    {
                        let mut ck = ck_arc.lock().await;
                        ck["status"] = serde_json::json!("partial");
                        ck["result_summary"] = serde_json::json!(summary);
                        ck["remaining_plan"] = serde_json::json!(remaining_plan);
                        ck["completed_at"] = serde_json::json!(chrono::Utc::now().to_rfc3339());
                        let _ = std::fs::write(&ck_path, serde_json::to_string_pretty(&*ck).unwrap_or_default());
                    }
                    break;
                }
                AgentEvent::Error(msg) => {
                    got_terminal = true;
                    let _ = app_handle.emit("agent:error", msg.clone());
                    {
                        let mut agents = sub_agents_tracker.lock().await;
                        if let Some(a) = agents.iter_mut().find(|a| a.id == agent_task_id) {
                            a.status = "failed".to_string();
                            a.error = Some(msg.clone());
                        }
                    }
                    // Checkpoint: mark failed
                    {
                        let mut ck = ck_arc.lock().await;
                        ck["status"] = serde_json::json!("failed");
                        ck["error"] = serde_json::json!(msg);
                        ck["completed_at"] = serde_json::json!(chrono::Utc::now().to_rfc3339());
                        let _ = std::fs::write(&ck_path, serde_json::to_string_pretty(&*ck).unwrap_or_default());
                    }
                    break;
                }
                AgentEvent::RetryableError { error, attempt, max_attempts, backoff_ms } => {
                    let payload = serde_json::json!({
                        "error": error,
                        "attempt": attempt,
                        "max_attempts": max_attempts,
                        "backoff_ms": backoff_ms,
                    });
                    let _ = app_handle.emit("agent:retry", payload);
                }
                AgentEvent::CircuitBreak { state, reason } => {
                    let payload = serde_json::json!({
                        "state": state.to_string(),
                        "reason": reason,
                    });
                    let _ = app_handle.emit("agent:circuit_break", payload);
                    if state == vibe_ai::agent::AgentHealthState::Blocked {
                        got_terminal = true;
                        let _ = app_handle.emit("agent:error", format!("Agent blocked: {}", reason));
                        break;
                    }
                }
            }
        }

        // Safety net: if the channel closed without a terminal event, the agent
        // task panicked, was aborted, or dropped the sender.  Mark as failed so
        // the sub-agent doesn't stay stuck in "working" forever.
        if !got_terminal {
            let msg = "Agent stream ended without completion signal (possible crash or abort)".to_string();
            let _ = app_handle.emit("agent:error", msg.clone());
            let mut agents = sub_agents_tracker.lock().await;
            if let Some(a) = agents.iter_mut().find(|a| a.id == agent_task_id) {
                a.status = "failed".to_string();
                a.error = Some(msg);
            }
        }
    });

    Ok(())
}

/// Respond to an agent tool-call approval prompt.
/// Abort the currently running agent task (if any).
/// Emits `agent:error` with "Agent stopped by user" so the frontend can reset its state.
#[tauri::command]
pub async fn stop_agent_task(
    app_handle: tauri::AppHandle,
    state: tauri::State<'_, AppState>,
) -> Result<(), String> {
    let handle = {
        let mut slot = state.agent_abort_handle.lock().await;
        slot.take()
    };
    if let Some(h) = handle {
        h.abort();
    }
    // Clear any pending approval so the UI doesn't stay blocked
    {
        let mut slot = state.agent_pending.lock().await;
        *slot = None;
    }
    // Mark any tracked agent task as cancelled in the dashboard
    {
        let mut agents = state.sub_agents.lock().await;
        for a in agents.iter_mut() {
            if a.role == "agent" && a.status == "working" {
                a.status = "cancelled".to_string();
            }
        }
    }
    let _ = app_handle.emit("agent:error", "Agent stopped by user");
    Ok(())
}

/// List resumable agent checkpoints (partial or failed runs).
#[tauri::command]
pub async fn list_agent_checkpoints(
    state: tauri::State<'_, AppState>,
) -> Result<serde_json::Value, String> {
    let workspace_root = {
        let ws = state.workspace.lock().await;
        ws.folders().first().cloned().unwrap_or_else(|| PathBuf::from("."))
    };
    let dir = workspace_root.join(".vibe").join("agent-runs");
    let mut runs: Vec<serde_json::Value> = Vec::new();
    if dir.is_dir() {
        if let Ok(entries) = std::fs::read_dir(&dir) {
            for entry in entries.flatten() {
                if entry.path().extension().and_then(|e| e.to_str()) == Some("json") {
                    if let Ok(data) = std::fs::read_to_string(entry.path()) {
                        if let Ok(val) = serde_json::from_str::<serde_json::Value>(&data) {
                            let status = val.get("status").and_then(|v| v.as_str()).unwrap_or("");
                            if status == "partial" || status == "failed" {
                                runs.push(val);
                            }
                        }
                    }
                }
            }
        }
    }
    Ok(serde_json::json!(runs))
}

/// Resume a partial/failed agent run from its checkpoint.
/// Reads the checkpoint, constructs a continuation prompt with the
/// remaining plan items and context from completed steps, then starts
/// a new agent run.
#[tauri::command]
pub async fn resume_agent_task(
    checkpoint_id: String,
    app_handle: tauri::AppHandle,
    state: tauri::State<'_, AppState>,
) -> Result<(), String> {
    let workspace_root = {
        let ws = state.workspace.lock().await;
        ws.folders().first().cloned().unwrap_or_else(|| PathBuf::from("."))
    };
    let ck_path = workspace_root.join(".vibe").join("agent-runs").join(format!("{}.json", &checkpoint_id));
    let ck_data = std::fs::read_to_string(&ck_path)
        .map_err(|e| format!("Cannot read checkpoint {}: {}", checkpoint_id, e))?;
    let ck: serde_json::Value = serde_json::from_str(&ck_data)
        .map_err(|e| format!("Invalid checkpoint JSON: {}", e))?;

    let original_task = ck.get("task").and_then(|v| v.as_str()).unwrap_or("").to_string();
    let provider = ck.get("provider").and_then(|v| v.as_str()).unwrap_or("").to_string();
    let approval_policy = ck.get("approval_policy").and_then(|v| v.as_str()).unwrap_or("auto-edit").to_string();

    // Build continuation context from completed steps
    let steps = ck.get("steps").and_then(|v| v.as_array()).cloned().unwrap_or_default();
    let remaining = ck.get("remaining_plan").and_then(|v| v.as_array()).cloned().unwrap_or_default();

    let mut context_parts = vec![
        format!("RESUMING INCOMPLETE TASK. Original task: {}", original_task),
        format!("\n{} steps were completed previously:", steps.len()),
    ];
    for s in &steps {
        let name = s.get("tool_name").and_then(|v| v.as_str()).unwrap_or("?");
        let summary = s.get("tool_summary").and_then(|v| v.as_str()).unwrap_or("");
        let ok = s.get("success").and_then(|v| v.as_bool()).unwrap_or(false);
        context_parts.push(format!("  - {} {} ({})", if ok { "✓" } else { "✗" }, name, summary));
    }
    if !remaining.is_empty() {
        context_parts.push(format!("\nRemaining plan items to execute ({}):", remaining.len()));
        for (i, item) in remaining.iter().enumerate() {
            let text = item.as_str().unwrap_or("?");
            context_parts.push(format!("  {}. {}", i + 1, text));
        }
    }
    context_parts.push("\nContinue executing the remaining steps now. Do NOT re-do completed work.".to_string());

    let continuation_task = context_parts.join("\n");

    // Archive the old checkpoint
    let archive_path = ck_path.with_extension("json.resumed");
    let _ = std::fs::rename(&ck_path, &archive_path);

    // Delegate to start_agent_task with the enriched task
    start_agent_task(continuation_task, approval_policy, provider, app_handle, state).await
}

/// Decompose a task into independent chunks and run them in parallel.
///
/// Strategy: ask the LLM to split the task into N independent sub-tasks,
/// then spawn each as a separate agent via the MultiAgentOrchestrator.
/// Each chunk runs as its own sub-agent with full tool access.
#[tauri::command]
pub async fn start_parallel_agent_task(
    task: String,
    provider: String,
    max_chunks: Option<usize>,
    app_handle: tauri::AppHandle,
    state: tauri::State<'_, AppState>,
) -> Result<(), String> {
    let max_chunks = max_chunks.unwrap_or(4).min(8);

    // Get the AI provider
    let provider_arc = {
        let mut engine = state.chat_engine.lock().await;
        engine.set_provider_by_name(&provider).map_err(|e| e.to_string())?;
        engine.active_provider().ok_or("No active provider")?.clone()
    };

    let workspace_root = {
        let ws = state.workspace.lock().await;
        ws.folders().first().cloned().unwrap_or_else(|| PathBuf::from("."))
    };

    // Step 1: Ask the LLM to decompose the task into independent chunks.
    let decompose_prompt = format!(
        "You are a task decomposition assistant. Split the following task into {} or fewer \
         independent sub-tasks that can be done IN PARALLEL (no dependencies between them). \
         Each sub-task should be self-contained.\n\n\
         Respond with ONLY a JSON array of strings, no markdown, no explanation:\n\
         [\"sub-task 1 description\", \"sub-task 2 description\", ...]\n\n\
         Task: {}",
        max_chunks, task
    );

    let decompose_messages = vec![
        vibe_ai::Message { role: vibe_ai::MessageRole::User, content: decompose_prompt },
    ];
    let decomposition = provider_arc.chat(&decompose_messages, None).await
        .map_err(|e| format!("Failed to decompose task: {}", e))?;

    // Parse the JSON array
    let chunks: Vec<String> = serde_json::from_str(decomposition.trim_matches(|c: char| c == '`' || c.is_whitespace()))
        .or_else(|_| {
            // Try stripping markdown code block
            let cleaned = decomposition
                .trim()
                .strip_prefix("```json").unwrap_or(&decomposition)
                .strip_prefix("```").unwrap_or(&decomposition)
                .strip_suffix("```").unwrap_or(&decomposition)
                .trim();
            serde_json::from_str(cleaned)
        })
        .unwrap_or_else(|_| vec![task.clone()]);

    let chunk_count = chunks.len();
    let _ = app_handle.emit("agent:chunk", format!(
        "Decomposed into {} parallel chunks:\n{}\n\nStarting parallel execution...\n",
        chunk_count,
        chunks.iter().enumerate()
            .map(|(i, c)| format!("  {}. {}", i + 1, c))
            .collect::<Vec<_>>()
            .join("\n")
    ));

    // Step 2: Spawn each chunk as its own sub-agent.
    // Git repos → true parallel with worktree isolation per chunk.
    // Non-git  → sequential execution to avoid concurrent write races.
    let sub_agents_tracker = state.sub_agents.clone();
    let app = app_handle.clone();
    let is_git = vibe_core::git::is_git_repo(&workspace_root);

    if is_git {
        let _ = app.emit("agent:chunk", "Git repo detected — using worktree isolation for parallel execution".to_string());
    } else {
        let _ = app.emit("agent:chunk", "Non-git project — running chunks sequentially to avoid write conflicts".to_string());
    }

    tokio::spawn(async move {
        // Helper closure: run a single chunk agent and return (id, success, summary).
        async fn run_chunk(
            chunk_idx: usize,
            chunk_id: String,
            chunk_task: String,
            provider_arc: Arc<dyn vibe_ai::provider::AIProvider>,
            agent_workspace: PathBuf,
            app: tauri::AppHandle,
            sub_agents: Arc<tokio::sync::Mutex<Vec<SubAgentDto>>>,
        ) -> (String, bool, String) {
            use vibe_ai::{AgentLoop, AgentContext, ApprovalPolicy, AgentEvent};
            use crate::agent_executor::TauriToolExecutor;

            let git_branch = vibe_core::git::get_current_branch(&agent_workspace).ok();
            let context = AgentContext {
                workspace_root: agent_workspace.clone(),
                open_files: vec![],
                git_branch,
                git_diff_summary: None,
                flow_context: None,
                approved_plan: None,
                extra_skill_dirs: vec![],
                parent_session_id: None,
                depth: 0,
                active_agent_counter: None,
                team_bus: None,
                team_agent_id: None,
                project_summary: None,
                task_context_files: vec![],
                memory_context: None,
                auto_commit: false,
            };

            let executor = Arc::new(
                TauriToolExecutor::with_app(agent_workspace.clone(), app.clone())
                    .with_provider(provider_arc.clone()),
            );
            let agent = AgentLoop::new(provider_arc, ApprovalPolicy::FullAuto, executor)
                .with_policy(&agent_workspace);

            let (tx, mut rx) = tokio::sync::mpsc::channel::<AgentEvent>(64);
            let agent_task = chunk_task.clone();
            tokio::spawn(async move {
                let _ = agent.run(&agent_task, context, tx).await;
            });

            let chunk_label = chunk_idx + 1;
            let mut summary = String::new();
            let mut tokens: u64 = 0;
            let mut success = false;
            while let Some(event) = rx.recv().await {
                match event {
                    AgentEvent::StreamChunk(text) => {
                        tokens += (text.len() as u64) / 4;
                        let _ = app.emit("agent:chunk", format!("[chunk-{}] {}", chunk_label, text));
                    }
                    AgentEvent::ToolCallExecuted(step) => {
                        let _ = app.emit("agent:step", AgentStepPayload {
                            step_num: step.step_num,
                            tool_name: step.tool_call.name().to_string(),
                            tool_summary: format!("[chunk-{}] {}", chunk_label, step.tool_call.summary()),
                            output: step.tool_result.output.clone(),
                            success: step.tool_result.success,
                            approved: step.approved,
                        });
                    }
                    AgentEvent::Complete(s) => {
                        summary = s;
                        success = true;
                        break;
                    }
                    AgentEvent::Partial { summary: s, .. } => {
                        summary = s;
                        break;
                    }
                    AgentEvent::Error(e) => {
                        summary = format!("Error: {}", e);
                        break;
                    }
                    _ => {}
                }
            }

            // Update sub-agent status
            {
                let mut agents = sub_agents.lock().await;
                if let Some(a) = agents.iter_mut().find(|a| a.id == chunk_id) {
                    a.status = if success { "completed" } else { "failed" }.to_string();
                    a.completed_at = Some(chrono::Utc::now().to_rfc3339());
                    a.result_summary = Some(summary.clone());
                    a.tokens_used = Some(tokens.max(1));
                }
            }
            (chunk_id, success, summary)
        }

        // Register all chunks in the dashboard up-front.
        let mut chunk_ids: Vec<String> = Vec::new();
        for (i, chunk_task) in chunks.iter().enumerate() {
            let chunk_id = format!("parallel-{}-{}", i, chrono::Utc::now().timestamp_millis());
            {
                let dto = SubAgentDto {
                    id: chunk_id.clone(),
                    role: format!("chunk-{}", i + 1),
                    status: "working".to_string(),
                    context_files: vec![],
                    provider: provider.clone(),
                    task_description: Some(chunk_task.clone()),
                    result_summary: None,
                    findings: vec![],
                    files_modified: vec![],
                    created_at: chrono::Utc::now().to_rfc3339(),
                    completed_at: None,
                    error: None,
                    tokens_used: None,
                };
                let mut agents = sub_agents_tracker.lock().await;
                agents.push(dto);
            }
            chunk_ids.push(chunk_id);
        }

        let mut results: Vec<(String, bool, String)> = Vec::new();

        if is_git {
            // ── Git repo: true parallel with worktree isolation ──────────
            let mut handles = Vec::new();
            let mut worktree_branches: Vec<(PathBuf, String)> = Vec::new();

            for (i, chunk_task) in chunks.iter().enumerate() {
                let branch = format!("vibe-parallel-{}-{}", i, chrono::Utc::now().timestamp_millis());
                let wt_path = workspace_root.join(format!(".vibe-worktree-{}", i));

                // Create isolated worktree branch
                if let Err(e) = vibe_core::git::create_worktree(&workspace_root, &branch, &wt_path) {
                    let _ = app.emit("agent:chunk", format!("[chunk-{}] Worktree creation failed: {} — falling back to shared workspace", i + 1, e));
                    // Fallback: use shared workspace for this chunk
                    worktree_branches.push((workspace_root.clone(), String::new()));
                } else {
                    let _ = app.emit("agent:chunk", format!("[chunk-{}] Isolated worktree: {}", i + 1, wt_path.display()));
                    worktree_branches.push((wt_path, branch));
                }

                let chunk_id = chunk_ids[i].clone();
                let chunk_task = chunk_task.clone();
                let provider_arc = provider_arc.clone();
                let agent_workspace = worktree_branches[i].0.clone();
                let app = app.clone();
                let sub_agents = sub_agents_tracker.clone();

                let handle = tokio::spawn(async move {
                    run_chunk(i, chunk_id, chunk_task, provider_arc, agent_workspace, app, sub_agents).await
                });
                handles.push(handle);
            }

            // Wait for all chunks
            for handle in handles {
                if let Ok(r) = handle.await {
                    results.push(r);
                }
            }

            // Merge worktree branches back and clean up
            let mut merge_errors: Vec<String> = Vec::new();
            for (i, (wt_path, branch)) in worktree_branches.iter().enumerate() {
                if branch.is_empty() {
                    continue; // was a fallback, no worktree to clean up
                }
                // Merge branch back into main
                match vibe_core::git::merge_worktree_branch(&workspace_root, branch) {
                    Ok(mr) if mr.success => {
                        let _ = app.emit("agent:chunk", format!("[chunk-{}] Merged worktree branch '{}' successfully", i + 1, branch));
                    }
                    Ok(mr) => {
                        let msg = format!("[chunk-{}] Merge conflicts on '{}': {:?}", i + 1, branch, mr.conflicts);
                        let _ = app.emit("agent:chunk", msg.clone());
                        merge_errors.push(msg);
                    }
                    Err(e) => {
                        let msg = format!("[chunk-{}] Merge failed for '{}': {}", i + 1, branch, e);
                        let _ = app.emit("agent:chunk", msg.clone());
                        merge_errors.push(msg);
                    }
                }
                // Clean up worktree
                let _ = vibe_core::git::remove_worktree(&workspace_root, wt_path);
                // Delete leftover branch
                let _ = std::process::Command::new("git")
                    .args(["branch", "-D", branch])
                    .current_dir(&workspace_root)
                    .output();
            }

            if !merge_errors.is_empty() {
                let _ = app.emit("agent:chunk", format!(
                    "\n⚠ {} merge issue(s) — review manually:\n{}",
                    merge_errors.len(),
                    merge_errors.join("\n"),
                ));
            }
        } else {
            // ── Non-git: sequential execution ────────────────────────────
            for (i, chunk_task) in chunks.iter().enumerate() {
                let r = run_chunk(
                    i,
                    chunk_ids[i].clone(),
                    chunk_task.clone(),
                    provider_arc.clone(),
                    workspace_root.clone(),
                    app.clone(),
                    sub_agents_tracker.clone(),
                ).await;
                results.push(r);
            }
        }

        let succeeded = results.iter().filter(|(_, ok, _)| *ok).count();
        let summary = format!(
            "Parallel execution complete: {}/{} chunks succeeded{}\n\n{}",
            succeeded,
            results.len(),
            if is_git { " (worktree-isolated)" } else { " (sequential)" },
            results.iter().enumerate()
                .map(|(i, (_, ok, s))| format!("Chunk {}: {} — {}", i + 1, if *ok { "OK" } else { "FAIL" }, s.chars().take(200).collect::<String>()))
                .collect::<Vec<_>>()
                .join("\n"),
        );
        let _ = app.emit("agent:complete", summary);
    });

    Ok(())
}

/// - `approved = true`  → execute the tool and send result to agent
/// - `approved = false` → reject (agent receives a "rejected" result)
#[tauri::command]
pub async fn respond_to_agent_approval(
    approved: bool,
    app_handle: tauri::AppHandle,
    state: tauri::State<'_, AppState>,
) -> Result<(), String> {
    use crate::agent_executor::TauriToolExecutor;

    let pending = {
        let mut slot = state.agent_pending.lock().await;
        slot.take()
    };

    let Some(PendingAgentCall { call, result_tx }) = pending else {
        return Err("No pending agent approval".to_string());
    };

    if approved {
        let workspace_root = {
            let ws = state.workspace.lock().await;
            ws.folders().first().cloned().unwrap_or_else(|| PathBuf::from("."))
        };
        let maybe_provider = {
            let engine = state.chat_engine.lock().await;
            engine.active_provider().cloned()
        };
        let mut exec = TauriToolExecutor::with_app(workspace_root, app_handle.clone());
        if let Some(p) = maybe_provider { exec = exec.with_provider(p); }
        let executor = exec;
        let result = executor.execute_call(&call).await;

        // Emit a step event so the UI shows what happened
        let payload = AgentStepPayload {
            step_num: 0, // step_num not tracked here
            tool_name: call.name().to_string(),
            tool_summary: call.summary(),
            output: result.output.clone(),
            success: result.success,
            approved: true,
        };
        let _ = app_handle.emit("agent:step", payload);

        let _ = result_tx.send(Some(result));
    } else {
        // Rejection: send None — agent will record "rejected by user"
        let _ = result_tx.send(None);
    }

    Ok(())
}

// ─── Memory / Rules Commands ───────────────────────────────────────────────────

/// Get project-level AI rules from `<workspace>/.vibeui.md`.
#[tauri::command]
pub async fn get_vibeui_rules(state: tauri::State<'_, AppState>) -> Result<String, String> {
    let ws = state.workspace.lock().await;
    let root = ws.folders().first().cloned().ok_or("No workspace folder open")?;
    drop(ws);
    Ok(crate::memory::load_workspace_rules(&root))
}

/// Save project-level AI rules to `<workspace>/.vibeui.md`.
#[tauri::command]
pub async fn save_vibeui_rules(
    content: String,
    state: tauri::State<'_, AppState>,
) -> Result<(), String> {
    let ws = state.workspace.lock().await;
    let root = ws.folders().first().cloned().ok_or("No workspace folder open")?;
    drop(ws);
    crate::memory::save_workspace_rules(&root, &content).map_err(|e| e.to_string())
}

/// Get global AI rules from `~/.vibeui/rules.md`.
#[tauri::command]
pub async fn get_global_rules() -> Result<String, String> {
    Ok(crate::memory::load_global_rules())
}

/// Save global AI rules to `~/.vibeui/rules.md`.
#[tauri::command]
pub async fn save_global_rules(content: String) -> Result<(), String> {
    crate::memory::save_global_rules(&content).map_err(|e| e.to_string())
}

// ─── Rules Directory Commands ──────────────────────────────────────────────────

#[derive(serde::Serialize, serde::Deserialize, Clone, Debug)]
pub struct RuleFileMeta {
    pub filename: String,
    pub name: String,
    pub path_pattern: Option<String>,
}

fn rules_dir(scope: &str, workspace_root: Option<&std::path::Path>) -> std::path::PathBuf {
    if scope == "workspace" {
        workspace_root
            .unwrap_or(std::path::Path::new("."))
            .join(".vibecli")
            .join("rules")
    } else {
        std::path::PathBuf::from(
            std::env::var("HOME").unwrap_or_else(|_| ".".to_string()),
        )
        .join(".vibecli")
        .join("rules")
    }
}

fn parse_rule_meta(content: &str, filename: &str) -> RuleFileMeta {
    let stem = std::path::Path::new(filename)
        .file_stem()
        .and_then(|s| s.to_str())
        .unwrap_or(filename)
        .to_string();
    let mut name = stem.clone();
    let mut path_pattern: Option<String> = None;
    if let Some(after_prefix) = content.strip_prefix("---") {
        let after = after_prefix.trim_start_matches('\n');
        if let Some(close) = after.find("\n---") {
            for line in after[..close].lines() {
                if let Some((k, v)) = line.split_once(':') {
                    let val = v.trim().trim_matches('"').trim_matches('\'').to_string();
                    match k.trim() {
                        "name" => name = val,
                        "path_pattern" => path_pattern = Some(val),
                        _ => {}
                    }
                }
            }
        }
    }
    RuleFileMeta { filename: filename.to_string(), name, path_pattern }
}

/// List all `.md` files in the rules directory (scope: "workspace" | "global").
#[tauri::command]
pub async fn list_rule_files(
    scope: String,
    state: tauri::State<'_, AppState>,
) -> Result<Vec<RuleFileMeta>, String> {
    let root = if scope == "workspace" {
        let ws = state.workspace.lock().await;
        ws.folders().first().cloned()
    } else {
        None
    };
    let dir = rules_dir(&scope, root.as_deref());
    if !dir.is_dir() {
        return Ok(vec![]);
    }
    let mut metas = vec![];
    let rd = std::fs::read_dir(&dir).map_err(|e| e.to_string())?;
    for entry in rd.flatten() {
        let path = entry.path();
        if path.extension().and_then(|x| x.to_str()) == Some("md") {
            let filename = path.file_name().and_then(|x| x.to_str()).unwrap_or("").to_string();
            let content = std::fs::read_to_string(&path).unwrap_or_default();
            metas.push(parse_rule_meta(&content, &filename));
        }
    }
    metas.sort_by(|a, b| a.filename.cmp(&b.filename));
    Ok(metas)
}

/// Read full content of a rule file.
#[tauri::command]
pub async fn get_rule_file(
    scope: String,
    filename: String,
    state: tauri::State<'_, AppState>,
) -> Result<String, String> {
    let root = if scope == "workspace" {
        let ws = state.workspace.lock().await;
        ws.folders().first().cloned()
    } else {
        None
    };
    let path = rules_dir(&scope, root.as_deref()).join(&filename);
    std::fs::read_to_string(&path).map_err(|e| e.to_string())
}

/// Write (create or overwrite) a rule file.
#[tauri::command]
pub async fn save_rule_file(
    scope: String,
    filename: String,
    content: String,
    state: tauri::State<'_, AppState>,
) -> Result<(), String> {
    let root = if scope == "workspace" {
        let ws = state.workspace.lock().await;
        ws.folders().first().cloned()
    } else {
        None
    };
    let dir = rules_dir(&scope, root.as_deref());
    std::fs::create_dir_all(&dir).map_err(|e| e.to_string())?;
    std::fs::write(dir.join(&filename), content).map_err(|e| e.to_string())
}

/// Delete a rule file permanently.
#[tauri::command]
pub async fn delete_rule_file(
    scope: String,
    filename: String,
    state: tauri::State<'_, AppState>,
) -> Result<(), String> {
    let root = if scope == "workspace" {
        let ws = state.workspace.lock().await;
        ws.folders().first().cloned()
    } else {
        None
    };
    let path = rules_dir(&scope, root.as_deref()).join(&filename);
    std::fs::remove_file(&path).map_err(|e| e.to_string())
}

/// Generate AI rules for a workspace based on detected project stack.
#[tauri::command]
pub async fn generate_vibeui_rules(
    state: tauri::State<'_, AppState>,
) -> Result<String, String> {
    let root = {
        let ws = state.workspace.lock().await;
        ws.folders().first().cloned()
    };
    let workspace = root.as_deref().unwrap_or(std::path::Path::new("."));

    // Detect key signals
    let cargo = workspace.join("Cargo.toml");
    let package_json = workspace.join("package.json");
    let go_mod = workspace.join("go.mod");
    let pyproject = workspace.join("pyproject.toml");
    let requirements = workspace.join("requirements.txt");

    let has_rust = cargo.exists();
    let has_ts = workspace.join("tsconfig.json").exists();
    let _has_js = package_json.exists() && !has_ts;
    let has_go = go_mod.exists();
    let has_python = pyproject.exists() || requirements.exists();
    let has_tauri = workspace.join("src-tauri").exists();
    let has_react = package_json.exists() && {
        std::fs::read_to_string(&package_json)
            .map(|c| c.contains("\"react\""))
            .unwrap_or(false)
    };
    let has_tests = workspace.join("tests").exists()
        || workspace.join("test").exists()
        || workspace.join("__tests__").exists()
        || workspace.join("src").join("__tests__").exists();
    let has_ci = workspace.join(".github/workflows").exists();
    let has_docker = workspace.join("Dockerfile").exists();
    let is_monorepo = has_rust && {
        std::fs::read_to_string(&cargo)
            .map(|c| c.contains("[workspace]"))
            .unwrap_or(false)
    };

    let mut lines = vec!["# AI Rules\n".to_string()];
    lines.push("<!-- Generated by VibeCody — edit freely -->\n".to_string());
    lines.push(String::new());

    if has_rust {
        lines.push("## Rust".to_string());
        lines.push("- Prefer `?` for error propagation; avoid `.unwrap()` in production code".to_string());
        lines.push("- Use `thiserror` for library errors, `anyhow` for application errors".to_string());
        lines.push("- Add `#[must_use]` to pure functions that return meaningful values".to_string());
        lines.push("- Prefer iterators and functional style over index-based loops".to_string());
        if is_monorepo {
            lines.push("- This is a Cargo workspace — new crates must be added to `[workspace.members]`".to_string());
        }
        lines.push(String::new());
    }

    if has_tauri {
        lines.push("## Tauri".to_string());
        lines.push("- Implement new commands in `commands.rs`, register in `lib.rs` `invoke_handler`".to_string());
        lines.push("- Never store secrets in frontend state — use `ProfileStore` / `WorkspaceStore`".to_string());
        lines.push("- Return `Result<T, String>` from all Tauri commands".to_string());
        lines.push(String::new());
    }

    if has_ts || has_react {
        lines.push("## TypeScript / React".to_string());
        if has_ts {
            lines.push("- Keep `strict: true` in tsconfig; fix all type errors before committing".to_string());
        }
        if has_react {
            lines.push("- Prefer function components and hooks; avoid class components".to_string());
            lines.push("- Use design system CSS classes (`panel-container`, `panel-btn`, etc.) rather than inline styles".to_string());
            lines.push("- Keep component files focused — one primary export per file".to_string());
        }
        lines.push(String::new());
    }

    if has_go {
        lines.push("## Go".to_string());
        lines.push("- Handle all errors explicitly; never ignore with `_`".to_string());
        lines.push("- Use `context.Context` as the first argument for I/O functions".to_string());
        lines.push("- Write table-driven tests using `t.Run`".to_string());
        lines.push(String::new());
    }

    if has_python {
        lines.push("## Python".to_string());
        lines.push("- Add type hints to all function signatures".to_string());
        lines.push("- Use `pathlib.Path` instead of `os.path` string manipulation".to_string());
        lines.push(String::new());
    }

    lines.push("## General".to_string());
    if has_tests {
        lines.push("- This project has tests — maintain coverage; add tests for new logic".to_string());
    }
    if has_ci {
        lines.push("- CI runs on every push — ensure `cargo check` / `tsc --noEmit` passes before committing".to_string());
    }
    if has_docker {
        lines.push("- When changing dependencies, update the Dockerfile if the install step is affected".to_string());
    }
    lines.push("- Prefer editing existing files over creating new ones".to_string());
    lines.push("- Don't add speculative features or over-engineer for hypothetical future requirements".to_string());
    lines.push("- Short, direct code over lengthy abstractions".to_string());

    Ok(lines.join("\n"))
}

// ─── MCP Server Manager Commands ──────────────────────────────────────────────

fn mcp_config_path() -> std::path::PathBuf {
    let home = std::env::var("HOME").unwrap_or_else(|_| ".".to_string());
    std::path::PathBuf::from(home).join(".vibeui").join("mcp.json")
}

/// Return all configured MCP servers from `~/.vibeui/mcp.json`.
#[tauri::command]
pub async fn get_mcp_servers() -> Result<Vec<serde_json::Value>, String> {
    let path = mcp_config_path();
    if !path.exists() {
        return Ok(vec![]);
    }
    let text = std::fs::read_to_string(&path).map_err(|e| e.to_string())?;
    serde_json::from_str::<Vec<serde_json::Value>>(&text).map_err(|e| e.to_string())
}

/// Persist the MCP server list to `~/.vibeui/mcp.json`.
#[tauri::command]
pub async fn save_mcp_servers(servers: Vec<serde_json::Value>) -> Result<(), String> {
    let path = mcp_config_path();
    if let Some(parent) = path.parent() {
        std::fs::create_dir_all(parent).map_err(|e| e.to_string())?;
    }
    let text = serde_json::to_string_pretty(&servers).map_err(|e| e.to_string())?;
    std::fs::write(&path, text).map_err(|e| e.to_string())
}

#[derive(serde::Serialize, serde::Deserialize, Clone, Debug)]
pub struct McpToolInfo {
    pub name: String,
    pub description: String,
}

/// Spawn a temporary MCP server connection and list its tools.
#[tauri::command]
pub async fn test_mcp_server(server: serde_json::Value) -> Result<Vec<McpToolInfo>, String> {
    let cfg: vibe_ai::mcp::McpServerConfig =
        serde_json::from_value(server).map_err(|e| format!("Invalid server config: {}", e))?;
    tokio::task::spawn_blocking(move || {
        let mut client =
            vibe_ai::mcp::McpClient::connect(&cfg).map_err(|e| format!("Connect failed: {:#}", e))?;
        let tools = client.list_tools().map_err(|e| format!("list_tools failed: {:#}", e))?;
        Ok(tools
            .into_iter()
            .map(|t| McpToolInfo { name: t.name, description: t.description })
            .collect())
    })
    .await
    .map_err(|e| format!("Task error: {}", e))?
}

// ─── MCP OAuth Commands ────────────────────────────────────────────────────────

fn mcp_token_path() -> std::path::PathBuf {
    let home = std::env::var("HOME").unwrap_or_else(|_| ".".to_string());
    std::path::PathBuf::from(home).join(".vibeui").join("mcp-tokens.json")
}

fn load_mcp_tokens() -> serde_json::Map<String, serde_json::Value> {
    let path = mcp_token_path();
    if let Ok(text) = std::fs::read_to_string(&path) {
        if let Ok(serde_json::Value::Object(map)) = serde_json::from_str(&text) {
            return map;
        }
    }
    serde_json::Map::new()
}

fn save_mcp_tokens(tokens: &serde_json::Map<String, serde_json::Value>) -> Result<(), String> {
    let path = mcp_token_path();
    if let Some(parent) = path.parent() {
        std::fs::create_dir_all(parent).map_err(|e| e.to_string())?;
    }
    let text = serde_json::to_string_pretty(&serde_json::Value::Object(tokens.clone()))
        .map_err(|e| e.to_string())?;
    std::fs::write(&path, text).map_err(|e| e.to_string())
}

/// Build the OAuth authorization URL and open it in the system browser.
/// The caller is responsible for listening to the redirect and passing the code
/// to `complete_mcp_oauth`.
#[tauri::command]
pub async fn initiate_mcp_oauth(
    app: tauri::AppHandle,
    server_name: String,
    client_id: String,
    auth_url: String,
    redirect_uri: String,
    scopes: String,
) -> Result<String, String> {
    use tauri_plugin_opener::OpenerExt;
    // Validate the auth_url starts with https
    if !auth_url.starts_with("https://") && !auth_url.starts_with("http://localhost") {
        return Err("auth_url must start with https:// or http://localhost".to_string());
    }
    let state_token = format!("vibecli-{}-{}", server_name, std::time::SystemTime::now()
        .duration_since(std::time::UNIX_EPOCH).unwrap_or_default().as_secs());
    let oauth_url = {
        let params: Vec<(&str, &str)> = vec![
            ("client_id",     &client_id),
            ("redirect_uri",  &redirect_uri),
            ("response_type", "code"),
            ("scope",         &scopes),
            ("state",         &state_token),
        ];
        let qs: String = url::form_urlencoded::Serializer::new(String::new())
            .extend_pairs(params)
            .finish();
        format!("{}?{}", auth_url, qs)
    };
    app.opener()
        .open_url(&oauth_url, None::<&str>)
        .map_err(|e| format!("Failed to open browser: {}", e))?;
    Ok(state_token)
}

/// Exchange an authorization code for a token and persist it.
#[tauri::command]
pub async fn complete_mcp_oauth(
    server_name: String,
    code: String,
    token_url: String,
    client_id: String,
    redirect_uri: String,
) -> Result<String, String> {
    if !token_url.starts_with("https://") && !token_url.starts_with("http://localhost") {
        return Err("token_url must start with https:// or http://localhost".to_string());
    }
    let client = reqwest::Client::new();
    let resp = client
        .post(&token_url)
        .form(&[
            ("grant_type",    "authorization_code"),
            ("code",          &code),
            ("client_id",     &client_id),
            ("redirect_uri",  &redirect_uri),
        ])
        .send()
        .await
        .map_err(|e| format!("Token request failed: {}", e))?;
    let body: serde_json::Value = resp.json().await.map_err(|e| format!("Token parse error: {}", e))?;
    let access_token = body["access_token"].as_str()
        .ok_or_else(|| format!("No access_token in response: {}", body))?
        .to_string();
    // Persist token
    let mut tokens = load_mcp_tokens();
    tokens.insert(server_name.clone(), serde_json::json!({
        "access_token": access_token,
        "token_type":   body["token_type"].as_str().unwrap_or("Bearer"),
        "expires_in":   body["expires_in"].as_u64().unwrap_or(3600),
        "obtained_at":  std::time::SystemTime::now()
            .duration_since(std::time::UNIX_EPOCH).unwrap_or_default().as_secs(),
    }));
    save_mcp_tokens(&tokens)?;
    Ok(access_token)
}

/// Return whether a token is stored for the given MCP server name.
#[tauri::command]
pub async fn get_mcp_token_status(server_name: String) -> Result<serde_json::Value, String> {
    let tokens = load_mcp_tokens();
    if let Some(rec) = tokens.get(&server_name) {
        let obtained = rec["obtained_at"].as_u64().unwrap_or(0);
        let expires  = rec["expires_in"].as_u64().unwrap_or(3600);
        let now = std::time::SystemTime::now()
            .duration_since(std::time::UNIX_EPOCH).unwrap_or_default().as_secs();
        let expired = now > obtained + expires;
        Ok(serde_json::json!({ "connected": true, "expired": expired }))
    } else {
        Ok(serde_json::json!({ "connected": false, "expired": true }))
    }
}

