/// OAuth configuration for each cloud provider.
fn cloud_oauth_config(provider: &str) -> Result<serde_json::Value, String> {
    let config = match provider {
        "google" => serde_json::json!({
            "auth_url": "https://accounts.google.com/o/oauth2/v2/auth",
            "token_url": "https://oauth2.googleapis.com/token",
            "userinfo_url": "https://www.googleapis.com/oauth2/v3/userinfo",
            "scopes": "openid email profile https://www.googleapis.com/auth/cloud-platform",
            "name": "Google Cloud"
        }),
        "github" => serde_json::json!({
            "auth_url": "https://github.com/login/oauth/authorize",
            "token_url": "https://github.com/login/oauth/access_token",
            "userinfo_url": "https://api.github.com/user",
            "scopes": "user:email repo read:org",
            "name": "GitHub"
        }),
        "gitlab" => serde_json::json!({
            "auth_url": "https://gitlab.com/oauth/authorize",
            "token_url": "https://gitlab.com/oauth/token",
            "userinfo_url": "https://gitlab.com/api/v4/user",
            "scopes": "read_user api read_repository",
            "name": "GitLab"
        }),
        "bitbucket" => serde_json::json!({
            "auth_url": "https://bitbucket.org/site/oauth2/authorize",
            "token_url": "https://bitbucket.org/site/oauth2/access_token",
            "userinfo_url": "https://api.bitbucket.org/2.0/user",
            "scopes": "account repository",
            "name": "Bitbucket"
        }),
        "microsoft" => serde_json::json!({
            "auth_url": "https://login.microsoftonline.com/common/oauth2/v2.0/authorize",
            "token_url": "https://login.microsoftonline.com/common/oauth2/v2.0/token",
            "userinfo_url": "https://graph.microsoft.com/v1.0/me",
            "scopes": "openid email profile User.Read",
            "name": "Microsoft Azure"
        }),
        "apple" => serde_json::json!({
            "auth_url": "https://appleid.apple.com/auth/authorize",
            "token_url": "https://appleid.apple.com/auth/token",
            "userinfo_url": "",
            "scopes": "name email",
            "name": "Apple"
        }),
        _ => return Err(format!("Unknown provider: {}", provider)),
    };
    Ok(config)
}

/// Initiate OAuth flow for a cloud provider — opens browser to auth URL.
/// Automatically starts a temporary local server on the redirect_uri port to
/// catch the callback and emit a `oauth-callback` Tauri event with the code.
#[tauri::command]
pub async fn cloud_oauth_initiate(
    app: tauri::AppHandle,
    provider: String,
    client_id: String,
    redirect_uri: String,
) -> Result<String, String> {
    use tauri_plugin_opener::OpenerExt;
    let config = cloud_oauth_config(&provider)?;
    let auth_url = config["auth_url"].as_str().ok_or("Missing auth_url")?;
    let scopes = config["scopes"].as_str().unwrap_or("");

    let state_token = format!("vibeui-{}-{}", provider, std::time::SystemTime::now()
        .duration_since(std::time::UNIX_EPOCH).unwrap_or_default().as_secs());

    let oauth_url = {
        let mut params: Vec<(&str, &str)> = vec![
            ("client_id",     &client_id),
            ("redirect_uri",  &redirect_uri),
            ("response_type", "code"),
            ("scope",         scopes),
            ("state",         &state_token),
        ];
        // Google needs access_type=offline for refresh tokens
        if provider == "google" {
            params.push(("access_type", "offline"));
            params.push(("prompt", "consent"));
        }
        // Apple needs response_mode=form_post
        if provider == "apple" {
            params.push(("response_mode", "form_post"));
        }
        let qs: String = url::form_urlencoded::Serializer::new(String::new())
            .extend_pairs(params)
            .finish();
        format!("{}?{}", auth_url, qs)
    };

    // Start a temporary local HTTP server to capture the OAuth callback.
    // Parse port from redirect_uri, default to 7878.
    let port: u16 = url::Url::parse(&redirect_uri)
        .ok()
        .and_then(|u| u.port())
        .unwrap_or(7878);
    let provider_clone = provider.clone();
    let app_clone = app.clone();
    tokio::spawn(async move {
        use tokio::io::{AsyncReadExt, AsyncWriteExt};
        let listener = match tokio::net::TcpListener::bind(("127.0.0.1", port)).await {
            Ok(l) => l,
            Err(_) => return, // port busy — fall back to manual code entry
        };
        // Accept one connection with a 120-second timeout
        let accept_result = tokio::time::timeout(
            std::time::Duration::from_secs(120),
            listener.accept(),
        ).await;
        let (mut stream, _) = match accept_result {
            Ok(Ok(pair)) => pair,
            _ => return,
        };
        let mut buf = vec![0u8; 4096];
        let n = stream.read(&mut buf).await.unwrap_or(0);
        let request = String::from_utf8_lossy(&buf[..n]);

        // Extract the query string from "GET /oauth/callback?code=...&state=... HTTP/1.1"
        let mut code = String::new();
        let mut error = String::new();
        if let Some(query_start) = request.find('?') {
            if let Some(line_end) = request[query_start..].find(' ') {
                let qs = &request[query_start + 1..query_start + line_end];
                for (key, val) in url::form_urlencoded::parse(qs.as_bytes()) {
                    match key.as_ref() {
                        "code" => code = val.into_owned(),
                        "error" => error = val.into_owned(),
                        _ => {}
                    }
                }
            }
        }

        // Send a response page to the browser
        let (status, body_html) = if !code.is_empty() {
            ("200 OK", "<html><body style=\"font-family:system-ui;display:flex;align-items:center;justify-content:center;height:100vh;margin:0;background:#1a1a2e;color:#e0e0e0\"><div style=\"text-align:center\"><h1 style=\"color:#4ade80\">&#10003; Authentication Successful</h1><p>You can close this tab and return to VibeCody.</p></div></body></html>")
        } else {
            ("400 Bad Request", "<html><body style=\"font-family:system-ui;display:flex;align-items:center;justify-content:center;height:100vh;margin:0;background:#1a1a2e;color:#e0e0e0\"><div style=\"text-align:center\"><h1 style=\"color:#f87171\">&#10007; Authentication Failed</h1><p>Please try again from VibeCody.</p></div></body></html>")
        };
        let response = format!(
            "HTTP/1.1 {}\r\nContent-Type: text/html; charset=utf-8\r\nConnection: close\r\n\r\n{}",
            status, body_html
        );
        let _ = stream.write_all(response.as_bytes()).await;
        let _ = stream.shutdown().await;

        // Emit Tauri event so the frontend can auto-complete the flow
        if !code.is_empty() {
            let _ = app_clone.emit("oauth-callback", serde_json::json!({
                "provider": provider_clone,
                "code": code,
            }));
        } else if !error.is_empty() {
            let _ = app_clone.emit("oauth-callback", serde_json::json!({
                "provider": provider_clone,
                "error": error,
            }));
        }
    });

    app.opener()
        .open_url(&oauth_url, None::<&str>)
        .map_err(|e| format!("Failed to open browser: {}", e))?;
    Ok(state_token)
}

/// Exchange authorization code for tokens and fetch user info.
#[tauri::command]
pub async fn cloud_oauth_complete(
    provider: String,
    code: String,
    client_id: String,
    client_secret: String,
    redirect_uri: String,
) -> Result<serde_json::Value, String> {
    let config = cloud_oauth_config(&provider)?;
    let token_url = config["token_url"].as_str().ok_or("Missing token_url")?;
    let userinfo_url = config["userinfo_url"].as_str().unwrap_or("");

    let client = reqwest::Client::new();

    // Exchange code for token
    let mut form = vec![
        ("grant_type",    "authorization_code".to_string()),
        ("code",          code),
        ("client_id",     client_id),
        ("redirect_uri",  redirect_uri),
    ];
    if !client_secret.is_empty() {
        form.push(("client_secret", client_secret));
    }

    let mut token_req = client.post(token_url);

    // GitHub wants Accept: application/json
    if provider == "github" {
        token_req = token_req.header("Accept", "application/json");
    }

    let resp = token_req
        .form(&form)
        .send()
        .await
        .map_err(|e| format!("Token request failed: {}", e))?;

    let body: serde_json::Value = resp.json().await
        .map_err(|e| format!("Token parse error: {}", e))?;

    let access_token = body["access_token"].as_str()
        .ok_or_else(|| format!("No access_token in response: {}", body))?
        .to_string();

    // Fetch user info if endpoint is available
    let mut email = String::new();
    let mut display_name = String::new();

    if !userinfo_url.is_empty() {
        let user_resp = client.get(userinfo_url)
            .header("Authorization", format!("Bearer {}", access_token))
            .header("User-Agent", "VibeCody/1.0")
            .send()
            .await;

        if let Ok(resp) = user_resp {
            if let Ok(user_info) = resp.json::<serde_json::Value>().await {
                // Different providers use different field names
                email = user_info["email"].as_str()
                    .or_else(|| user_info["mail"].as_str())
                    .unwrap_or("").to_string();
                display_name = user_info["name"].as_str()
                    .or_else(|| user_info["displayName"].as_str())
                    .or_else(|| user_info["display_name"].as_str())
                    .or_else(|| user_info["login"].as_str())
                    .or_else(|| user_info["username"].as_str())
                    .unwrap_or("").to_string();

                // GitHub: email may be null in profile, fetch from /user/emails
                if email.is_empty() && provider == "github" {
                    if let Ok(emails_resp) = client.get("https://api.github.com/user/emails")
                        .header("Authorization", format!("Bearer {}", access_token))
                        .header("User-Agent", "VibeCody/1.0")
                        .send().await
                    {
                        if let Ok(emails) = emails_resp.json::<Vec<serde_json::Value>>().await {
                            if let Some(primary) = emails.iter().find(|e| e["primary"].as_bool() == Some(true)) {
                                email = primary["email"].as_str().unwrap_or("").to_string();
                            } else if let Some(first) = emails.first() {
                                email = first["email"].as_str().unwrap_or("").to_string();
                            }
                        }
                    }
                }
            }
        }
    }

    let now = std::time::SystemTime::now()
        .duration_since(std::time::UNIX_EPOCH).unwrap_or_default().as_secs();

    let token_record = serde_json::json!({
        "access_token": access_token,
        "refresh_token": body["refresh_token"].as_str().unwrap_or(""),
        "token_type": body["token_type"].as_str().unwrap_or("Bearer"),
        "expires_in": body["expires_in"].as_u64().unwrap_or(3600),
        "obtained_at": now,
        "email": email,
        "display_name": display_name,
        "provider": provider,
    });

    // Persist token
    let mut tokens = load_cloud_oauth_tokens();
    tokens.insert(provider.clone(), token_record.clone());
    save_cloud_oauth_tokens(&tokens)?;

    Ok(serde_json::json!({
        "provider": provider,
        "email": email,
        "display_name": display_name,
        "connected": true,
    }))
}

/// Check connection status for a cloud provider.
#[tauri::command]
pub async fn cloud_oauth_status(provider: String) -> Result<serde_json::Value, String> {
    let tokens = load_cloud_oauth_tokens();
    if let Some(rec) = tokens.get(&provider) {
        let obtained = rec["obtained_at"].as_u64().unwrap_or(0);
        let expires = rec["expires_in"].as_u64().unwrap_or(3600);
        let now = std::time::SystemTime::now()
            .duration_since(std::time::UNIX_EPOCH).unwrap_or_default().as_secs();
        let expired = now > obtained + expires;
        Ok(serde_json::json!({
            "connected": true,
            "expired": expired,
            "email": rec["email"].as_str().unwrap_or(""),
            "display_name": rec["display_name"].as_str().unwrap_or(""),
            "provider": provider,
        }))
    } else {
        Ok(serde_json::json!({
            "connected": false,
            "expired": true,
            "email": "",
            "display_name": "",
            "provider": provider,
        }))
    }
}

/// Get all connected cloud providers and their status.
#[tauri::command]
pub async fn cloud_oauth_list_connected() -> Result<Vec<serde_json::Value>, String> {
    let tokens = load_cloud_oauth_tokens();
    let now = std::time::SystemTime::now()
        .duration_since(std::time::UNIX_EPOCH).unwrap_or_default().as_secs();
    let mut result = Vec::new();
    for (provider, rec) in &tokens {
        let obtained = rec["obtained_at"].as_u64().unwrap_or(0);
        let expires = rec["expires_in"].as_u64().unwrap_or(3600);
        let expired = now > obtained + expires;
        result.push(serde_json::json!({
            "provider": provider,
            "connected": true,
            "expired": expired,
            "email": rec["email"].as_str().unwrap_or(""),
            "display_name": rec["display_name"].as_str().unwrap_or(""),
        }));
    }
    Ok(result)
}

/// Disconnect (revoke) a cloud provider's OAuth token.
#[tauri::command]
pub async fn cloud_oauth_disconnect(provider: String) -> Result<(), String> {
    let mut tokens = load_cloud_oauth_tokens();
    tokens.remove(&provider);
    save_cloud_oauth_tokens(&tokens)
}

/// Refresh an expired OAuth token using the refresh_token.
#[tauri::command]
pub async fn cloud_oauth_refresh(
    provider: String,
    client_id: String,
    client_secret: String,
) -> Result<serde_json::Value, String> {
    let tokens = load_cloud_oauth_tokens();
    let rec = tokens.get(&provider)
        .ok_or_else(|| format!("No token found for {}", provider))?;
    let refresh_token = rec["refresh_token"].as_str()
        .ok_or("No refresh_token available")?;
    if refresh_token.is_empty() {
        return Err("No refresh_token available — re-authenticate".to_string());
    }

    let config = cloud_oauth_config(&provider)?;
    let token_url = config["token_url"].as_str().ok_or("Missing token_url")?;

    let client = reqwest::Client::new();
    let mut form = vec![
        ("grant_type",     "refresh_token".to_string()),
        ("refresh_token",  refresh_token.to_string()),
        ("client_id",      client_id),
    ];
    if !client_secret.is_empty() {
        form.push(("client_secret", client_secret));
    }

    let resp = client.post(token_url)
        .form(&form)
        .send()
        .await
        .map_err(|e| format!("Refresh token request failed: {}", e))?;

    let body: serde_json::Value = resp.json().await
        .map_err(|e| format!("Refresh parse error: {}", e))?;

    let access_token = body["access_token"].as_str()
        .ok_or_else(|| format!("No access_token in refresh response: {}", body))?
        .to_string();

    let now = std::time::SystemTime::now()
        .duration_since(std::time::UNIX_EPOCH).unwrap_or_default().as_secs();

    // Update stored token
    let mut tokens = load_cloud_oauth_tokens();
    if let Some(serde_json::Value::Object(ref mut map)) = tokens.get_mut(&provider) {
        map.insert("access_token".to_string(), serde_json::json!(access_token));
        map.insert("obtained_at".to_string(), serde_json::json!(now));
        if let Some(exp) = body["expires_in"].as_u64() {
            map.insert("expires_in".to_string(), serde_json::json!(exp));
        }
        // If a new refresh_token was issued, update it
        if let Some(new_rt) = body["refresh_token"].as_str() {
            map.insert("refresh_token".to_string(), serde_json::json!(new_rt));
        }
    }
    save_cloud_oauth_tokens(&tokens)?;

    Ok(serde_json::json!({ "provider": provider, "refreshed": true }))
}

/// Get the stored access token for a cloud provider (for use by other commands).
#[tauri::command]
pub async fn cloud_oauth_get_token(provider: String) -> Result<String, String> {
    let tokens = load_cloud_oauth_tokens();
    let rec = tokens.get(&provider)
        .ok_or_else(|| format!("Not connected to {}", provider))?;
    rec["access_token"].as_str()
        .map(|s| s.to_string())
        .ok_or_else(|| "No access_token stored".to_string())
}

/// Fetch Google profile (name, email, avatar) using stored OAuth token.
/// Falls back to stored token data if the API call fails.
#[tauri::command]
pub async fn cloud_oauth_google_profile() -> Result<serde_json::Value, String> {
    let tokens = load_cloud_oauth_tokens();
    let rec = tokens.get("google")
        .ok_or("Not connected to Google. Please connect via OAuth first.")?;
    let access_token = rec["access_token"].as_str()
        .ok_or("No access token stored for Google")?;

    // Try to fetch fresh profile data from Google userinfo endpoint
    let client = reqwest::Client::new();
    let resp = client.get("https://www.googleapis.com/oauth2/v3/userinfo")
        .header("Authorization", format!("Bearer {}", access_token))
        .send()
        .await;

    if let Ok(resp) = resp {
        if resp.status().is_success() {
            if let Ok(info) = resp.json::<serde_json::Value>().await {
                return Ok(serde_json::json!({
                    "displayName": info["name"].as_str().unwrap_or(""),
                    "email": info["email"].as_str().unwrap_or(""),
                    "avatarUrl": info["picture"].as_str().unwrap_or(""),
                    "source": "google_api",
                }));
            }
        }
    }

    // Fallback to stored token data
    Ok(serde_json::json!({
        "displayName": rec["display_name"].as_str().unwrap_or(""),
        "email": rec["email"].as_str().unwrap_or(""),
        "avatarUrl": "",
        "source": "stored_token",
    }))
}

/// Save OAuth client credentials (client_id, client_secret) for a provider.
#[tauri::command]
pub async fn cloud_oauth_save_client_config(
    provider: String,
    client_id: String,
    client_secret: String,
) -> Result<(), String> {
    let path = {
        let home = std::env::var("HOME").unwrap_or_else(|_| ".".to_string());
        std::path::PathBuf::from(home).join(".vibeui").join("oauth-clients.json")
    };
    if let Some(parent) = path.parent() {
        std::fs::create_dir_all(parent).map_err(|e| e.to_string())?;
    }
    let mut configs: serde_json::Map<String, serde_json::Value> = if let Ok(text) = std::fs::read_to_string(&path) {
        if let Ok(serde_json::Value::Object(map)) = serde_json::from_str(&text) { map } else { serde_json::Map::new() }
    } else {
        serde_json::Map::new()
    };
    configs.insert(provider, serde_json::json!({
        "client_id": client_id,
        "client_secret": client_secret,
    }));
    let text = serde_json::to_string_pretty(&serde_json::Value::Object(configs))
        .map_err(|e| e.to_string())?;
    std::fs::write(&path, text).map_err(|e| e.to_string())
}

/// Load stored OAuth client credentials for a provider.
#[tauri::command]
pub async fn cloud_oauth_get_client_config(provider: String) -> Result<serde_json::Value, String> {
    let path = {
        let home = std::env::var("HOME").unwrap_or_else(|_| ".".to_string());
        std::path::PathBuf::from(home).join(".vibeui").join("oauth-clients.json")
    };
    let configs: serde_json::Map<String, serde_json::Value> = if let Ok(text) = std::fs::read_to_string(&path) {
        if let Ok(serde_json::Value::Object(map)) = serde_json::from_str(&text) { map } else { serde_json::Map::new() }
    } else {
        serde_json::Map::new()
    };
    Ok(configs.get(&provider).cloned().unwrap_or(serde_json::json!({
        "client_id": "",
        "client_secret": "",
    })))
}

// ─── Test Runner (Phase 43) ───────────────────────────────────────────────────

#[derive(Serialize, Deserialize, Clone)]
pub struct TestResult {
    pub name: String,
    pub status: String, // "passed" | "failed" | "ignored" | "running"
    pub duration_ms: Option<u64>,
    pub output: Option<String>,
}

#[derive(Serialize)]
pub struct TestRunResult {
    pub framework: String,
    pub passed: u32,
    pub failed: u32,
    pub ignored: u32,
    pub total: u32,
    pub duration_ms: u64,
    pub tests: Vec<TestResult>,
}

/// Detect which test framework the workspace uses.
#[tauri::command]
pub async fn detect_test_framework(workspace: String) -> String {
    let ws = std::path::Path::new(&workspace);
    if ws.join("Cargo.toml").exists() { return "cargo test".to_string(); }
    // Check package.json for test script
    if let Ok(txt) = std::fs::read_to_string(ws.join("package.json")) {
        if let Ok(v) = serde_json::from_str::<serde_json::Value>(&txt) {
            if v["scripts"]["test"].is_string() {
                let mgr = if ws.join("bun.lockb").exists() { "bun" }
                    else if ws.join("yarn.lock").exists() { "yarn" }
                    else { "npm" };
                return format!("{} test", mgr);
            }
        }
    }
    if ws.join("pytest.ini").exists() || ws.join("pyproject.toml").exists() || ws.join("setup.py").exists() {
        return "pytest".to_string();
    }
    if ws.join("go.mod").exists() { return "go test ./...".to_string(); }
    "unknown".to_string()
}

/// Run tests in the workspace and return parsed results.
///
/// Emits `test:log` events for each output line so the frontend can show a live stream.
#[tauri::command]
pub async fn run_tests(
    app: tauri::AppHandle,
    workspace: String,
    command: Option<String>,
) -> Result<TestRunResult, String> {
    let framework = detect_test_framework(workspace.clone()).await;
    let cmd_str = command.unwrap_or_else(|| framework.clone());
    if cmd_str == "unknown" {
        return Err("Could not detect a test framework. Set a custom command.".to_string());
    }

    let started = std::time::Instant::now();
    let _ = app.emit("test:log", format!("$ {}", cmd_str));

    let (prog, args_str) = if cmd_str.starts_with("cargo") {
        ("cargo", "test")
    } else if cmd_str.starts_with("bun") {
        ("bun", "test")
    } else if cmd_str.starts_with("yarn") {
        ("yarn", "test --json 2>&1 || true")
    } else if cmd_str.starts_with("npm") {
        ("npm", "test -- --json 2>&1 || true")
    } else if cmd_str.starts_with("pytest") {
        ("python", "-m pytest -v --tb=short --no-header 2>&1 || true")
    } else if cmd_str.starts_with("go test") {
        ("go", "test -v ./... 2>&1 || true")
    } else {
        // custom command: run via sh
        let output = std::process::Command::new("sh")
            .arg("-c")
            .arg(&cmd_str)
            .current_dir(&workspace)
            .output()
            .map_err(|e| format!("Failed to run: {}", e))?;
        let text = String::from_utf8_lossy(&output.stdout).to_string()
            + &String::from_utf8_lossy(&output.stderr);
        for line in text.lines() {
            let _ = app.emit("test:log", line.to_string());
        }
        let elapsed = started.elapsed().as_millis() as u64;
        let passed = if output.status.success() { 1 } else { 0 };
        let failed = 1 - passed;
        return Ok(TestRunResult {
            framework: cmd_str,
            passed, failed, ignored: 0, total: 1, duration_ms: elapsed,
            tests: vec![TestResult {
                name: "Test run".to_string(),
                status: if output.status.success() { "passed".to_string() } else { "failed".to_string() },
                duration_ms: Some(elapsed),
                output: if !output.status.success() { Some(text.chars().take(2000).collect()) } else { None },
            }],
        });
    };

    let output = std::process::Command::new(prog)
        .args(args_str.split_whitespace())
        .current_dir(&workspace)
        .output()
        .map_err(|e| format!("Failed to run {} {}: {}", prog, args_str, e))?;

    let stdout = String::from_utf8_lossy(&output.stdout).to_string();
    let stderr = String::from_utf8_lossy(&output.stderr).to_string();
    let combined = format!("{}{}", stdout, stderr);

    for line in combined.lines().take(500) {
        let _ = app.emit("test:log", line.to_string());
    }

    let elapsed = started.elapsed().as_millis() as u64;

    // Parse results based on framework
    let mut tests: Vec<TestResult> = Vec::new();

    if prog == "cargo" {
        // Parse cargo test standard libtest output:
        //   "test module::name ... ok"
        //   "test module::name ... FAILED"
        //   "test module::name ... ignored"
        // Also parse the summary line: "test result: ok. N passed; N failed; N ignored; ..."
        for line in combined.lines() {
            let trimmed = line.trim();
            if let Some(rest) = trimmed.strip_prefix("test ") {
                if let Some(name) = rest.strip_suffix(" ... ok") {
                    tests.push(TestResult { name: name.to_string(), status: "passed".to_string(), duration_ms: None, output: None });
                } else if let Some(name) = rest.strip_suffix(" ... FAILED") {
                    tests.push(TestResult { name: name.to_string(), status: "failed".to_string(), duration_ms: None, output: None });
                } else if let Some(name) = rest.strip_suffix(" ... ignored") {
                    tests.push(TestResult { name: name.to_string(), status: "ignored".to_string(), duration_ms: None, output: None });
                }
            }
        }
    } else if prog == "python" {
        // pytest: "test_name PASSED" or "test_name FAILED"
        for line in combined.lines() {
            let trimmed = line.trim();
            if let Some(rest) = trimmed.strip_prefix("PASSED ") {
                tests.push(TestResult { name: rest.trim().to_string(), status: "passed".to_string(), duration_ms: None, output: None });
            } else if let Some(rest) = trimmed.strip_prefix("FAILED ") {
                tests.push(TestResult { name: rest.trim().to_string(), status: "failed".to_string(), duration_ms: None, output: None });
            } else if trimmed.contains(" PASSED") {
                let name = trimmed.split(" PASSED").next().unwrap_or(trimmed).trim();
                if !name.is_empty() && !name.starts_with("=") {
                    tests.push(TestResult { name: name.to_string(), status: "passed".to_string(), duration_ms: None, output: None });
                }
            } else if trimmed.contains(" FAILED") && !trimmed.starts_with("=") && !trimmed.starts_with("FAILED") {
                let name = trimmed.split(" FAILED").next().unwrap_or(trimmed).trim();
                if !name.is_empty() {
                    tests.push(TestResult { name: name.to_string(), status: "failed".to_string(), duration_ms: None, output: None });
                }
            }
        }
    } else if prog == "go" {
        // go test: "--- PASS: TestName (0.00s)"
        for line in combined.lines() {
            let trimmed = line.trim();
            if let Some(after_pass) = trimmed.strip_prefix("--- PASS: ") {
                let parts: Vec<&str> = after_pass.split_whitespace().collect();
                let name = parts.first().unwrap_or(&"?").to_string();
                let dur: Option<u64> = parts.get(1).and_then(|s| s.trim_matches(['(','s',')']).parse::<f64>().ok()).map(|s| (s * 1000.0) as u64);
                tests.push(TestResult { name, status: "passed".to_string(), duration_ms: dur, output: None });
            } else if let Some(after_fail) = trimmed.strip_prefix("--- FAIL: ") {
                let parts: Vec<&str> = after_fail.split_whitespace().collect();
                let name = parts.first().unwrap_or(&"?").to_string();
                tests.push(TestResult { name, status: "failed".to_string(), duration_ms: None, output: None });
            }
        }
    } else {
        // npm/yarn/bun: try to parse Jest/Vitest JSON output
        // Look for Jest JSON format: {"testResults": [...]}
        if let Ok(v) = serde_json::from_str::<serde_json::Value>(&stdout) {
            if let Some(results) = v["testResults"].as_array() {
                for suite in results {
                    if let Some(assertions) = suite["assertionResults"].as_array() {
                        for assertion in assertions {
                            let name = assertion["fullName"].as_str()
                                .or_else(|| assertion["title"].as_str())
                                .unwrap_or("?").to_string();
                            let status = match assertion["status"].as_str() {
                                Some("passed") => "passed",
                                Some("failed") => "failed",
                                Some("pending") | Some("skipped") => "ignored",
                                _ => "passed",
                            };
                            let dur = assertion["duration"].as_u64();
                            tests.push(TestResult { name, status: status.to_string(), duration_ms: dur, output: None });
                        }
                    }
                }
            }
        }

        // Fallback: parse Vitest/Jest text output
        if tests.is_empty() {
            for line in combined.lines() {
                let trimmed = line.trim();
                // Vitest: "✓ test name 1ms" or "× test name"
                if let Some(rest) = trimmed.strip_prefix("✓ ").or_else(|| trimmed.strip_prefix("√ ")) {
                    let name = rest.trim_end_matches(|c: char| c.is_ascii_digit() || c == 'm' || c == 's' || c == ' ').trim();
                    tests.push(TestResult { name: name.to_string(), status: "passed".to_string(), duration_ms: None, output: None });
                } else if let Some(rest) = trimmed.strip_prefix("× ").or_else(|| trimmed.strip_prefix("✕ ")) {
                    tests.push(TestResult { name: rest.trim().to_string(), status: "failed".to_string(), duration_ms: None, output: None });
                }
            }
        }
    }

    // If we couldn't parse individual tests, synthesize a single result from exit code
    if tests.is_empty() {
        tests.push(TestResult {
            name: "Test suite".to_string(),
            status: if output.status.success() { "passed".to_string() } else { "failed".to_string() },
            duration_ms: Some(elapsed),
            output: if !output.status.success() { Some(combined.chars().take(2000).collect()) } else { None },
        });
    }

    let passed  = tests.iter().filter(|t| t.status == "passed").count() as u32;
    let failed  = tests.iter().filter(|t| t.status == "failed").count() as u32;
    let ignored = tests.iter().filter(|t| t.status == "ignored").count() as u32;
    let total   = tests.len() as u32;

    Ok(TestRunResult { framework, passed, failed, ignored, total, duration_ms: elapsed, tests })
}

// ─── AI Commit Message (Phase 43) ─────────────────────────────────────────────

/// Generate a commit message for the current git diff using the active LLM provider.
/// Accepts optional `files` list — if provided and nothing is staged, diffs those
/// specific files (unstaged) so the user doesn't have to manually `git add` first.
#[tauri::command]
pub async fn generate_commit_message(
    files: Option<Vec<String>>,
    state: tauri::State<'_, AppState>,
) -> Result<String, String> {
    // Get the workspace path
    let ws = state.workspace.lock().await;
    let ws_path = ws.folders().first()
        .cloned()
        .ok_or_else(|| "No workspace open".to_string())?;
    drop(ws);

    // Try staged diff first
    let diff_output = std::process::Command::new("git")
        .args(["diff", "--staged", "--stat", "--diff-algorithm=histogram"])
        .current_dir(&ws_path)
        .output()
        .map_err(|e| format!("git diff failed: {}", e))?;
    let mut stat = String::from_utf8_lossy(&diff_output.stdout).to_string();

    let diff_output2 = std::process::Command::new("git")
        .args(["diff", "--staged", "--unified=3"])
        .current_dir(&ws_path)
        .output()
        .map_err(|e| format!("git diff body failed: {}", e))?;
    let mut diff_body = String::from_utf8_lossy(&diff_output2.stdout).to_string();

    // If nothing staged, fall back to unstaged diff of the selected files (or all)
    if stat.trim().is_empty() && diff_body.trim().is_empty() {
        let file_args: Vec<String> = files.unwrap_or_default();

        // Get stat for unstaged changes
        let mut stat_cmd = std::process::Command::new("git");
        stat_cmd.args(["diff", "--stat", "--diff-algorithm=histogram"]);
        if !file_args.is_empty() {
            stat_cmd.arg("--");
            for f in &file_args { stat_cmd.arg(f); }
        }
        let stat_out = stat_cmd.current_dir(&ws_path).output()
            .map_err(|e| format!("git diff failed: {}", e))?;
        stat = String::from_utf8_lossy(&stat_out.stdout).to_string();

        // Get diff body for unstaged changes
        let mut diff_cmd = std::process::Command::new("git");
        diff_cmd.args(["diff", "--unified=3"]);
        if !file_args.is_empty() {
            diff_cmd.arg("--");
            for f in &file_args { diff_cmd.arg(f); }
        }
        let diff_out = diff_cmd.current_dir(&ws_path).output()
            .map_err(|e| format!("git diff body failed: {}", e))?;
        diff_body = String::from_utf8_lossy(&diff_out.stdout).to_string();

        // Also check for untracked files in the selection
        if stat.trim().is_empty() && diff_body.trim().is_empty() {
            // Check if any of the files are new/untracked
            let ls_out = std::process::Command::new("git")
                .args(["status", "--porcelain"])
                .current_dir(&ws_path)
                .output()
                .map_err(|e| format!("git status failed: {}", e))?;
            let status_lines = String::from_utf8_lossy(&ls_out.stdout);
            let untracked: Vec<&str> = status_lines.lines()
                .filter(|l| l.starts_with("??") || l.starts_with(" M") || l.starts_with("M ") || l.starts_with("A "))
                .collect();
            if untracked.is_empty() {
                return Err("No changes detected. Modify files first.".to_string());
            }
            // Build a summary from status for untracked/new files
            stat = untracked.join("\n");
            diff_body = "(new/untracked files — no diff available)".to_string();
        }
    }

    let prompt = format!(
        r#"Write a concise git commit message for the following staged diff.
Rules: imperative mood, ≤72 chars subject line, no trailing period, no "feat:"/"fix:" prefix.
Optionally add a blank line + 1-3 bullet body lines for complex changes.

--- stat ---
{}
--- diff (first 4000 chars) ---
{}
---
Respond with the commit message only, no explanation."#,
        stat.trim(),
        diff_body.chars().take(4000).collect::<String>()
    );

    let engine = state.chat_engine.lock().await;
    let messages = vec![vibe_ai::Message {
        role: vibe_ai::MessageRole::User,
        content: prompt,
    }];
    engine.chat(&messages, None)
        .await
        .map(|r| r.trim().to_string())
        .map_err(|e| e.to_string())
}

// ─── Checkpoint Commands ───────────────────────────────────────────────────────

#[derive(Serialize)]
pub struct CheckpointInfo {
    pub index: usize,
    pub message: String,
    pub oid: String,
}

/// Create a git stash checkpoint with a label.
#[tauri::command]
pub async fn create_checkpoint(
    label: String,
    state: tauri::State<'_, AppState>,
) -> Result<String, String> {
    let ws = state.workspace.lock().await;
    let root = ws.folders().first().cloned().ok_or("No workspace folder open")?;
    drop(ws);
    let name = format!("vibeui-checkpoint: {}", label);
    vibe_core::git::create_stash(&root, &name).map_err(|e| e.to_string())
}

/// List all git stash checkpoints.
#[tauri::command]
pub async fn list_checkpoints(
    state: tauri::State<'_, AppState>,
) -> Result<Vec<CheckpointInfo>, String> {
    let ws = state.workspace.lock().await;
    let root = ws.folders().first().cloned().ok_or("No workspace folder open")?;
    drop(ws);
    vibe_core::git::list_stashes(&root)
        .map(|stashes| {
            stashes.into_iter().map(|s| CheckpointInfo {
                index: s.index,
                message: s.message,
                oid: s.oid,
            }).collect()
        })
        .map_err(|e| e.to_string())
}

/// Restore (apply) a checkpoint by index. Does not drop the stash.
#[tauri::command]
pub async fn restore_checkpoint(
    index: usize,
    state: tauri::State<'_, AppState>,
) -> Result<(), String> {
    let ws = state.workspace.lock().await;
    let root = ws.folders().first().cloned().ok_or("No workspace folder open")?;
    drop(ws);
    vibe_core::git::restore_stash(&root, index).map_err(|e| e.to_string())
}

/// Delete (drop) a checkpoint by index permanently.
#[tauri::command]
pub async fn delete_checkpoint(
    index: usize,
    state: tauri::State<'_, AppState>,
) -> Result<(), String> {
    let ws = state.workspace.lock().await;
    let root = ws.folders().first().cloned().ok_or("No workspace folder open")?;
    drop(ws);
    vibe_core::git::drop_stash(&root, index).map_err(|e| e.to_string())
}

// ─── Phase 7.3 — Next-Edit Prediction ────────────────────────────────────────

/// A single edit event used as input for next-edit prediction.
#[derive(Deserialize, Debug)]
pub struct EditEvent {
    pub line: u32,
    pub col: u32,
    pub old_text: String,
    pub new_text: String,
    pub elapsed_ms: u64,
}

/// Predicted next location and replacement text.
#[derive(Serialize, Debug)]
pub struct NextEditPrediction {
    pub target_line: u32,
    pub target_col: u32,
    pub suggested_text: String,
    pub confidence: f32,
}

/// Predict the next edit a developer will make after a series of recent changes.
///
/// Sends the recent edit history to the fast model and parses its JSON response.
/// Returns `None` if the model has no high-confidence prediction.
#[tauri::command]
pub async fn predict_next_edit(
    state: tauri::State<'_, AppState>,
    current_file: String,
    content: String,
    cursor_line: u32,
    _cursor_col: u32,
    recent_edits: Vec<EditEvent>,
    provider: String,
) -> Result<Option<NextEditPrediction>, String> {
    // Build the prediction prompt
    let mut edit_lines = String::new();
    for (i, edit) in recent_edits.iter().enumerate() {
        edit_lines.push_str(&format!(
            "{}. Line {}, col {}: {:?} → {:?} ({}ms ago)\n",
            i + 1, edit.line + 1, edit.col + 1,
            edit.old_text, edit.new_text, edit.elapsed_ms
        ));
    }

    // Count occurrences of old text still in content (to show remaining locations)
    let first_old = recent_edits.first().map(|e| e.old_text.as_str()).unwrap_or("");
    let remaining_count = if first_old.is_empty() {
        0
    } else {
        content.matches(first_old).count()
    };

    let prompt = format!(
        "Recent edits in `{}`:\n{}\n\
        The text {:?} still appears {} more time(s) in the file at cursor line {}.\n\
        Predict the next edit the developer will make. \
        Respond ONLY with JSON (no markdown, no explanation):\n\
        {{\"line\": <0-indexed line>, \"col\": <0-indexed col>, \"replacement\": \"<text>\", \"confidence\": <0.0-1.0>}}\n\
        If you have no confident prediction, respond: {{\"confidence\": 0.0}}",
        current_file, edit_lines,
        first_old, remaining_count,
        cursor_line + 1,
    );

    let messages = vec![
        vibe_ai::Message {
            role: vibe_ai::MessageRole::System,
            content: "You are a next-edit prediction engine. Output only valid JSON.".to_string(),
        },
        vibe_ai::Message {
            role: vibe_ai::MessageRole::User,
            content: prompt,
        },
    ];

    let mut engine = state.chat_engine.lock().await;
    if !provider.is_empty() {
        let _ = engine.set_provider_by_name(&provider);
    }
    let response = engine.chat(&messages, None).await.map_err(|e| e.to_string())?;
    drop(engine);

    // Parse the JSON response
    let raw = response.trim();
    // Strip markdown code fences if present
    let json_str = if raw.starts_with("```") {
        raw.lines()
            .filter(|l| !l.starts_with("```"))
            .collect::<Vec<_>>()
            .join("\n")
    } else {
        raw.to_string()
    };

    #[derive(Deserialize)]
    struct RawPrediction {
        #[serde(default)]
        line: Option<u32>,
        #[serde(default)]
        col: Option<u32>,
        #[serde(default)]
        replacement: Option<String>,
        confidence: f32,
    }

    match serde_json::from_str::<RawPrediction>(&json_str) {
        Ok(pred) if pred.confidence >= 0.5 => {
            if let (Some(line), Some(col), Some(replacement)) = (pred.line, pred.col, pred.replacement) {
                Ok(Some(NextEditPrediction {
                    target_line: line,
                    target_col: col,
                    suggested_text: replacement,
                    confidence: pred.confidence,
                }))
            } else {
                Ok(None)
            }
        }
        _ => Ok(None),
    }
}

// ─── Inline Edit (Cmd+K) ──────────────────────────────────────────────────────

/// AI-powered inline edit: given a selected code range and an instruction,
/// return the replacement text to apply.
#[tauri::command]
#[allow(clippy::too_many_arguments)]
pub async fn inline_edit(
    state: tauri::State<'_, AppState>,
    file_path: String,
    language: String,
    selected_text: String,
    start_line: u32,
    end_line: u32,
    instruction: String,
    provider: String,
) -> Result<String, String> {
    let prompt = format!(
        "You are an expert code editor. \
         Edit the following {language} code according to the instruction.\n\n\
         File: {file_path}\n\
         Lines: {}-{}\n\n\
         === SELECTED CODE ===\n{selected_text}\n=== END CODE ===\n\n\
         Instruction: {instruction}\n\n\
         Respond ONLY with the replacement code (no markdown fences, no explanation). \
         Preserve the original indentation.",
        start_line + 1,
        end_line + 1,
    );

    let messages = vec![vibe_ai::provider::Message {
        role: vibe_ai::provider::MessageRole::User,
        content: prompt,
    }];

    let mut chat_engine = state.chat_engine.lock().await;
    if !provider.is_empty() {
        let _ = chat_engine.set_provider_by_name(&provider);
    }
    chat_engine.chat(&messages, None).await.map_err(|e| e.to_string())
}

/// Generate code at cursor position using file context, project context, and user instruction.
#[tauri::command]
pub async fn generate_code(
    state: tauri::State<'_, AppState>,
    file_path: String,
    language: String,
    file_content: String,
    cursor_line: u32,
    instruction: String,
    provider: String,
) -> Result<String, String> {
    // Gather nearby context: lines around cursor
    let lines: Vec<&str> = file_content.lines().collect();
    let total = lines.len();
    let cursor = cursor_line as usize;
    let before_start = cursor.saturating_sub(40);
    let after_end = (cursor + 20).min(total);
    let before_ctx = lines[before_start..cursor.min(total)].join("\n");
    let after_ctx = if cursor < total { lines[cursor..after_end].join("\n") } else { String::new() };

    // Get project file tree for context
    let ws = {
        let workspace = state.workspace.lock().await;
        workspace.folders().first().cloned()
            .unwrap_or_else(|| std::env::current_dir().unwrap_or_default())
    };
    let mut file_list = Vec::new();
    fn walk_brief(dir: &std::path::Path, prefix: &str, out: &mut Vec<String>, depth: u8) {
        if depth > 3 || out.len() > 100 { return; }
        let Ok(entries) = std::fs::read_dir(dir) else { return };
        for entry in entries.flatten() {
            let name = entry.file_name().to_string_lossy().to_string();
            if name.starts_with('.') || name == "node_modules" || name == "target" || name == "dist" { continue; }
            let path_str = if prefix.is_empty() { name.clone() } else { format!("{}/{}", prefix, name) };
            if entry.file_type().map(|t| t.is_dir()).unwrap_or(false) {
                out.push(format!("{}/", path_str));
                walk_brief(&entry.path(), &path_str, out, depth + 1);
            } else {
                out.push(path_str);
            }
            if out.len() > 100 { return; }
        }
    }
    walk_brief(&ws, "", &mut file_list, 0);
    let project_tree = if file_list.is_empty() { String::new() } else {
        format!("\nPROJECT FILES:\n{}\n", file_list.join("\n"))
    };

    let prompt = format!(
        r#"You are an expert {language} developer. Generate code to insert at line {line} in file "{file_path}".
{project_tree}
=== CODE BEFORE CURSOR (line {before_start_line}-{cursor_line}) ===
{before_ctx}
=== CURSOR IS HERE (line {line}) ===
=== CODE AFTER CURSOR (line {after_start}-{after_end_line}) ===
{after_ctx}
=== END FILE CONTEXT ===

INSTRUCTION: {instruction}

Generate ONLY the code to insert at the cursor position. No markdown fences, no explanations.
Follow the existing code style, indentation, and patterns in the file.
If the instruction is a comment describing what to build, generate the implementation."#,
        language = language,
        file_path = file_path,
        line = cursor_line + 1,
        before_start_line = before_start + 1,
        cursor_line = cursor.min(total),
        after_start = cursor + 1,
        after_end_line = after_end,
        before_ctx = before_ctx,
        after_ctx = after_ctx,
        instruction = instruction,
        project_tree = project_tree,
    );

    let messages = vec![vibe_ai::provider::Message {
        role: vibe_ai::provider::MessageRole::User,
        content: prompt,
    }];

    let mut chat_engine = state.chat_engine.lock().await;
    if !provider.is_empty() {
        let _ = chat_engine.set_provider_by_name(&provider);
    }
    let result = chat_engine.chat(&messages, None).await.map_err(|e| e.to_string())?;

    // Strip markdown fences if the model wrapped them anyway
    let code = result.trim();
    let code = if code.starts_with("```") {
        let s = code.find('\n').map(|i| i + 1).unwrap_or(3);
        let e = code.rfind("```").unwrap_or(code.len());
        &code[s..e]
    } else { code };

    Ok(code.to_string())
}

// ─── Build System Commands ───────────────────────────────────────────────────

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct BuildSystem {
    pub name: String,
    pub build_command: String,
    pub run_command: String,
    pub config_file: String,
    #[serde(default)]
    pub tool_available: bool,
    #[serde(default)]
    pub install_hint: String,
    /// Relative path from workspace root (empty = root, "services/api" = subproject)
    #[serde(default)]
    pub project_path: String,
}

/// Check if a command-line tool is available on PATH.
fn tool_exists(name: &str) -> bool {
    std::process::Command::new("which").arg(name).output()
        .map(|o| o.status.success()).unwrap_or(false)
}

/// Build a BuildSystem with availability check and install hint.
fn build_sys(name: &str, build_cmd: &str, run_cmd: &str, config: &str, tool: &str, install: &str) -> BuildSystem {
    BuildSystem {
        name: name.into(),
        build_command: build_cmd.into(),
        run_command: run_cmd.into(),
        config_file: config.into(),
        tool_available: tool_exists(tool),
        install_hint: install.into(),
        project_path: String::new(),
    }
}

/// Build a BuildSystem scoped to a sub-project path.
fn build_sys_at(name: &str, build_cmd: &str, run_cmd: &str, config: &str, tool: &str, install: &str, rel_path: &str) -> BuildSystem {
    BuildSystem {
        name: name.into(),
        build_command: build_cmd.into(),
        run_command: run_cmd.into(),
        config_file: config.into(),
        tool_available: tool_exists(tool),
        install_hint: install.into(),
        project_path: rel_path.into(),
    }
}

#[derive(Debug, Clone, Serialize)]
pub struct BuildError {
    pub file: Option<String>,
    pub line: Option<u32>,
    pub column: Option<u32>,
    pub message: String,
    pub severity: String,
}

#[derive(Serialize)]
pub struct BuildResult {
    pub build_system: String,
    pub success: bool,
    pub exit_code: i32,
    pub duration_ms: u64,
    pub errors: Vec<BuildError>,
    pub output: String,
}

/// List subdirectories (up to 2 levels deep) for the build directory picker.
#[tauri::command]
pub async fn list_workspace_subdirs(workspace: String) -> Result<Vec<String>, String> {
    let root = std::path::Path::new(&workspace);
    if !root.is_dir() { return Ok(Vec::new()); }
    let mut dirs = Vec::new();
    let Ok(entries) = std::fs::read_dir(root) else { return Ok(dirs); };
    for entry in entries.flatten() {
        let path = entry.path();
        if !path.is_dir() { continue; }
        let name = entry.file_name().to_string_lossy().to_string();
        if name.starts_with('.') || name == "node_modules" || name == "target" || name == "__pycache__"
            || name == "dist" || name == "build" || name == ".git" || name == "vendor" { continue; }
        dirs.push(name.clone());
        // Second level
        if let Ok(sub_entries) = std::fs::read_dir(&path) {
            for sub in sub_entries.flatten() {
                if sub.path().is_dir() {
                    let sub_name = sub.file_name().to_string_lossy().to_string();
                    if !sub_name.starts_with('.') && sub_name != "node_modules" && sub_name != "target" {
                        dirs.push(format!("{name}/{sub_name}"));
                    }
                }
            }
        }
    }
    dirs.sort();
    Ok(dirs)
}

#[tauri::command]
pub async fn detect_build_system(workspace: String) -> Result<Vec<BuildSystem>, String> {
    let path = std::path::PathBuf::from(&workspace);
    let mut systems = Vec::new();

    // ── 1. Check for build config files (project-level build systems) ──
    let node_mgr = if path.join("bun.lockb").exists() { "bun" }
        else if path.join("yarn.lock").exists() { "yarn" }
        else if path.join("pnpm-lock.yaml").exists() { "pnpm" }
        else { "npm" };

    if path.join("Cargo.toml").exists() {
        systems.push(build_sys("cargo", "cargo build", "cargo run", "Cargo.toml", "cargo",
            "Install Rust: curl --proto '=https' --tlsv1.2 -sSf https://sh.rustup.rs | sh"));
    }
    if path.join("package.json").exists() {
        let mut build_cmd = format!("{} run build", node_mgr);
        let mut run_cmd = format!("{} start", node_mgr);
        if let Ok(content) = std::fs::read_to_string(path.join("package.json")) {
            if let Ok(pkg) = serde_json::from_str::<serde_json::Value>(&content) {
                if let Some(scripts) = pkg.get("scripts").and_then(|s| s.as_object()) {
                    if scripts.contains_key("dev") { run_cmd = format!("{} run dev", node_mgr); }
                    if !scripts.contains_key("build") { build_cmd = format!("{} install", node_mgr); }
                }
            }
        }
        systems.push(build_sys(node_mgr, &build_cmd, &run_cmd, "package.json", node_mgr,
            "Install Node.js: https://nodejs.org/ or `brew install node`"));
    }
    if path.join("pom.xml").exists() {
        systems.push(build_sys("maven", "mvn package -q", "mvn exec:java -q", "pom.xml", "mvn",
            "Install Maven: https://maven.apache.org/download.cgi or `brew install maven`"));
    }
    if path.join("build.gradle").exists() || path.join("build.gradle.kts").exists() {
        let wrapper = if path.join("gradlew").exists() { "./gradlew" } else { "gradle" };
        systems.push(build_sys("gradle", &format!("{} build", wrapper), &format!("{} run", wrapper), "build.gradle", "gradle",
            "Install Gradle: https://gradle.org/install/ or `brew install gradle`"));
    }
    if path.join("CMakeLists.txt").exists() {
        systems.push(build_sys("cmake", "cmake -B build && cmake --build build", "./build/main", "CMakeLists.txt", "cmake",
            "Install CMake: https://cmake.org/download/ or `brew install cmake`"));
    }
    if path.join("Makefile").exists() || path.join("makefile").exists() {
        systems.push(build_sys("make", "make", "make run", "Makefile", "make",
            "Install Make: `xcode-select --install` (macOS) or `apt install build-essential` (Linux)"));
    }
    if path.join("go.mod").exists() {
        systems.push(build_sys("go", "go build ./...", "go run .", "go.mod", "go",
            "Install Go: https://go.dev/dl/ or `brew install go`"));
    }
    if path.join("pyproject.toml").exists() || path.join("setup.py").exists() {
        let cfg = if path.join("pyproject.toml").exists() { "pyproject.toml" } else { "setup.py" };
        systems.push(build_sys("python", "pip install -e .", "python -m $(basename $(pwd))", cfg, "python3",
            "Install Python: https://www.python.org/downloads/ or `brew install python`"));
    }
    if path.join("mix.exs").exists() {
        systems.push(build_sys("elixir", "mix compile", "mix run", "mix.exs", "elixir",
            "Install Elixir: https://elixir-lang.org/install.html or `brew install elixir`"));
    }
    let has_csproj = std::fs::read_dir(&path).ok()
        .map(|entries| entries.flatten().any(|e| {
            let n = e.file_name().to_string_lossy().to_string();
            n.ends_with(".csproj") || n.ends_with(".sln")
        })).unwrap_or(false);
    if has_csproj {
        systems.push(build_sys("dotnet", "dotnet build", "dotnet run", "*.csproj", "dotnet",
            "Install .NET: https://dotnet.microsoft.com/download or `brew install dotnet`"));
    }
    if path.join("Gemfile").exists() {
        systems.push(build_sys("ruby", "bundle install", "bundle exec ruby main.rb", "Gemfile", "ruby",
            "Install Ruby: https://www.ruby-lang.org/en/downloads/ or `brew install ruby`"));
    }

    // ── 2. Scan subdirectories for sub-projects (monorepo support) ──
    let skip = ["node_modules", "target", "dist", "build", ".git", "__pycache__", "vendor", ".next", ".nuxt"];
    if let Ok(entries) = std::fs::read_dir(&path) {
        for entry in entries.flatten() {
            let name = entry.file_name().to_string_lossy().to_string();
            if !entry.file_type().map(|t| t.is_dir()).unwrap_or(false) { continue; }
            if name.starts_with('.') || skip.contains(&name.as_str()) { continue; }

            let sub = entry.path();
            let rel = name.clone();

            // Check for build config files in subdirectory
            if sub.join("Cargo.toml").exists() {
                systems.push(build_sys_at("cargo", &format!("cargo build --manifest-path {}/Cargo.toml", rel), &format!("cargo run --manifest-path {}/Cargo.toml", rel), "Cargo.toml", "cargo",
                    "Install Rust: curl --proto '=https' --tlsv1.2 -sSf https://sh.rustup.rs | sh", &rel));
            }
            if sub.join("package.json").exists() {
                let mgr = if sub.join("bun.lockb").exists() { "bun" } else if sub.join("yarn.lock").exists() { "yarn" } else { "npm" };
                systems.push(build_sys_at(mgr, &format!("cd {} && {} run build", rel, mgr), &format!("cd {} && {} start", rel, mgr), "package.json", mgr,
                    "Install Node.js: https://nodejs.org/", &rel));
            }
            if sub.join("pom.xml").exists() {
                systems.push(build_sys_at("maven", &format!("cd {} && mvn package -q", rel), &format!("cd {} && mvn exec:java -q", rel), "pom.xml", "mvn",
                    "Install Maven: https://maven.apache.org/", &rel));
            }
            if sub.join("build.gradle").exists() || sub.join("build.gradle.kts").exists() {
                let wrapper = if sub.join("gradlew").exists() { format!("{}/gradlew", rel) } else { "gradle".into() };
                systems.push(build_sys_at("gradle", &format!("cd {} && {} build", rel, wrapper), &format!("cd {} && {} run", rel, wrapper), "build.gradle", "gradle",
                    "Install Gradle: https://gradle.org/install/", &rel));
            }
            if sub.join("go.mod").exists() {
                systems.push(build_sys_at("go", &format!("cd {} && go build ./...", rel), &format!("cd {} && go run .", rel), "go.mod", "go",
                    "Install Go: https://go.dev/dl/", &rel));
            }
            if sub.join("CMakeLists.txt").exists() {
                systems.push(build_sys_at("cmake", &format!("cd {} && cmake -B build && cmake --build build", rel), &format!("./{}/build/main", rel), "CMakeLists.txt", "cmake",
                    "Install CMake: https://cmake.org/download/", &rel));
            }
            if sub.join("Makefile").exists() {
                systems.push(build_sys_at("make", &format!("cd {} && make", rel), &format!("cd {} && make run", rel), "Makefile", "make",
                    "Install Make: xcode-select --install (macOS)", &rel));
            }
            if sub.join("pyproject.toml").exists() || sub.join("setup.py").exists() {
                systems.push(build_sys_at("python", &format!("cd {} && pip install -e .", rel), &format!("cd {} && python -m .", rel), "pyproject.toml", "python3",
                    "Install Python: https://www.python.org/downloads/", &rel));
            }
            if sub.join("mix.exs").exists() {
                systems.push(build_sys_at("elixir", &format!("cd {} && mix compile", rel), &format!("cd {} && mix run", rel), "mix.exs", "elixir",
                    "Install Elixir: https://elixir-lang.org/install.html", &rel));
            }
        }
    }

    // ── 3. If no build config found, scan for standalone source files ──
    if systems.is_empty() {
        let entries: Vec<String> = std::fs::read_dir(&path).ok()
            .map(|rd| rd.flatten()
                .filter_map(|e| {
                    let name = e.file_name().to_string_lossy().to_string();
                    if e.file_type().map(|t| t.is_file()).unwrap_or(false) { Some(name) } else { None }
                }).collect())
            .unwrap_or_default();

        let has_ext = |ext: &str| entries.iter().any(|f| f.ends_with(ext));

        // Java: compile all .java files, run the one with main()
        if has_ext(".java") {
            let java_files: Vec<&String> = entries.iter().filter(|f| f.ends_with(".java")).collect();
            let files_str = java_files.iter().map(|f| f.as_str()).collect::<Vec<_>>().join(" ");
            // Find main class: check each file for "public static void main"
            let mut main_class = java_files.first().map(|f| f.trim_end_matches(".java").to_string()).unwrap_or_default();
            for f in &java_files {
                if let Ok(content) = std::fs::read_to_string(path.join(f)) {
                    if content.contains("public static void main") {
                        main_class = f.trim_end_matches(".java").to_string();
                        break;
                    }
                }
            }
            systems.push(build_sys("javac", &format!("javac {}", files_str), &format!("java {}", main_class), &files_str, "javac",
                "Install JDK: https://adoptium.net/ or `brew install openjdk`"));
        }

        // C files
        if has_ext(".c") {
            let c_files: Vec<&String> = entries.iter().filter(|f| f.ends_with(".c")).collect();
            let files_str = c_files.iter().map(|f| f.as_str()).collect::<Vec<_>>().join(" ");
            let compiler = if tool_exists("gcc") { "gcc" } else { "cc" };
            systems.push(build_sys(compiler, &format!("{} -o main {}", compiler, files_str), "./main", &files_str, compiler,
                "Install GCC: `xcode-select --install` (macOS) or `apt install gcc` (Linux)"));
        }

        // C++ files
        if has_ext(".cpp") || has_ext(".cc") || has_ext(".cxx") {
            let cpp_files: Vec<&String> = entries.iter().filter(|f| f.ends_with(".cpp") || f.ends_with(".cc") || f.ends_with(".cxx")).collect();
            let files_str = cpp_files.iter().map(|f| f.as_str()).collect::<Vec<_>>().join(" ");
            let compiler = if tool_exists("g++") { "g++" } else { "c++" };
            systems.push(build_sys(compiler, &format!("{} -o main {}", compiler, files_str), "./main", &files_str, compiler,
                "Install G++: `xcode-select --install` (macOS) or `apt install g++` (Linux)"));
        }

        // Go standalone (no go.mod)
        if has_ext(".go") {
            let go_files: Vec<&String> = entries.iter().filter(|f| f.ends_with(".go")).collect();
            let files_str = go_files.iter().map(|f| f.as_str()).collect::<Vec<_>>().join(" ");
            systems.push(build_sys("go", &format!("go build {}", files_str), &format!("go run {}", files_str), &files_str, "go",
                "Install Go: https://go.dev/dl/ or `brew install go`"));
        }

        // Rust standalone (no Cargo.toml)
        if has_ext(".rs") {
            let rs_files: Vec<&String> = entries.iter().filter(|f| f.ends_with(".rs")).collect();
            if let Some(main_file) = rs_files.iter().find(|f| **f == "main.rs").or_else(|| rs_files.first()) {
                systems.push(build_sys("rustc", &format!("rustc {}", main_file), "./main", main_file, "rustc",
                    "Install Rust: curl --proto '=https' --tlsv1.2 -sSf https://sh.rustup.rs | sh"));
            }
        }

        // Python (standalone scripts)
        if has_ext(".py") {
            let py_files: Vec<&String> = entries.iter().filter(|f| f.ends_with(".py")).collect();
            if let Some(main_file) = py_files.iter().find(|f| **f == "main.py" || **f == "app.py").or_else(|| py_files.first()) {
                systems.push(build_sys("python", &format!("python3 -m py_compile {}", main_file), &format!("python3 {}", main_file), main_file, "python3",
                    "Install Python: https://www.python.org/downloads/ or `brew install python`"));
            }
        }

        // TypeScript standalone
        if has_ext(".ts") && !has_ext(".js") {
            let ts_files: Vec<&String> = entries.iter().filter(|f| f.ends_with(".ts")).collect();
            let files_str = ts_files.iter().map(|f| f.as_str()).collect::<Vec<_>>().join(" ");
            let runner = if tool_exists("bun") { "bun" } else if tool_exists("ts-node") { "ts-node" } else { "npx ts-node" };
            if let Some(main) = ts_files.iter().find(|f| **f == "index.ts" || **f == "main.ts").or_else(|| ts_files.first()) {
                systems.push(build_sys("typescript", &format!("npx tsc {}", files_str), &format!("{} {}", runner, main), &files_str, "tsc",
                    "Install TypeScript: `npm install -g typescript` or use Bun: https://bun.sh/"));
            }
        }

        // Kotlin
        if has_ext(".kt") {
            let kt_files: Vec<&String> = entries.iter().filter(|f| f.ends_with(".kt")).collect();
            let files_str = kt_files.iter().map(|f| f.as_str()).collect::<Vec<_>>().join(" ");
            systems.push(build_sys("kotlin", &format!("kotlinc {} -include-runtime -d app.jar", files_str), "java -jar app.jar", &files_str, "kotlinc",
                "Install Kotlin: https://kotlinlang.org/docs/command-line.html or `brew install kotlin`"));
        }

        // Swift
        if has_ext(".swift") {
            let sw_files: Vec<&String> = entries.iter().filter(|f| f.ends_with(".swift")).collect();
            let files_str = sw_files.iter().map(|f| f.as_str()).collect::<Vec<_>>().join(" ");
            systems.push(build_sys("swift", &format!("swiftc -o main {}", files_str), "./main", &files_str, "swiftc",
                "Install Swift: https://www.swift.org/download/ (included with Xcode on macOS)"));
        }

        // Zig
        if has_ext(".zig") {
            let zig_files: Vec<&String> = entries.iter().filter(|f| f.ends_with(".zig")).collect();
            if let Some(main_file) = zig_files.iter().find(|f| **f == "main.zig").or_else(|| zig_files.first()) {
                systems.push(build_sys("zig", &format!("zig build-exe {}", main_file), "./main", main_file, "zig",
                    "Install Zig: https://ziglang.org/download/ or `brew install zig`"));
            }
        }

        // Nim
        if has_ext(".nim") {
            let nim_files: Vec<&String> = entries.iter().filter(|f| f.ends_with(".nim")).collect();
            if let Some(main_file) = nim_files.iter().find(|f| **f == "main.nim").or_else(|| nim_files.first()) {
                let bin_name = main_file.trim_end_matches(".nim");
                systems.push(build_sys("nim", &format!("nim compile {}", main_file), &format!("./{}", bin_name), main_file, "nim",
                    "Install Nim: https://nim-lang.org/install.html or `brew install nim`"));
            }
        }

        // Crystal
        if has_ext(".cr") {
            let cr_files: Vec<&String> = entries.iter().filter(|f| f.ends_with(".cr")).collect();
            if let Some(main_file) = cr_files.iter().find(|f| **f == "main.cr").or_else(|| cr_files.first()) {
                systems.push(build_sys("crystal", &format!("crystal build {}", main_file), &format!("./{}", main_file.trim_end_matches(".cr")), main_file, "crystal",
                    "Install Crystal: https://crystal-lang.org/install/ or `brew install crystal`"));
            }
        }

        // Ada (GNAT)
        if has_ext(".adb") || has_ext(".ads") {
            let ada_files: Vec<&String> = entries.iter().filter(|f| f.ends_with(".adb")).collect();
            if let Some(main_file) = ada_files.iter().find(|f| **f == "main.adb").or_else(|| ada_files.first()) {
                let bin_name = main_file.trim_end_matches(".adb");
                systems.push(build_sys("gnat", &format!("gnatmake {}", main_file), &format!("./{}", bin_name), main_file, "gnatmake",
                    "Install GNAT: `apt install gnat` (Linux) or `brew install gnat` (macOS) — https://www.adacore.com/download"));
            }
        }

        // D
        if has_ext(".d") {
            let d_files: Vec<&String> = entries.iter().filter(|f| f.ends_with(".d")).collect();
            let files_str = d_files.iter().map(|f| f.as_str()).collect::<Vec<_>>().join(" ");
            systems.push(build_sys("dmd", &format!("dmd -of=main {}", files_str), "./main", &files_str, "dmd",
                "Install D: https://dlang.org/download.html or `brew install dmd`"));
        }

        // Dart
        if let Some(main) = entries.iter().find(|f| *f == "main.dart" || f.ends_with(".dart")) {
            systems.push(build_sys("dart", &format!("dart compile exe {}", main), &format!("dart run {}", main), main, "dart",
                "Install Dart: https://dart.dev/get-dart or `brew install dart`"));
        }

        // Haskell
        if let Some(main) = entries.iter().find(|f| *f == "Main.hs" || f.ends_with(".hs")) {
            systems.push(build_sys("ghc", &format!("ghc -o main {}", main), "./main", main, "ghc",
                "Install GHC: https://www.haskell.org/ghcup/ or `brew install ghc`"));
        }

        // Scala
        if let Some(main) = entries.iter().find(|f| f.ends_with(".scala")) {
            systems.push(build_sys("scalac", &format!("scalac {}", main), &format!("scala {}", main.trim_end_matches(".scala")), main, "scalac",
                "Install Scala: https://www.scala-lang.org/download/ or `brew install scala`"));
        }

        // OCaml
        if let Some(main) = entries.iter().find(|f| f.ends_with(".ml")) {
            systems.push(build_sys("ocaml", &format!("ocamlfind ocamlopt -o main {}", main), "./main", main, "ocamlfind",
                "Install OCaml: https://ocaml.org/install or `brew install ocaml opam`"));
        }

        // Erlang
        if let Some(main) = entries.iter().find(|f| f.ends_with(".erl")) {
            let mod_name = main.trim_end_matches(".erl");
            systems.push(build_sys("erlc", &format!("erlc {}", main), &format!("erl -noshell -s {} start -s init stop", mod_name), main, "erlc",
                "Install Erlang: https://www.erlang.org/downloads or `brew install erlang`"));
        }

        // Perl
        if let Some(main) = entries.iter().find(|f| *f == "main.pl" || *f == "app.pl" || f.ends_with(".pl")) {
            systems.push(build_sys("perl", &format!("perl -c {}", main), &format!("perl {}", main), main, "perl",
                "Perl is usually pre-installed. Otherwise: https://www.perl.org/get.html"));
        }

        // PHP
        if let Some(main) = entries.iter().find(|f| *f == "index.php" || f.ends_with(".php")) {
            systems.push(build_sys("php", &format!("php -l {}", main), &format!("php {}", main), main, "php",
                "Install PHP: https://www.php.net/downloads or `brew install php`"));
        }

        // Lua
        if let Some(main) = entries.iter().find(|f| *f == "main.lua" || *f == "init.lua" || f.ends_with(".lua")) {
            systems.push(build_sys("lua", &format!("luac -p {}", main), &format!("lua {}", main), main, "lua",
                "Install Lua: https://www.lua.org/download.html or `brew install lua`"));
        }

        // R
        if let Some(main) = entries.iter().find(|f| f.ends_with(".R") || f.ends_with(".r")) {
            systems.push(build_sys("r", &format!("Rscript --vanilla {}", main), &format!("Rscript {}", main), main, "Rscript",
                "Install R: https://cran.r-project.org/ or `brew install r`"));
        }

        // Julia
        if let Some(main) = entries.iter().find(|f| *f == "main.jl" || f.ends_with(".jl")) {
            systems.push(build_sys("julia", &format!("julia --compiled-modules=yes {}", main), &format!("julia {}", main), main, "julia",
                "Install Julia: https://julialang.org/downloads/ or `brew install julia`"));
        }

        // Fortran
        if has_ext(".f90") || has_ext(".f") || has_ext(".f95") {
            let f_files: Vec<&String> = entries.iter().filter(|f| f.ends_with(".f90") || f.ends_with(".f") || f.ends_with(".f95")).collect();
            let files_str = f_files.iter().map(|f| f.as_str()).collect::<Vec<_>>().join(" ");
            systems.push(build_sys("gfortran", &format!("gfortran -o main {}", files_str), "./main", &files_str, "gfortran",
                "Install GFortran: `brew install gcc` (macOS) or `apt install gfortran` (Linux)"));
        }

        // V
        if has_ext(".v") && !has_ext(".vala") {
            if let Some(main) = entries.iter().find(|f| f.ends_with(".v")) {
                systems.push(build_sys("vlang", &format!("v {}", main), &format!("v run {}", main), main, "v",
                    "Install V: https://vlang.io/ or `brew install vlang`"));
            }
        }

        // Racket
        if let Some(main) = entries.iter().find(|f| f.ends_with(".rkt")) {
            systems.push(build_sys("racket", &format!("raco make {}", main), &format!("racket {}", main), main, "racket",
                "Install Racket: https://racket-lang.org/download/ or `brew install racket`"));
        }

        // Pascal
        if let Some(main) = entries.iter().find(|f| f.ends_with(".pas") || f.ends_with(".pp")) {
            systems.push(build_sys("fpc", &format!("fpc {}", main), &format!("./{}", main.split('.').next().unwrap_or("main")), main, "fpc",
                "Install Free Pascal: https://www.freepascal.org/ or `brew install fpc`"));
        }

        // Prolog
        if has_ext(".pl") && entries.iter().any(|f| f.ends_with(".pro") || (f.ends_with(".pl") && std::fs::read_to_string(std::path::Path::new(&path).join(f)).unwrap_or_default().contains(":-"))) {
            // Skip if already detected as Perl
        }
    }

    Ok(systems)
}

#[tauri::command]
pub async fn run_build(
    app_handle: tauri::AppHandle,
    workspace: String,
    command: Option<String>,
) -> Result<BuildResult, String> {
    let cmd_str = if let Some(cmd) = command {
        cmd
    } else {
        let systems = detect_build_system(workspace.clone()).await?;
        systems.first().map(|s| s.build_command.clone()).ok_or("No build system detected")?
    };
    let build_system_name = detect_build_system(workspace.clone()).await.ok().and_then(|s| s.first().map(|b| b.name.clone())).unwrap_or("unknown".into());

    let _ = app_handle.emit("build:log", format!("$ {}", cmd_str));
    let started = std::time::Instant::now();

    use tokio::process::Command as TokioCommand;
    use tokio::io::{AsyncBufReadExt, BufReader};

    let mut child = TokioCommand::new("sh")
        .arg("-c")
        .arg(&cmd_str)
        .current_dir(&workspace)
        .stdout(std::process::Stdio::piped())
        .stderr(std::process::Stdio::piped())
        .spawn()
        .map_err(|e| format!("Failed to spawn build: {}", e))?;

    let stdout = child.stdout.take().expect("stdout piped");
    let stderr = child.stderr.take().expect("stderr piped");

    let app2 = app_handle.clone();
    let stderr_handle = tokio::spawn(async move {
        let mut lines = BufReader::new(stderr).lines();
        let mut collected = Vec::new();
        while let Ok(Some(line)) = lines.next_line().await {
            let _ = app2.emit("build:log", line.clone());
            collected.push(line);
        }
        collected
    });

    let mut all_output = Vec::new();
    let mut stdout_reader = BufReader::new(stdout).lines();
    while let Ok(Some(line)) = stdout_reader.next_line().await {
        let _ = app_handle.emit("build:log", line.clone());
        all_output.push(line);
    }

    let stderr_lines = stderr_handle.await.unwrap_or_default();
    all_output.extend(stderr_lines);

    let status = child.wait().await.map_err(|e| e.to_string())?;
    let duration_ms = started.elapsed().as_millis() as u64;
    let exit_code = status.code().unwrap_or(-1);
    let combined = all_output.join("\n");

    // Parse errors from output
    let errors = parse_build_errors(&combined, &build_system_name);

    let _ = app_handle.emit("build:log", format!("\nBuild {} in {:.1}s (exit {})", if status.success() { "succeeded" } else { "failed" }, duration_ms as f64 / 1000.0, exit_code));

    Ok(BuildResult {
        build_system: build_system_name,
        success: status.success(),
        exit_code,
        duration_ms,
        errors,
        output: if combined.len() > 4000 { combined[combined.len()-4000..].to_string() } else { combined },
    })
}

#[tauri::command]
pub async fn run_app(
    app_handle: tauri::AppHandle,
    workspace: String,
    command: Option<String>,
) -> Result<BuildResult, String> {
    let cmd_str = if let Some(cmd) = command {
        cmd
    } else {
        let systems = detect_build_system(workspace.clone()).await?;
        systems.first().map(|s| s.run_command.clone()).ok_or("No run command detected")?
    };

    let _ = app_handle.emit("run:log", format!("$ {}", cmd_str));
    let started = std::time::Instant::now();

    use tokio::process::Command as TokioCommand;
    use tokio::io::{AsyncBufReadExt, BufReader};

    let mut child = TokioCommand::new("sh")
        .arg("-c")
        .arg(&cmd_str)
        .current_dir(&workspace)
        .stdout(std::process::Stdio::piped())
        .stderr(std::process::Stdio::piped())
        .spawn()
        .map_err(|e| format!("Failed to spawn app: {}", e))?;

    let stdout = child.stdout.take().expect("stdout piped");
    let stderr = child.stderr.take().expect("stderr piped");

    let app2 = app_handle.clone();
    let stderr_handle = tokio::spawn(async move {
        let mut lines = BufReader::new(stderr).lines();
        let mut collected = Vec::new();
        while let Ok(Some(line)) = lines.next_line().await {
            let _ = app2.emit("run:log", line.clone());
            collected.push(line);
        }
        collected
    });

    let mut all_output = Vec::new();
    let mut stdout_reader = BufReader::new(stdout).lines();
    while let Ok(Some(line)) = stdout_reader.next_line().await {
        let _ = app_handle.emit("run:log", line.clone());
        all_output.push(line);
    }

    let stderr_lines = stderr_handle.await.unwrap_or_default();
    all_output.extend(stderr_lines);

    let status = child.wait().await.map_err(|e| e.to_string())?;
    let duration_ms = started.elapsed().as_millis() as u64;
    let combined = all_output.join("\n");

    Ok(BuildResult {
        build_system: "app".into(),
        success: status.success(),
        exit_code: status.code().unwrap_or(-1),
        duration_ms,
        errors: vec![],
        output: if combined.len() > 4000 { combined[combined.len()-4000..].to_string() } else { combined },
    })
}

fn parse_build_errors(output: &str, build_system: &str) -> Vec<BuildError> {
    let mut errors = Vec::new();
    let lines: Vec<&str> = output.lines().collect();

    for (i, line) in lines.iter().enumerate() {
        match build_system {
            "cargo" => {
                // Rust: "error[E0308]: mismatched types" followed by " --> src/main.rs:10:5"
                if line.contains("error[E") || line.starts_with("error:") || line.starts_with("warning:") {
                    let severity = if line.contains("warning") { "warning" } else { "error" };
                    let msg = line.trim().to_string();
                    let mut file = None;
                    let mut ln = None;
                    let mut col = None;
                    for line_j in lines.iter().take(lines.len().min(i+5)).skip(i+1) {
                        if let Some(arrow) = line_j.find("--> ") {
                            let loc = &line_j[arrow+4..];
                            let parts: Vec<&str> = loc.rsplitn(3, ':').collect();
                            if parts.len() >= 3 {
                                col = parts[0].trim().parse().ok();
                                ln = parts[1].trim().parse().ok();
                                file = Some(parts[2].to_string());
                            }
                            break;
                        }
                    }
                    errors.push(BuildError { file, line: ln, column: col, message: msg, severity: severity.into() });
                }
            }
            "npm" | "yarn" | "bun" | "pnpm" => {
                // TypeScript: "src/App.tsx(10,5): error TS2345: ..."
                if line.contains("): error TS") || line.contains("): warning TS") {
                    let severity = if line.contains("warning") { "warning" } else { "error" };
                    if let Some(paren) = line.find('(') {
                        let file = line[..paren].trim().to_string();
                        let rest = &line[paren+1..];
                        if let Some(close) = rest.find(')') {
                            let coords = &rest[..close];
                            let parts: Vec<&str> = coords.split(',').collect();
                            let ln = parts.first().and_then(|s| s.trim().parse().ok());
                            let col = parts.get(1).and_then(|s| s.trim().parse().ok());
                            let msg = rest[close+1..].trim_start_matches(':').trim().to_string();
                            errors.push(BuildError { file: Some(file), line: ln, column: col, message: msg, severity: severity.into() });
                        }
                    }
                }
            }
            "go" | "cmake" | "make" => {
                // GCC/Go: "file.go:10:5: error message"
                let parts: Vec<&str> = line.splitn(4, ':').collect();
                if parts.len() >= 4 {
                    let ln: Option<u32> = parts[1].trim().parse().ok();
                    let col: Option<u32> = parts[2].trim().parse().ok();
                    if ln.is_some() {
                        let msg = parts[3].trim().to_string();
                        let severity = if msg.starts_with(" warning") || msg.starts_with("warning") { "warning" } else { "error" };
                        errors.push(BuildError { file: Some(parts[0].to_string()), line: ln, column: col, message: msg, severity: severity.into() });
                    }
                }
            }
            "maven" => {
                // Maven: "[ERROR] /path/File.java:[10,5] error message"
                if line.starts_with("[ERROR]") && line.contains(":[") {
                    let content = &line[7..].trim();
                    if let Some(colon) = content.find(":[") {
                        let file = content[..colon].to_string();
                        let rest = &content[colon+2..];
                        if let Some(bracket) = rest.find(']') {
                            let coords = &rest[..bracket];
                            let parts: Vec<&str> = coords.split(',').collect();
                            let ln = parts.first().and_then(|s| s.trim().parse().ok());
                            let col = parts.get(1).and_then(|s| s.trim().parse().ok());
                            let msg = rest[bracket+1..].trim().to_string();
                            errors.push(BuildError { file: Some(file), line: ln, column: col, message: msg, severity: "error".into() });
                        }
                    }
                }
            }
            "dotnet" => {
                // .NET: "File.cs(10,5): error CS0001: message"
                if (line.contains("): error") || line.contains("): warning")) && line.contains("CS") {
                    let severity = if line.contains("warning") { "warning" } else { "error" };
                    if let Some(paren) = line.find('(') {
                        let file = line[..paren].trim().to_string();
                        let rest = &line[paren+1..];
                        if let Some(close) = rest.find(')') {
                            let coords = &rest[..close];
                            let parts: Vec<&str> = coords.split(',').collect();
                            let ln = parts.first().and_then(|s| s.trim().parse().ok());
                            let col = parts.get(1).and_then(|s| s.trim().parse().ok());
                            let msg = rest[close+1..].trim_start_matches(':').trim().to_string();
                            errors.push(BuildError { file: Some(file), line: ln, column: col, message: msg, severity: severity.into() });
                        }
                    }
                }
            }
            _ => {}
        }
    }

    // Deduplicate
    errors.dedup_by(|a, b| a.message == b.message && a.file == b.file && a.line == b.line);
    errors
}

// ─── Phase 5 — Trace / History Commands ───────────────────────────────────────

#[derive(Serialize)]
pub struct TraceSessionInfo {
    pub session_id: String,
    pub timestamp: u64,
    pub step_count: usize,
}

#[derive(Serialize)]
pub struct TraceEntryInfo {
    pub timestamp: u64,
    pub session_id: String,
    pub step: usize,
    pub tool: String,
    pub input_summary: String,
    pub output: String,
    pub success: bool,
    pub duration_ms: u64,
    pub approved_by: String,
}

fn vibeui_trace_dir() -> std::path::PathBuf {
    let base = std::env::var("HOME")
        .map(std::path::PathBuf::from)
        .unwrap_or_else(|_| std::path::PathBuf::from("."));
    base.join(".vibeui").join("traces")
}

/// List all agent trace sessions for the HistoryPanel.
#[tauri::command]
pub async fn list_trace_sessions() -> Result<Vec<TraceSessionInfo>, String> {
    let dir = vibeui_trace_dir();
    let sessions = vibe_ai::list_traces(&dir);
    Ok(sessions
        .into_iter()
        .map(|s| TraceSessionInfo {
            session_id: s.session_id,
            timestamp: s.timestamp,
            step_count: s.step_count,
        })
        .collect())
}

/// Load all entries from a specific trace session.
#[tauri::command]
pub async fn load_trace_session(session_id: String) -> Result<Vec<TraceEntryInfo>, String> {
    let dir = vibeui_trace_dir();
    let path = dir.join(format!("{}.jsonl", session_id));
    let entries = vibe_ai::load_trace(&path);
    Ok(entries
        .into_iter()
        .map(|e| TraceEntryInfo {
            timestamp: e.timestamp,
            session_id: e.session_id,
            step: e.step,
            tool: e.tool,
            input_summary: e.input_summary,
            output: e.output,
            success: e.success,
            duration_ms: e.duration_ms,
            approved_by: e.approved_by,
        })
        .collect())
}

/// Aggregate trust metrics across all trace sessions.
/// Returns per-tool success/failure counts and per-session entries for scoring.
#[derive(Serialize)]
pub struct TrustTraceEntry {
    pub session_id: String,
    pub timestamp: u64,
    pub tool: String,
    pub success: bool,
    pub duration_ms: u64,
}

#[tauri::command]
pub async fn get_all_trace_entries() -> Result<Vec<TrustTraceEntry>, String> {
    let dir = vibeui_trace_dir();
    let sessions = vibe_ai::list_traces(&dir);
    let mut all_entries = Vec::new();
    for s in &sessions {
        let path = dir.join(format!("{}.jsonl", s.session_id));
        let entries = vibe_ai::load_trace(&path);
        for e in entries {
            all_entries.push(TrustTraceEntry {
                session_id: e.session_id,
                timestamp: e.timestamp,
                tool: e.tool,
                success: e.success,
                duration_ms: e.duration_ms,
            });
        }
    }
    // Sort newest first
    all_entries.sort_by(|a, b| b.timestamp.cmp(&a.timestamp));
    Ok(all_entries)
}

// ── Attachment Commands ──────────────────────────────────────────────────────

/// Read a file from disk and return it as a ChatAttachment (base64-encoded).
/// Handles images, text files, PDFs, and other documents.
#[tauri::command]
pub async fn read_attachment(path: String) -> Result<ChatAttachment, String> {
    let file_path = std::path::Path::new(&path);
    if !file_path.exists() {
        return Err(format!("File not found: {}", path));
    }
    let metadata = std::fs::metadata(file_path).map_err(|e| e.to_string())?;
    // Limit to 20 MB
    if metadata.len() > 20 * 1024 * 1024 {
        return Err("File too large (max 20 MB)".to_string());
    }

    let name = file_path.file_name()
        .and_then(|n| n.to_str())
        .unwrap_or("file")
        .to_string();

    let ext = file_path.extension()
        .and_then(|e| e.to_str())
        .unwrap_or("")
        .to_lowercase();

    let mime_type = match ext.as_str() {
        "png" => "image/png",
        "jpg" | "jpeg" => "image/jpeg",
        "gif" => "image/gif",
        "webp" => "image/webp",
        "svg" => "image/svg+xml",
        "pdf" => "application/pdf",
        "csv" => "text/csv",
        "json" => "application/json",
        "xml" => "application/xml",
        "html" | "htm" => "text/html",
        "md" | "markdown" => "text/markdown",
        "txt" | "log" => "text/plain",
        "rs" | "py" | "js" | "ts" | "tsx" | "jsx" | "go" | "java" | "c" | "cpp" | "h"
        | "rb" | "php" | "swift" | "kt" | "scala" | "sh" | "bash" | "zsh" | "sql"
        | "yaml" | "yml" | "toml" | "ini" | "cfg" | "conf" | "env"
        | "css" | "scss" | "less" | "vue" | "svelte" => "text/plain",
        _ => "application/octet-stream",
    }.to_string();

    // For text files, read as UTF-8 and send text_content directly (no base64 round-trip)
    let is_text = mime_type.starts_with("text/") || mime_type == "application/json"
        || mime_type == "application/xml";

    if is_text {
        match std::fs::read_to_string(file_path) {
            Ok(content) => {
                let size = std::fs::metadata(file_path).map(|m| m.len() as usize).unwrap_or(content.len());
                Ok(ChatAttachment {
                    name,
                    mime_type,
                    data: String::new(), // no base64 needed for text
                    size,
                    text_content: Some(content),
                })
            }
            Err(_) => {
                // File is detected as text but isn't valid UTF-8 — treat as binary
                use std::io::Read;
                let mut bytes = Vec::new();
                std::fs::File::open(file_path).map_err(|e| e.to_string())?
                    .read_to_end(&mut bytes).map_err(|e| e.to_string())?;
                let size = bytes.len();
                let data = base64_encode_bytes(&bytes);
                Ok(ChatAttachment { name, mime_type, data, size, text_content: None })
            }
        }
    } else {
        // Binary/image files: read raw bytes and base64-encode
        use std::io::Read;
        let mut bytes = Vec::new();
        std::fs::File::open(file_path).map_err(|e| e.to_string())?
            .read_to_end(&mut bytes).map_err(|e| e.to_string())?;
        let size = bytes.len();
        let data = base64_encode_bytes(&bytes);
        Ok(ChatAttachment { name, mime_type, data, size, text_content: None })
    }
}

/// Decode base64 data to a UTF-8 string (returns None for binary/invalid UTF-8).
fn base64_decode_to_string(b64: &str) -> Option<String> {
    const DECODE: [u8; 128] = {
        let mut t = [0xFFu8; 128];
        let chars = b"ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/";
        let mut i = 0;
        while i < 64 {
            t[chars[i] as usize] = i as u8;
            i += 1;
        }
        t
    };
    let filtered: Vec<u8> = b64.bytes().filter(|&b| b != b'=' && b != b'\n' && b != b'\r' && b != b' ').collect();
    let mut out = Vec::with_capacity(filtered.len() * 3 / 4);
    for chunk in filtered.chunks(4) {
        if chunk.iter().any(|&b| b >= 128 || DECODE[b as usize] == 0xFF) {
            return None;
        }
        let vals: Vec<u8> = chunk.iter().map(|&b| DECODE[b as usize]).collect();
        let n = match vals.len() {
            4 => (vals[0] as u32) << 18 | (vals[1] as u32) << 12 | (vals[2] as u32) << 6 | vals[3] as u32,
            3 => (vals[0] as u32) << 18 | (vals[1] as u32) << 12 | (vals[2] as u32) << 6,
            2 => (vals[0] as u32) << 18 | (vals[1] as u32) << 12,
            _ => return None,
        };
        out.push((n >> 16) as u8);
        if vals.len() > 2 { out.push((n >> 8) as u8); }
        if vals.len() > 3 { out.push(n as u8); }
    }
    String::from_utf8(out).ok()
}

/// Simple base64 encoder for attachment data.
fn base64_encode_bytes(data: &[u8]) -> String {
    const CHARS: &[u8] = b"ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/";
    let mut out = String::with_capacity(data.len().div_ceil(3) * 4);
    for chunk in data.chunks(3) {
        let b0 = chunk[0] as u32;
        let b1 = if chunk.len() > 1 { chunk[1] as u32 } else { 0 };
        let b2 = if chunk.len() > 2 { chunk[2] as u32 } else { 0 };
        let n = (b0 << 16) | (b1 << 8) | b2;
        out.push(CHARS[((n >> 18) & 0x3F) as usize] as char);
        out.push(CHARS[((n >> 12) & 0x3F) as usize] as char);
        if chunk.len() > 1 { out.push(CHARS[((n >> 6) & 0x3F) as usize] as char); } else { out.push('='); }
        if chunk.len() > 2 { out.push(CHARS[(n & 0x3F) as usize] as char); } else { out.push('='); }
    }
    out
}

// ── Session Browser Commands ──────────────────────────────────────────────────

#[derive(Serialize)]
pub struct SessionBrowserEntry {
    pub id: String,
    pub timestamp: u64,
    pub message_count: usize,
    pub file_size: u64,
    pub has_messages: bool,
    pub has_context: bool,
}

#[derive(Serialize)]
pub struct SessionMessage {
    pub role: String,
    pub content: String,
}

fn vibecli_trace_dir(workspace: &str) -> std::path::PathBuf {
    std::path::PathBuf::from(workspace)
        .join(".vibecli")
        .join("traces")
}

/// List all sessions in the workspace's `.vibecli/traces/` directory.
#[tauri::command]
pub async fn list_sessions(workspace: String) -> Result<Vec<SessionBrowserEntry>, String> {
    let dir = vibecli_trace_dir(&workspace);
    let entries = match std::fs::read_dir(&dir) {
        Ok(e) => e,
        Err(_) => return Ok(vec![]),
    };
    let mut sessions: Vec<SessionBrowserEntry> = entries
        .flatten()
        .filter_map(|e| {
            let name = e.file_name().to_string_lossy().to_string();
            let id = name.strip_suffix(".jsonl")?;
            let meta = e.metadata().ok()?;
            let file_size = meta.len();
            // Count lines in the JSONL file for step count
            let step_count = count_lines_at(&e.path()).unwrap_or(0);
            // Check for sidecar files
            let messages_path = dir.join(format!("{}-messages.json", id));
            let context_path = dir.join(format!("{}-context.json", id));
            let has_messages = messages_path.exists();
            let has_context = context_path.exists();
            // Message count: if messages sidecar exists, count entries; else use step_count
            let message_count = if has_messages {
                std::fs::read_to_string(&messages_path)
                    .ok()
                    .and_then(|s| serde_json::from_str::<Vec<serde_json::Value>>(&s).ok())
                    .map(|v| v.len())
                    .unwrap_or(step_count)
            } else {
                step_count
            };
            // Parse timestamp from session ID (may be "name-12345" or plain "12345")
            let ts: u64 = id
                .rsplit('-')
                .next()
                .and_then(|s| s.parse().ok())
                .unwrap_or(0);
            Some(SessionBrowserEntry {
                id: id.to_string(),
                timestamp: ts,
                message_count,
                file_size,
                has_messages,
                has_context,
            })
        })
        .collect();
    sessions.sort_by(|a, b| b.timestamp.cmp(&a.timestamp));
    Ok(sessions)
}

fn count_lines_at(path: &std::path::Path) -> Option<usize> {
    let f = std::fs::File::open(path).ok()?;
    Some(std::io::BufReader::new(f).lines().count())
}

use std::io::BufRead as BufReadSessions;

/// Load conversation messages for a specific session.
#[tauri::command]
pub async fn get_session_detail(
    workspace: String,
    session_id: String,
) -> Result<Vec<SessionMessage>, String> {
    let dir = vibecli_trace_dir(&workspace);
    // Prefer messages sidecar
    let messages_path = dir.join(format!("{}-messages.json", session_id));
    if messages_path.exists() {
        let data = std::fs::read_to_string(&messages_path)
            .map_err(|e| format!("Failed to read messages file: {}", e))?;
        let raw: Vec<serde_json::Value> = serde_json::from_str(&data)
            .map_err(|e| format!("Failed to parse messages JSON: {}", e))?;
        let messages = raw
            .into_iter()
            .map(|v| SessionMessage {
                role: v
                    .get("role")
                    .and_then(|r| r.as_str())
                    .unwrap_or("unknown")
                    .to_string(),
                content: v
                    .get("content")
                    .and_then(|c| c.as_str())
                    .unwrap_or("")
                    .to_string(),
            })
            .collect();
        return Ok(messages);
    }
    // Fallback: reconstruct from JSONL trace entries
    let jsonl_path = dir.join(format!("{}.jsonl", session_id));
    if !jsonl_path.exists() {
        return Err(format!("Session {} not found", session_id));
    }
    let entries = vibe_ai::load_trace(&jsonl_path);
    let messages = entries
        .into_iter()
        .map(|e| SessionMessage {
            role: if e.tool == "user_message" {
                "user".to_string()
            } else {
                "assistant".to_string()
            },
            content: if e.input_summary.is_empty() {
                e.output
            } else {
                format!("[{}] {}", e.tool, e.input_summary)
            },
        })
        .collect();
    Ok(messages)
}

/// Delete a session and its sidecar files.
#[tauri::command]
pub async fn delete_session(
    workspace: String,
    session_id: String,
) -> Result<(), String> {
    let dir = vibecli_trace_dir(&workspace);
    // Prevent path traversal
    if session_id.contains("..") || session_id.contains('/') || session_id.contains('\\') {
        return Err("Invalid session ID".to_string());
    }
    let jsonl = dir.join(format!("{}.jsonl", session_id));
    let messages = dir.join(format!("{}-messages.json", session_id));
    let context = dir.join(format!("{}-context.json", session_id));
    if !jsonl.exists() {
        return Err(format!("Session {} not found", session_id));
    }
    let _ = std::fs::remove_file(&jsonl);
    let _ = std::fs::remove_file(&messages);
    let _ = std::fs::remove_file(&context);
    Ok(())
}

// ── Phase 8 (extra) — Hooks Config UI ─────────────────────────────────────────

/// A simplified hook config descriptor for the UI (avoids exposing internal enum variants).
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct HookConfigUi {
    pub event: String,
    #[serde(default)]
    pub tools: Vec<String>,
    /// "command", "llm", or "http"
    pub handler_type: String,
    /// Shell command string (for handler_type == "command")
    #[serde(default)]
    pub command: String,
    /// LLM prompt template (for handler_type == "llm")
    #[serde(default)]
    pub prompt: String,
    /// HTTP webhook URL (for handler_type == "http")
    #[serde(default)]
    pub http_url: String,
    /// HTTP method: POST, PUT, PATCH, GET (for handler_type == "http")
    #[serde(default = "default_http_method_str")]
    pub http_method: String,
    /// HTTP headers as JSON string (for handler_type == "http")
    #[serde(default)]
    pub http_headers: String,
    /// HTTP timeout in ms (for handler_type == "http")
    #[serde(default = "default_http_timeout")]
    pub http_timeout_ms: u64,
    #[serde(default)]
    pub async_exec: bool,
}

fn default_http_method_str() -> String { "POST".to_string() }
fn default_http_timeout() -> u64 { 10_000 }

fn hooks_config_path(workspace_path: Option<&str>) -> std::path::PathBuf {
    if let Some(ws) = workspace_path {
        if !ws.is_empty() {
            return std::path::PathBuf::from(ws).join(".vibecli").join("hooks.json");
        }
    }
    let home = std::env::var("HOME").unwrap_or_else(|_| ".".to_string());
    std::path::PathBuf::from(home).join(".vibecli").join("hooks.json")
}

/// Load hooks configuration for the Hooks Config UI panel.
#[tauri::command]
pub async fn get_hooks_config(workspace_path: Option<String>) -> Result<Vec<HookConfigUi>, String> {
    let path = hooks_config_path(workspace_path.as_deref());
    if !path.exists() {
        return Ok(vec![]);
    }
    let json = std::fs::read_to_string(&path).map_err(|e| e.to_string())?;
    serde_json::from_str(&json).map_err(|e| e.to_string())
}

/// Save hooks configuration from the Hooks Config UI panel.
#[tauri::command]
pub async fn save_hooks_config(
    hooks: Vec<HookConfigUi>,
    workspace_path: Option<String>,
) -> Result<(), String> {
    let path = hooks_config_path(workspace_path.as_deref());
    if let Some(parent) = path.parent() {
        std::fs::create_dir_all(parent).map_err(|e| e.to_string())?;
    }
    let json = serde_json::to_string_pretty(&hooks).map_err(|e| e.to_string())?;
    std::fs::write(&path, json).map_err(|e| e.to_string())
}

// ── Phase 9.1 — Manager View (Parallel Agent Orchestration) ──────────────────

/// Describes one running or completed parallel agent instance.
#[derive(Debug, Clone, Serialize)]
pub struct AgentInstanceInfo {
    pub id: String,
    pub task: String,
    /// "pending" | "running" | "done" | "failed"
    pub status: String,
    pub step_count: usize,
    pub branch: String,
    pub worktree_path: String,
}

/// A task spec submitted to the parallel orchestrator.
#[derive(Debug, Deserialize)]
pub struct ParallelAgentTask {
    pub id: String,
    pub task: String,
    /// Optional list of task IDs this one depends on (reserved for future dependency tracking).
    #[serde(default)]
    pub _depends_on: Vec<String>,
}

/// Spawn multiple parallel agents for the Manager View.
///
/// Emits Tauri events:
/// - `manager:agent_update` → `AgentInstanceInfo`   (status change)
/// - `manager:agent_step`   → `{id, step_num, tool}` (per-step progress)
#[tauri::command]
pub async fn start_parallel_agents(
    tasks: Vec<ParallelAgentTask>,
    provider: String,
    approval_policy: String,
    app_handle: tauri::AppHandle,
    state: tauri::State<'_, AppState>,
) -> Result<Vec<AgentInstanceInfo>, String> {
    use vibe_ai::{AgentLoop, AgentContext, ApprovalPolicy, AgentEvent};
    use crate::agent_executor::TauriToolExecutor;

    if tasks.is_empty() {
        return Ok(vec![]);
    }

    let workspace_root = {
        let ws = state.workspace.lock().await;
        ws.folders().first().cloned().unwrap_or_else(|| PathBuf::from("."))
    };

    let provider_arc = {
        let mut engine = state.chat_engine.lock().await;
        engine.set_provider_by_name(&provider).map_err(|e| e.to_string())?;
        engine.active_provider().ok_or("No active provider")?.clone()
    };

    let approval = ApprovalPolicy::from_str(&approval_policy);

    // Build initial status list for the UI
    let mut instances: Vec<AgentInstanceInfo> = tasks
        .iter()
        .map(|t| AgentInstanceInfo {
            id: t.id.clone(),
            task: t.task.clone(),
            status: "pending".to_string(),
            step_count: 0,
            branch: format!("agent/{}", t.id),
            worktree_path: workspace_root
                .join(".agent-worktrees")
                .join(&t.id)
                .to_string_lossy()
                .into_owned(),
        })
        .collect();

    let handle = app_handle.clone();
    let root = workspace_root.clone();
    let prov = provider_arc.clone();

    // Spawn agents concurrently — one independent AgentLoop per task
    for (i, task) in tasks.iter().enumerate() {
        let task_id = task.id.clone();
        let task_desc = task.task.clone();
        let prov2 = prov.clone();
        let root2 = root.clone();
        let approval2 = approval.clone();
        let h2 = handle.clone();

        // Emit "running" status
        instances[i].status = "running".to_string();
        let _ = handle.emit("manager:agent_update", instances[i].clone());

        tokio::spawn(async move {
            let git_branch = vibe_core::git::get_current_branch(&root2).ok();
            let memory_context = {
                let mem_path = root2.join(".vibe").join("memory.md");
                std::fs::read_to_string(&mem_path).ok().filter(|s| !s.trim().is_empty())
            };
            let context = AgentContext {
                workspace_root: root2.clone(),
                open_files: vec![],
                git_branch,
                git_diff_summary: None,
                flow_context: None,
                approved_plan: None,
                extra_skill_dirs: vec![],
                parent_session_id: None,
                depth: 0,
                active_agent_counter: None,
                team_bus: None,
                team_agent_id: None,
                project_summary: None,
                task_context_files: vec![],
                memory_context,
                auto_commit: false,
            };

            let executor = Arc::new(
                TauriToolExecutor::with_app(root2, h2.clone())
                    .with_provider(prov2.clone())
                    .with_parent_context(context.clone()),
            );
            let agent = AgentLoop::new(prov2, approval2, executor);
            let (event_tx, mut event_rx) = tokio::sync::mpsc::channel::<AgentEvent>(64);

            let tid = task_id.clone();
            let h3 = h2.clone();

            tokio::spawn(async move {
                let _ = agent.run(&task_desc, context, event_tx).await;
            });

            let mut step_count: usize = 0;
            while let Some(event) = event_rx.recv().await {
                match event {
                    AgentEvent::ToolCallExecuted(step) => {
                        step_count += 1;
                        let payload = serde_json::json!({
                            "id": &tid,
                            "step_num": step.step_num,
                            "tool": step.tool_call.name(),
                            "success": step.tool_result.success,
                        });
                        let _ = h3.emit("manager:agent_step", payload);
                    }
                    AgentEvent::Complete(_) => {
                        let update = AgentInstanceInfo {
                            id: tid.clone(),
                            task: String::new(),
                            status: "done".to_string(),
                            step_count,
                            branch: format!("agent/{}", &tid),
                            worktree_path: String::new(),
                        };
                        let _ = h3.emit("manager:agent_update", update);
                        break;
                    }
                    AgentEvent::Error(msg) => {
                        let update = AgentInstanceInfo {
                            id: tid.clone(),
                            task: msg,
                            status: "failed".to_string(),
                            step_count,
                            branch: format!("agent/{}", &tid),
                            worktree_path: String::new(),
                        };
                        let _ = h3.emit("manager:agent_update", update);
                        break;
                    }
                    _ => {}
                }
            }
        });
    }

    Ok(instances)
}

/// Retrieve current status of all spawned parallel agents.
///
/// Since agents run as background tasks, this returns the last-known status
/// from the emitted Tauri events. The frontend maintains the live state;
/// this command provides a snapshot for initial render.
#[tauri::command]
pub async fn get_orchestrator_status(
    state: tauri::State<'_, AppState>,
) -> Result<Vec<AgentInstanceInfo>, String> {
    // The live state is maintained by the frontend via manager:agent_update events.
    // Return empty list — the frontend builds its view from events.
    let _ = state;
    Ok(vec![])
}

/// Merge a completed agent's worktree branch into the main branch.
///
/// Strategy: "merge" (default) | "squash" | "rebase"
#[tauri::command]
pub async fn merge_agent_branch(
    agent_id: String,
    strategy: String,
    state: tauri::State<'_, AppState>,
) -> Result<String, String> {
    let workspace_root = {
        let ws = state.workspace.lock().await;
        ws.folders().first().cloned().unwrap_or_else(|| PathBuf::from("."))
    };

    let branch = format!("agent/{}", agent_id);

    // Use git CLI to perform the merge
    let merge_args: Vec<&str> = match strategy.as_str() {
        "squash" => vec!["merge", "--squash", &branch],
        "rebase" => vec!["rebase", &branch],
        _ => vec!["merge", "--no-ff", &branch],
    };

    let output = std::process::Command::new("git")
        .args(&merge_args)
        .current_dir(&workspace_root)
        .output()
        .map_err(|e| format!("git error: {e}"))?;

    if output.status.success() {
        Ok(format!(
            "Merged branch '{}' using '{}' strategy",
            branch, strategy
        ))
    } else {
        Err(String::from_utf8_lossy(&output.stderr).trim().to_string())
    }
}

// ── Code Review ───────────────────────────────────────────────────────────────

/// Run an AI-powered code review and return a structured report.
#[tauri::command]
pub async fn run_code_review(
    state: tauri::State<'_, AppState>,
    workspace_path: String,
    base_ref: Option<String>,
    target_ref: Option<String>,
) -> Result<serde_json::Value, String> {
    let workspace = PathBuf::from(&workspace_path);

    // Get git diff
    let base = base_ref.as_deref().unwrap_or("");
    let diff_args: Vec<&str> = if base.is_empty() {
        vec!["diff", "HEAD"]
    } else {
        vec!["diff", base, target_ref.as_deref().unwrap_or("HEAD")]
    };

    let diff_output = std::process::Command::new("git")
        .args(&diff_args)
        .current_dir(&workspace)
        .output()
        .map_err(|e| format!("git error: {e}"))?;

    let diff = String::from_utf8_lossy(&diff_output.stdout).to_string();
    if diff.trim().is_empty() {
        return Err("No diff found. Make sure there are uncommitted changes or specify a valid base ref.".to_string());
    }

    // Truncate very large diffs
    let diff_for_review = if diff.len() > 20_000 {
        {
            let end = diff.char_indices().nth(20_000).map(|(i,_)| i).unwrap_or(diff.len());
            format!("{}\n...(diff truncated at 20k chars)", &diff[..end])
        }
    } else {
        diff
    };

    // Get the active AI provider from the chat engine.
    let provider = {
        let engine = state.chat_engine.lock().await;
        engine.active_provider().ok_or("No active AI provider. Set a provider first.")?.clone()
    };

    let review_prompt = format!(
        r#"You are an expert code reviewer. Analyze this git diff and produce a structured review.

Respond ONLY with a JSON object matching this exact schema:
{{
  "summary": "2-3 sentence summary of the changes",
  "issues": [
    {{
      "file": "path/to/file.rs",
      "line": 42,
      "severity": "critical|warning|info",
      "category": "security|performance|correctness|style|testing",
      "description": "What is wrong",
      "suggested_fix": "How to fix it (optional)"
    }}
  ],
  "suggestions": [
    {{ "description": "General suggestion", "file": "optional/file.rs" }}
  ],
  "score": {{
    "overall": 7.5,
    "correctness": 8.0,
    "security": 9.0,
    "performance": 7.0,
    "style": 6.5
  }},
  "files_reviewed": ["list", "of", "files"]
}}

Scores are 0–10 (10 = excellent). Only report real issues.

## Git Diff
```diff
{}
```"#,
        diff_for_review
    );

    let messages = vec![
        vibe_ai::provider::Message {
            role: vibe_ai::provider::MessageRole::User,
            content: review_prompt,
        },
    ];

    let response = provider
        .chat(&messages, None)
        .await
        .map_err(|e| format!("AI provider error: {e}"))?;

    // Extract JSON from the response (strip markdown code fences if present)
    let json_str = extract_json(&response);
    let mut report: serde_json::Value = serde_json::from_str(&json_str)
        .map_err(|e| {
            let end = response.char_indices().nth(500).map(|(i,_)| i).unwrap_or(response.len());
            format!("Failed to parse review JSON: {e}\n\nRaw: {}", &response[..end])
        })?;

    // Inject refs for display
    report["base_ref"] = serde_json::Value::String(base_ref.unwrap_or_default());
    report["target_ref"] = serde_json::Value::String(target_ref.unwrap_or_else(|| "HEAD".to_string()));

    Ok(report)
}

/// Open a URL in the system's default browser using the Tauri opener plugin.
#[tauri::command]
pub async fn open_external_url(
    url: String,
    app: tauri::AppHandle,
) -> Result<(), String> {
    if !url.starts_with("http://") && !url.starts_with("https://") {
        return Err("Only http:// and https:// URLs are supported.".to_string());
    }
    use tauri_plugin_opener::OpenerExt;
    app.opener()
        .open_url(&url, None::<&str>)
        .map_err(|e| e.to_string())
}

// ── Symbol + Codebase Search Commands ─────────────────────────────────────────

#[derive(Serialize)]
pub struct SymbolResult {
    pub name: String,
    pub kind: String,
    pub file: String,
    pub line: usize,
}

/// Search the workspace codebase for symbols matching `query` (substring/fuzzy).
/// Returns up to 20 results, sorted by relevance.
#[tauri::command]
pub async fn search_workspace_symbols(
    query: String,
    state: tauri::State<'_, AppState>,
) -> Result<Vec<SymbolResult>, String> {
    let root = {
        let ws = state.workspace.lock().await;
        ws.folders().first().cloned().ok_or("No workspace folder open")?
    };
    let mut idx = vibe_core::index::CodebaseIndex::new(root.clone());
    idx.build().map_err(|e| e.to_string())?;
    let hits = idx.search_symbols(&query);
    Ok(hits.into_iter().take(20).map(|s| SymbolResult {
        name: s.name,
        kind: format!("{:?}", s.kind),
        file: s.file.strip_prefix(&root).unwrap_or(&s.file)
            .to_string_lossy().into_owned(),
        line: s.line,
    }).collect())
}

/// Semantic search over the workspace.
///
/// 1. If `.vibeui/embeddings/index.json` exists in the workspace root, loads the
///    `EmbeddingIndex` and performs cosine-similarity search.
/// 2. Otherwise falls back to fast keyword/symbol search via `CodebaseIndex`.
#[tauri::command]
pub async fn semantic_search_codebase(
    query: String,
    limit: Option<usize>,
    state: tauri::State<'_, AppState>,
) -> Result<Vec<SymbolResult>, String> {
    let k = limit.unwrap_or(8).min(20);
    let root = {
        let ws = state.workspace.lock().await;
        ws.folders().first().cloned().ok_or("No workspace folder open")?
    };

    // ── Try embedding search first ────────────────────────────────────────────
    let index_path = root.join(".vibeui").join("embeddings").join("index.json");
    if index_path.exists() {
        use vibe_core::index::embeddings::EmbeddingIndex;
        match EmbeddingIndex::load(&index_path) {
            Ok(idx) => {
                match idx.search(&query, k).await {
                    Ok(hits) => {
                        return Ok(hits.into_iter().map(|h| {
                            let rel = h.file.strip_prefix(&root).unwrap_or(&h.file)
                                .to_string_lossy().into_owned();
                            SymbolResult {
                                name: h.text.lines().next().unwrap_or("").trim()
                                    .chars().take(80).collect(),
                                kind: format!("snippet (score {:.2})", h.score),
                                file: rel,
                                line: h.chunk_start,
                            }
                        }).collect());
                    }
                    Err(e) => {
                        eprintln!("[vibeui] EmbeddingIndex search failed ({}); falling back to keyword", e);
                    }
                }
            }
            Err(e) => {
                eprintln!("[vibeui] Could not load embedding index ({}); falling back to keyword", e);
            }
        }
    }

    // ── Keyword/symbol fallback ───────────────────────────────────────────────
    let mut idx2 = vibe_core::index::CodebaseIndex::new(root.clone());
    idx2.build().map_err(|e| e.to_string())?;
    let hits = idx2.search_symbols(&query);
    Ok(hits.into_iter().take(k).map(|s| SymbolResult {
        name: s.name,
        kind: format!("{:?}", s.kind),
        file: s.file.strip_prefix(&root).unwrap_or(&s.file).to_string_lossy().into_owned(),
        line: s.line,
    }).collect())
}

/// Build (or rebuild) the workspace embedding index.
///
/// Saves to `<workspace>/.vibeui/embeddings/index.json`.
/// `provider`: `"ollama"` (default) or `"openai"`.
/// `model`: embedding model name (default `"nomic-embed-text"` for Ollama).
#[tauri::command]
pub async fn build_embedding_index(
    provider: Option<String>,
    model: Option<String>,
    state: tauri::State<'_, AppState>,
) -> Result<String, String> {
    use vibe_core::index::embeddings::{EmbeddingIndex, EmbeddingProvider};

    let root = {
        let ws = state.workspace.lock().await;
        ws.folders().first().cloned().ok_or("No workspace folder open")?
    };

    let embedding_provider = match provider.as_deref().unwrap_or("ollama") {
        "openai" => {
            let key = std::env::var("OPENAI_API_KEY")
                .map_err(|_| "OPENAI_API_KEY env var not set".to_string())?;
            EmbeddingProvider::openai(key)
        }
        _ => EmbeddingProvider::ollama(
            model.as_deref().unwrap_or("nomic-embed-text"),
        ),
    };

    let idx = EmbeddingIndex::build(&root, &embedding_provider)
        .await
        .map_err(|e| e.to_string())?;

    let chunk_count = idx.chunk_count();
    let file_count = idx.file_count();

    let index_path = root.join(".vibeui").join("embeddings").join("index.json");
    idx.save(&index_path).map_err(|e| e.to_string())?;

    Ok(format!(
        "Built embedding index: {} files, {} chunks → {}",
        file_count, chunk_count, index_path.display()
    ))
}

// ── @docs context ─────────────────────────────────────────────────────────────

/// Fetch library documentation from an online registry.
///
/// `registry`: `"rs"` (docs.rs), `"npm"` (npmjs.com), `"py"` (PyPI).
/// Returns a plain-text summary (max 4000 chars) suitable for AI injection.
#[tauri::command]
pub async fn fetch_doc_content(name: String, registry: String) -> Result<String, String> {
    let url = match registry.as_str() {
        "rs" => format!("https://docs.rs/crate/{}/latest/", name),
        "npm" => format!("https://registry.npmjs.org/{}", name),
        "py" => format!("https://pypi.org/pypi/{}/json", name),
        _ => return Err(format!("Unknown registry: {}", registry)),
    };

    let body = fetch_and_strip(&url).await.map_err(|e| e.to_string())?;

    // For JSON registries, try to extract meaningful fields
    if registry == "npm" || registry == "py" {
        if let Ok(json) = serde_json::from_str::<serde_json::Value>(&body) {
            let summary = if registry == "npm" {
                let desc = json["description"].as_str().unwrap_or("").to_string();
                let ver  = json["dist-tags"]["latest"].as_str().unwrap_or("?");
                let kws: Vec<&str> = json["keywords"].as_array()
                    .map(|a| a.iter().filter_map(|v| v.as_str()).collect())
                    .unwrap_or_default();
                format!(
                    "Package: {} (npm v{})\n{}\nKeywords: {}",
                    name, ver, desc, kws.join(", ")
                )
            } else {
                // PyPI JSON
                let info = &json["info"];
                let desc = info["summary"].as_str().unwrap_or("").to_string();
                let ver  = info["version"].as_str().unwrap_or("?");
                format!("Package: {} (PyPI v{})\n{}", name, ver, desc)
            };
            return Ok(summary.chars().take(4000).collect());
        }
    }

    // For docs.rs, return stripped HTML text
    Ok(body.chars().take(4000).collect())
}

// ── Linter integration ────────────────────────────────────────────────────────

#[derive(Debug, Serialize, Deserialize)]
pub struct LintErrorOut {
    pub line: usize,
    pub col: usize,
    pub severity: String,
    pub message: String,
    pub rule: Option<String>,
}

#[derive(Debug, Serialize)]
pub struct LintResultOut {
    pub errors: Vec<LintErrorOut>,
    pub warnings: Vec<LintErrorOut>,
    pub raw_output: String,
    pub linter_available: bool,
}

/// Run the appropriate linter for `file_path` and return parsed results.
///
/// Supported linters:
/// - `eslint` — TypeScript/JavaScript
/// - `cargo-check` — Rust (fast, no borrow-checker bypass)
/// - `flake8` — Python
/// - `go-vet` — Go
#[tauri::command]
pub async fn run_linter(file_path: String, linter: String) -> Result<LintResultOut, String> {
    use std::process::Command;

    let path = std::path::Path::new(&file_path);
    let dir  = path.parent().unwrap_or(std::path::Path::new("."));

    let (prog, args, parse_mode) = match linter.as_str() {
        "eslint" => (
            "eslint",
            vec!["--format", "json", &file_path],
            "eslint-json",
        ),
        "cargo-check" => (
            "cargo",
            vec!["check", "--message-format=json", "--quiet"],
            "cargo-json",
        ),
        "flake8" => (
            "flake8",
            vec!["--format=%(path)s:%(row)d:%(col)d:%(code)s:%(text)s", &file_path],
            "flake8-text",
        ),
        "go-vet" => (
            "go",
            vec!["vet", &file_path],
            "go-text",
        ),
        _ => return Ok(LintResultOut {
            errors: vec![], warnings: vec![],
            raw_output: format!("Unknown linter: {}", linter),
            linter_available: false,
        }),
    };

    let output = match Command::new(prog)
        .args(&args)
        .current_dir(dir)
        .output()
    {
        Ok(o) => o,
        Err(e) if e.kind() == std::io::ErrorKind::NotFound => {
            return Ok(LintResultOut {
                errors: vec![], warnings: vec![],
                raw_output: format!("{} not found in PATH", prog),
                linter_available: false,
            });
        }
        Err(e) => return Err(e.to_string()),
    };

    let stdout = String::from_utf8_lossy(&output.stdout).to_string();
    let stderr = String::from_utf8_lossy(&output.stderr).to_string();
    let raw_output = if stdout.is_empty() { stderr.clone() } else { stdout.clone() };

    let (errors, warnings) = match parse_mode {
        "eslint-json" => parse_eslint_json(&stdout),
        "cargo-json"  => parse_cargo_json(&stdout),
        "flake8-text" => parse_flake8_text(&stdout),
        _             => parse_generic_text(&stderr),
    };

    Ok(LintResultOut { errors, warnings, raw_output, linter_available: true })
}

fn parse_eslint_json(output: &str) -> (Vec<LintErrorOut>, Vec<LintErrorOut>) {
    let mut errors = vec![];
    let mut warnings = vec![];
    if let Ok(json) = serde_json::from_str::<serde_json::Value>(output) {
        if let Some(files) = json.as_array() {
            for file in files {
                if let Some(msgs) = file["messages"].as_array() {
                    for msg in msgs {
                        let sev = if msg["severity"].as_u64().unwrap_or(2) == 1 { "warning" } else { "error" };
                        let item = LintErrorOut {
                            line: msg["line"].as_u64().unwrap_or(1) as usize,
                            col: msg["column"].as_u64().unwrap_or(1) as usize,
                            severity: sev.to_string(),
                            message: msg["message"].as_str().unwrap_or("").to_string(),
                            rule: msg["ruleId"].as_str().map(|s| s.to_string()),
                        };
                        if sev == "error" { errors.push(item); } else { warnings.push(item); }
                    }
                }
            }
        }
    }
    (errors, warnings)
}

fn parse_cargo_json(output: &str) -> (Vec<LintErrorOut>, Vec<LintErrorOut>) {
    let mut errors = vec![];
    let mut warnings = vec![];
    for line in output.lines() {
        if let Ok(msg) = serde_json::from_str::<serde_json::Value>(line) {
            if msg["reason"].as_str() != Some("compiler-message") { continue; }
            let level = msg["message"]["level"].as_str().unwrap_or("");
            let text  = msg["message"]["message"].as_str().unwrap_or("").to_string();
            let spans = msg["message"]["spans"].as_array();
            let (line_no, col_no) = spans
                .and_then(|s| s.first())
                .map(|sp| (
                    sp["line_start"].as_u64().unwrap_or(1) as usize,
                    sp["column_start"].as_u64().unwrap_or(1) as usize,
                ))
                .unwrap_or((1, 1));
            let item = LintErrorOut {
                line: line_no, col: col_no,
                severity: if level == "error" { "error" } else { "warning" }.to_string(),
                message: text, rule: None,
            };
            if level == "error" { errors.push(item); } else { warnings.push(item); }
        }
    }
    (errors, warnings)
}

fn parse_flake8_text(output: &str) -> (Vec<LintErrorOut>, Vec<LintErrorOut>) {
    let mut errors = vec![];
    let mut warnings = vec![];
    for line in output.lines() {
        // Format: path:row:col:code:text
        let parts: Vec<&str> = line.splitn(5, ':').collect();
        if parts.len() < 5 { continue; }
        let row: usize = parts[1].trim().parse().unwrap_or(1);
        let col: usize = parts[2].trim().parse().unwrap_or(1);
        let code = parts[3].trim();
        let msg  = parts[4].trim().to_string();
        let is_error = code.starts_with('E');
        let item = LintErrorOut {
            line: row, col,
            severity: if is_error { "error" } else { "warning" }.to_string(),
            message: msg,
            rule: Some(code.to_string()),
        };
        if is_error { errors.push(item); } else { warnings.push(item); }
    }
    (errors, warnings)
}

fn parse_generic_text(output: &str) -> (Vec<LintErrorOut>, Vec<LintErrorOut>) {
    let errors: Vec<LintErrorOut> = output.lines()
        .filter(|l| !l.is_empty())
        .take(20)
        .map(|l| LintErrorOut {
            line: 1, col: 1,
            severity: "error".to_string(),
            message: l.to_string(),
            rule: None,
        })
        .collect();
    (errors, vec![])
}

