#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct ModelResponse {
    pub provider: String,
    pub model: String,
    pub content: String,
    pub duration_ms: u64,
    pub tokens: Option<u32>,
    pub error: Option<String>,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct CompareResult {
    pub a: ModelResponse,
    pub b: ModelResponse,
}

/// Build a temporary provider instance by type name.
/// Checks environment variables first, then falls back to saved API keys
/// from `~/.vibecli/profile_settings.db`.
fn build_temp_provider(provider_type: &str, model: &str)
    -> Option<Arc<dyn vibe_ai::provider::AIProvider>>
{
    use vibe_ai::providers;
    use vibe_ai::provider::ProviderConfig;

    // Try env var first
    let api_key_from_env = match provider_type {
        "claude" | "anthropic" => std::env::var("ANTHROPIC_API_KEY").ok(),
        "openai"               => std::env::var("OPENAI_API_KEY").ok(),
        "gemini" | "google"    => std::env::var("GEMINI_API_KEY").or_else(|_| std::env::var("GOOGLE_API_KEY")).ok(),
        "grok"                 => std::env::var("GROK_API_KEY").or_else(|_| std::env::var("XAI_API_KEY")).ok(),
        "groq"                 => std::env::var("GROQ_API_KEY").ok(),
        "mistral"              => std::env::var("MISTRAL_API_KEY").ok(),
        "deepseek"             => std::env::var("DEEPSEEK_API_KEY").ok(),
        "cerebras"             => std::env::var("CEREBRAS_API_KEY").ok(),
        "openrouter"           => std::env::var("OPENROUTER_API_KEY").ok(),
        "perplexity"           => std::env::var("PERPLEXITY_API_KEY").ok(),
        "together"             => std::env::var("TOGETHER_API_KEY").ok(),
        "fireworks"            => std::env::var("FIREWORKS_API_KEY").ok(),
        "ollama"               => Some(String::new()),
        _                      => std::env::var(format!("{}_API_KEY", provider_type.to_uppercase())).ok(),
    };

    // Fall back to saved settings from profile_settings.db
    let api_key = match api_key_from_env {
        Some(ref k) if !k.is_empty() || provider_type == "ollama" => api_key_from_env,
        _ => {
            let provider_name = match provider_type {
                "claude" | "anthropic" => "anthropic",
                "gemini" | "google"    => "gemini",
                other => other,
            };
            _ProfileStore::new().ok()
                .and_then(|s| s.get_api_key(_PROFILE_ID, provider_name).ok().flatten())
                .filter(|k| !k.is_empty())
        }
    };

    // Reject providers that need an API key but don't have one
    if provider_type != "ollama" && api_key.as_ref().is_none_or(|k| k.is_empty()) {
        return None;
    }

    let cfg = ProviderConfig {
        provider_type: provider_type.to_string(),
        api_key,
        model: model.to_string(),
        ..Default::default()
    };

    let p: Arc<dyn vibe_ai::provider::AIProvider> = match provider_type {
        "claude" | "anthropic" => Arc::new(providers::ClaudeProvider::new(cfg)),
        "openai"               => Arc::new(providers::OpenAIProvider::new(cfg)),
        "gemini" | "google"    => Arc::new(providers::GeminiProvider::new(cfg)),
        "grok"                 => Arc::new(providers::GrokProvider::new(cfg)),
        "groq"                 => Arc::new(providers::GroqProvider::new(cfg)),
        "mistral"              => Arc::new(providers::MistralProvider::new(cfg)),
        "deepseek"             => Arc::new(providers::DeepSeekProvider::new(cfg)),
        "cerebras"             => Arc::new(providers::CerebrasProvider::new(cfg)),
        "openrouter"           => Arc::new(providers::OpenRouterProvider::new(cfg)),
        "perplexity"           => Arc::new(providers::PerplexityProvider::new(cfg)),
        "together"             => Arc::new(providers::TogetherProvider::new(cfg)),
        "fireworks"            => Arc::new(providers::FireworksProvider::new(cfg)),
        "ollama"               => Arc::new(providers::OllamaProvider::new(cfg)),
        _                      => return None,
    };
    Some(vibe_ai::ResilientProvider::wrap(p))
}

/// Call a single provider with a prompt and return a `ModelResponse`.
async fn call_provider(provider_type: &str, model: &str, prompt: &str) -> ModelResponse {
    use vibe_ai::provider::{Message, MessageRole};
    let start = std::time::Instant::now();
    let messages = vec![Message { role: MessageRole::User, content: prompt.to_string() }];

    let Some(provider) = build_temp_provider(provider_type, model) else {
        return ModelResponse {
            provider: provider_type.to_string(), model: model.to_string(),
            content: String::new(), duration_ms: 0, tokens: None,
            error: Some(format!("Provider '{provider_type}' is not configured")),
        };
    };

    match provider.chat_response(&messages, None).await {
        Ok(resp) => ModelResponse {
            provider: provider_type.to_string(),
            model: model.to_string(),
            content: resp.text,
            duration_ms: start.elapsed().as_millis() as u64,
            tokens: resp.usage.map(|u| u.total()),
            error: None,
        },
        Err(e) => ModelResponse {
            provider: provider_type.to_string(),
            model: model.to_string(),
            content: String::new(),
            duration_ms: start.elapsed().as_millis() as u64,
            tokens: None,
            error: Some(e.to_string()),
        },
    }
}

/// Send the same prompt to two providers in parallel and return both responses.
#[tauri::command]
pub async fn compare_models(
    prompt: String,
    provider_a: String,
    model_a: String,
    provider_b: String,
    model_b: String,
) -> Result<CompareResult, String> {
    let (a, b) = tokio::join!(
        call_provider(&provider_a, &model_a, &prompt),
        call_provider(&provider_b, &model_b, &prompt),
    );
    Ok(CompareResult { a, b })
}

// ══════════════════════════════════════════════════════════════════════════════
// Phase 44 — HTTP Playground
// ══════════════════════════════════════════════════════════════════════════════

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct HttpRequestHeader {
    pub key: String,
    pub value: String,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct HttpResponseData {
    pub status: u16,
    pub status_text: String,
    pub headers: Vec<HttpRequestHeader>,
    pub body: String,
    pub duration_ms: u64,
}

/// Send an HTTP request and return the response.
#[tauri::command]
pub async fn send_http_request(
    method: String,
    url: String,
    headers: Vec<HttpRequestHeader>,
    body: Option<String>,
) -> Result<HttpResponseData, String> {
    if !url.starts_with("http://") && !url.starts_with("https://") {
        return Err("URL must start with http:// or https://".to_string());
    }

    let start = std::time::Instant::now();
    let client = reqwest::Client::builder()
        .timeout(std::time::Duration::from_secs(30))
        .build()
        .map_err(|e| e.to_string())?;

    let method_parsed = reqwest::Method::from_bytes(method.to_uppercase().as_bytes())
        .map_err(|e| e.to_string())?;

    let mut req = client.request(method_parsed, &url);
    for h in &headers {
        req = req.header(h.key.as_str(), h.value.as_str());
    }
    if let Some(b) = body {
        req = req.body(b);
    }

    let resp = req.send().await.map_err(|e| e.to_string())?;
    let duration_ms = start.elapsed().as_millis() as u64;
    let status = resp.status();
    let resp_headers: Vec<HttpRequestHeader> = resp.headers().iter()
        .map(|(k, v)| HttpRequestHeader {
            key: k.to_string(),
            value: v.to_str().unwrap_or("").to_string(),
        })
        .collect();
    let body_text = resp.text().await.map_err(|e| e.to_string())?;

    Ok(HttpResponseData {
        status: status.as_u16(),
        status_text: status.canonical_reason().unwrap_or("").to_string(),
        headers: resp_headers,
        body: body_text,
        duration_ms,
    })
}

/// Grep the workspace for common API route patterns.
#[tauri::command]
pub async fn discover_api_endpoints(workspace: String) -> Result<Vec<String>, String> {
    static PATTERNS: &[&str] = &[
        r"app\.(get|post|put|delete|patch)\s*\(",
        r"router\.(get|post|put|delete|patch)\s*\(",
        r#"@(Get|Post|Put|Delete|Patch)\s*\("#,
        r"\.route\s*\(",
        r#"axum::Router::new\(\)"#,
    ];
    let compiled: Vec<regex::Regex> = PATTERNS.iter()
        .filter_map(|p| regex::Regex::new(p).ok())
        .collect();

    let ws = PathBuf::from(&workspace);
    let mut endpoints = Vec::new();

    for entry in walkdir::WalkDir::new(&ws)
        .follow_links(false)
        .max_depth(6)
        .into_iter()
        .filter_map(|e| e.ok())
        .filter(|e| {
            let ext = e.path().extension().and_then(|x| x.to_str()).unwrap_or("");
            matches!(ext, "js" | "ts" | "jsx" | "tsx" | "rs" | "py" | "go" | "java")
        })
        .take(500)
    {
        if endpoints.len() >= 60 { break; }
        if let Ok(content) = std::fs::read_to_string(entry.path()) {
            for line in content.lines() {
                let trimmed = line.trim().to_string();
                if compiled.iter().any(|re| re.is_match(&trimmed))
                    && !endpoints.contains(&trimmed) {
                        endpoints.push(trimmed);
                        if endpoints.len() >= 60 { break; }
                    }
            }
        }
    }
    Ok(endpoints)
}

