/// Serializable team info for the frontend.
#[derive(Debug, Clone, Serialize)]
pub struct AgentTeamInfo {
    pub id: String,
    pub lead_agent_id: String,
    pub member_ids: Vec<String>,
    pub goal: String,
    pub status: String,
    pub tasks: Vec<AgentTeamTask>,
    pub message_count: usize,
    pub messages: Vec<AgentTeamMessage>,
}

#[derive(Debug, Clone, Serialize)]
pub struct AgentTeamTask {
    pub id: String,
    pub agent_id: String,
    pub description: String,
    pub status: String,
    pub result: Option<String>,
    pub generated_files: Vec<String>,
}

#[derive(Debug, Clone, Serialize)]
pub struct AgentTeamMessage {
    pub from_agent_id: String,
    pub to_agent_id: Option<String>,
    pub msg_type: String,
    pub content: String,
    pub timestamp: u64,
}

/// Sanitize a string for use as a filename component.
fn sanitize_filename(s: &str) -> String {
    s.chars()
        .map(|c| if c.is_alphanumeric() || c == '-' || c == '_' { c } else { '_' })
        .take(50)
        .collect::<String>()
        .trim_end_matches('_')
        .to_string()
}

/// A code block extracted from an AI response, tagged with a file path.
struct ExtractedFile {
    path: String,
    content: String,
}

/// Extract fenced code blocks with file paths from an AI response.
///
/// Recognises patterns like:
///   ```rust:src/main.rs
///   ```path/to/file.ts
///   ``` src/lib.rs
/// The path must contain at least one `/` or `.` to be treated as a file path
/// (avoids matching bare language names like ```rust).
fn extract_code_files(response: &str) -> Vec<ExtractedFile> {
    let mut files = Vec::new();
    let mut lines = response.lines().peekable();

    while let Some(line) = lines.next() {
        let trimmed = line.trim();
        if !trimmed.starts_with("```") {
            continue;
        }

        // Parse the fence header: ```lang:path, ```path, or ``` path
        let after_ticks = trimmed.trim_start_matches('`');
        if after_ticks.is_empty() {
            // closing fence or bare ``` — skip
            continue;
        }

        let path = if let Some((_lang, p)) = after_ticks.split_once(':') {
            // ```rust:src/main.rs
            p.trim().to_string()
        } else {
            // ```src/main.rs  or  ``` src/main.rs
            after_ticks.trim().to_string()
        };

        // Validate it looks like a file path (contains / or .)
        if !path.contains('/') && !path.contains('.') {
            // Probably just a language name like "rust" or "typescript" — skip content
            for l in lines.by_ref() {
                if l.trim().starts_with("```") { break; }
            }
            continue;
        }

        // Reject paths that try to escape the project root
        if path.contains("..") || path.starts_with('/') {
            for l in lines.by_ref() {
                if l.trim().starts_with("```") { break; }
            }
            continue;
        }

        // Collect content until closing fence
        let mut content = String::new();
        for l in lines.by_ref() {
            if l.trim().starts_with("```") { break; }
            if !content.is_empty() { content.push('\n'); }
            content.push_str(l);
        }

        if !content.is_empty() {
            files.push(ExtractedFile { path, content });
        }
    }

    files
}

/// Start an agent team with a goal and member count.
/// The lead agent decomposes the goal into sub-tasks using AI.
#[tauri::command]
pub async fn start_agent_team(
    goal: String,
    member_count: usize,
    state: tauri::State<'_, AppState>,
    app_handle: tauri::AppHandle,
) -> Result<AgentTeamInfo, String> {
    use vibe_ai::agent_team::*;

    let member_count = member_count.clamp(2, 8);
    let team_id = format!("team-{}", std::time::SystemTime::now()
        .duration_since(std::time::UNIX_EPOCH).unwrap_or_default().as_millis() % 100000);
    let lead_id = format!("{}-lead", team_id);

    let mut team = AgentTeam::new(&team_id, &lead_id, &goal);

    // Add member agents
    for i in 0..member_count.saturating_sub(1) {
        team.add_member(&format!("{}-worker-{}", team_id, i));
    }

    // Use AI to decompose the goal into sub-tasks
    let engine = state.chat_engine.lock().await;
    if let Some(provider) = engine.active_provider() {
        let decompose_prompt = format!(
            "Decompose this task into {} sub-tasks for a team of AI agents. \
             Return only a numbered list, one sub-task per line, no explanations:\n\n{}",
            member_count, goal
        );
        let messages = vec![vibe_ai::Message {
            role: vibe_ai::MessageRole::User,
            content: decompose_prompt,
        }];

        match provider.chat(&messages, None).await {
            Ok(response) => {
                let subtasks: Vec<TeamSubTask> = response
                    .lines()
                    .filter(|l| !l.trim().is_empty())
                    .enumerate()
                    .take(member_count)
                    .map(|(i, line)| {
                        let desc = line.trim().trim_start_matches(|c: char| c.is_ascii_digit() || c == '.' || c == ')' || c == ' ').to_string();
                        let agent_id = if i == 0 {
                            lead_id.clone()
                        } else {
                            format!("{}-worker-{}", team_id, i.saturating_sub(1))
                        };
                        TeamSubTask {
                            id: format!("task-{}", i),
                            agent_id,
                            description: if desc.is_empty() { line.trim().to_string() } else { desc },
                            status: TeamTaskStatus::Pending,
                            result: None,
                            generated_files: vec![],
                        }
                    })
                    .collect();

                team.set_tasks(subtasks).await;
            }
            Err(e) => {
                eprintln!("[warn] Failed to decompose team goal: {}", e);
            }
        }
    }

    team.set_status("working").await;

    // Announce team formation on the bus
    team.bus.send(TeamMessage::new(
        &lead_id,
        TeamMessageType::Status,
        &format!("Team formed with {} members. Goal: {}", team.member_ids.len(), goal),
    )).await.map_err(|e| e.to_string())?;

    // Emit Tauri event
    let _ = app_handle.emit("team:created", serde_json::json!({
        "team_id": team_id,
        "goal": goal,
        "members": team.member_ids,
    }));

    let info = team_to_info(&team).await;

    // Store the team in AppState so get_team_status works
    {
        let mut active = state.active_team.lock().await;
        *active = Some(team);
    }

    // Resolve the project root from the workspace's first folder
    let project_root = {
        let ws = state.workspace.lock().await;
        ws.folders().first().cloned().unwrap_or_else(|| std::env::current_dir().unwrap_or_default())
    };

    // Spawn background workers to execute each task via AI
    let chat_engine = state.chat_engine.clone();
    let active_team = state.active_team.clone();
    let app = app_handle.clone();
    let goal_clone = goal.clone();

    tokio::spawn(async move {
        use vibe_ai::agent_team::*;
        let project_root = project_root;

        let team_guard = active_team.lock().await;
        let team = match team_guard.as_ref() {
            Some(t) => t,
            None => return,
        };

        let task_list: Vec<(String, String, String)> = {
            let tasks = team.tasks.lock().await;
            tasks.iter().map(|t| (t.id.clone(), t.agent_id.clone(), t.description.clone())).collect()
        };
        let bus = team.bus.clone();
        drop(team_guard);

        for (task_id, agent_id, description) in task_list {
            // Mark task InProgress
            {
                let team_guard = active_team.lock().await;
                if let Some(team) = team_guard.as_ref() {
                    let mut tasks = team.tasks.lock().await;
                    if let Some(t) = tasks.iter_mut().find(|t| t.id == task_id) {
                        t.status = TeamTaskStatus::InProgress;
                    }
                }
            }

            let _ = bus.send(TeamMessage::new(
                &agent_id,
                TeamMessageType::Status,
                &format!("Starting: {}", description),
            )).await;

            let _ = app.emit("team:updated", &task_id);

            // Execute via AI
            let result = {
                let engine = chat_engine.lock().await;
                let prompt = format!(
                    "You are agent '{}' on a team working toward: {}\n\n\
                     Your assigned sub-task: {}\n\n\
                     Complete this sub-task. Generate the required code files.\n\
                     For each file, use a fenced code block with the file path after the backticks, e.g.:\n\
                     ```src/auth/jwt.rs\n\
                     // code here\n\
                     ```\n\n\
                     After the code blocks, provide a brief summary of what you created or changed.",
                    agent_id, goal_clone, description
                );
                let messages = vec![vibe_ai::Message {
                    role: vibe_ai::MessageRole::User,
                    content: prompt,
                }];
                engine.chat(&messages, None).await
            };

            // Update task status and write code artifacts to the project
            {
                let team_guard = active_team.lock().await;
                if let Some(team) = team_guard.as_ref() {
                    let mut tasks = team.tasks.lock().await;
                    if let Some(t) = tasks.iter_mut().find(|t| t.id == task_id) {
                        match &result {
                            Ok(response) => {
                                t.status = TeamTaskStatus::Completed;
                                t.result = Some(response.clone());

                                // Extract code blocks and write files to the project
                                let extracted = extract_code_files(response);
                                let mut written_files = Vec::new();
                                for file in &extracted {
                                    let target = project_root.join(&file.path);
                                    if let Some(parent) = target.parent() {
                                        let _ = std::fs::create_dir_all(parent);
                                    }
                                    if std::fs::write(&target, &file.content).is_ok() {
                                        written_files.push(file.path.clone());
                                    }
                                }
                                t.generated_files = written_files.clone();

                                let files_msg = if written_files.is_empty() {
                                    "Completed (no files generated)".to_string()
                                } else {
                                    format!("Completed — wrote {} file(s): {}", written_files.len(), written_files.join(", "))
                                };
                                let _ = bus.send(TeamMessage::new(
                                    &agent_id,
                                    TeamMessageType::Finding,
                                    &files_msg,
                                )).await;
                            }
                            Err(e) => {
                                t.status = TeamTaskStatus::Failed;
                                t.result = Some(format!("Error: {}", e));
                                let _ = bus.send(TeamMessage::new(
                                    &agent_id,
                                    TeamMessageType::Challenge,
                                    &format!("Failed: {}", e),
                                )).await;
                            }
                        }
                    }
                }
            }

            let _ = app.emit("team:updated", &task_id);
        }

        // Mark team complete
        {
            let team_guard = active_team.lock().await;
            if let Some(team) = team_guard.as_ref() {
                team.set_status("complete").await;
                let _ = bus.send(TeamMessage::new(
                    "system",
                    TeamMessageType::Status,
                    "All tasks completed. Team work finished.",
                )).await;
            }
        }
        let _ = app.emit("team:updated", "done");
    });

    Ok(info)
}

/// Get the current status of a team.
#[tauri::command]
pub async fn get_team_status(
    team_id: String,
    state: tauri::State<'_, AppState>,
) -> Result<AgentTeamInfo, String> {
    let active = state.active_team.lock().await;
    match active.as_ref() {
        Some(team) if team.id == team_id => Ok(team_to_info(team).await),
        _ => Err(format!("Team {} not found in active registry", team_id)),
    }
}

/// Send a message on the team bus (from the user/UI to agents).
#[tauri::command]
pub async fn send_team_message(
    team_id: String,
    content: String,
    state: tauri::State<'_, AppState>,
) -> Result<(), String> {
    use vibe_ai::agent_team::*;
    let active = state.active_team.lock().await;
    match active.as_ref() {
        Some(team) if team.id == team_id => {
            team.bus.send(TeamMessage::new("user", TeamMessageType::Request, &content))
                .await.map_err(|e| e.to_string())
        }
        _ => Err(format!("Team {} not found", team_id)),
    }
}

/// Dismiss the active team, saving it to history first.
#[tauri::command]
pub async fn dismiss_team(
    state: tauri::State<'_, AppState>,
) -> Result<(), String> {
    let mut active = state.active_team.lock().await;
    if let Some(team) = active.as_ref() {
        let info = team_to_info(team).await;
        let dir = project_data_dir("teams").unwrap_or_else(|_| dirs::home_dir().unwrap_or_default().join(".vibeui"));
        let _ = std::fs::create_dir_all(&dir);

        // Write full artifacts for this run
        let artifacts_dir = dir.join("team_artifacts").join(&info.id);
        let _ = std::fs::create_dir_all(&artifacts_dir);

        // Save each task result as a separate file
        for task in &info.tasks {
            if let Some(result) = &task.result {
                let filename = format!("{}-{}.md", task.id, sanitize_filename(&task.description));
                let content = format!(
                    "# Task: {}\n\n**Agent:** {}\n**Status:** {}\n\n---\n\n{}\n",
                    task.description, task.agent_id, task.status, result
                );
                let _ = std::fs::write(artifacts_dir.join(&filename), &content);
            }
        }

        // Save all messages
        let messages_json: Vec<serde_json::Value> = info.messages.iter().map(|m| {
            serde_json::json!({
                "from": m.from_agent_id,
                "to": m.to_agent_id,
                "type": m.msg_type,
                "content": m.content,
            })
        }).collect();
        let _ = std::fs::write(
            artifacts_dir.join("messages.json"),
            serde_json::to_string_pretty(&messages_json).unwrap_or_default(),
        );

        // Save summary
        let summary = serde_json::json!({
            "id": info.id,
            "goal": info.goal,
            "status": info.status,
            "member_ids": info.member_ids,
            "tasks": info.tasks.iter().map(|t| serde_json::json!({
                "id": t.id,
                "agent_id": t.agent_id,
                "description": t.description,
                "status": t.status,
                "result": t.result,
                "generated_files": t.generated_files,
            })).collect::<Vec<_>>(),
            "completed_at": chrono::Utc::now().to_rfc3339(),
        });
        let _ = std::fs::write(
            artifacts_dir.join("summary.json"),
            serde_json::to_string_pretty(&summary).unwrap_or_default(),
        );

        // Append entry to history index
        let entry = serde_json::json!({
            "id": info.id,
            "goal": info.goal,
            "status": info.status,
            "member_count": info.member_ids.len(),
            "task_count": info.tasks.len(),
            "artifacts_dir": artifacts_dir.to_string_lossy(),
            "completed_at": chrono::Utc::now().to_rfc3339(),
        });
        let path = dir.join("team_history.json");
        let mut history: Vec<serde_json::Value> = std::fs::read_to_string(&path)
            .ok()
            .and_then(|s| serde_json::from_str(&s).ok())
            .unwrap_or_default();
        history.insert(0, entry);
        history.truncate(50);
        let _ = std::fs::write(&path, serde_json::to_string_pretty(&history).unwrap_or_default());
    }
    *active = None;
    Ok(())
}

/// Get history of past team runs.
#[tauri::command]
pub async fn get_team_history() -> Result<serde_json::Value, String> {
    let path = project_data_dir("teams").unwrap_or_else(|_| dirs::home_dir().unwrap_or_default().join(".vibeui")).join("team_history.json");
    let history: Vec<serde_json::Value> = std::fs::read_to_string(&path)
        .ok()
        .and_then(|s| serde_json::from_str(&s).ok())
        .unwrap_or_default();
    Ok(serde_json::json!(history))
}

async fn team_to_info(team: &vibe_ai::agent_team::AgentTeam) -> AgentTeamInfo {
    let tasks = team.tasks.lock().await;
    let history = team.bus.history().await;

    AgentTeamInfo {
        id: team.id.clone(),
        lead_agent_id: team.lead_agent_id.clone(),
        member_ids: team.member_ids.clone(),
        goal: team.goal.clone(),
        status: team.get_status().await,
        tasks: tasks.iter().map(|t| AgentTeamTask {
            id: t.id.clone(),
            agent_id: t.agent_id.clone(),
            description: t.description.clone(),
            status: format!("{:?}", t.status),
            result: t.result.clone(),
            generated_files: t.generated_files.clone(),
        }).collect(),
        message_count: history.len(),
        messages: history.iter().map(|m| AgentTeamMessage {
            from_agent_id: m.from_agent_id.clone(),
            to_agent_id: m.to_agent_id.clone(),
            msg_type: format!("{:?}", m.msg_type),
            content: m.content.clone(),
            timestamp: m.timestamp,
        }).collect(),
    }
}

