// ── Sub-Agent Management ────────────────────────────────────────────────────

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct SubAgentDto {
    pub id: String,
    pub role: String,
    pub status: String,       // "idle" | "working" | "completed" | "failed"
    pub context_files: Vec<String>,
    pub provider: String,
    pub task_description: Option<String>,
    pub result_summary: Option<String>,
    pub findings: Vec<String>,
    pub files_modified: Vec<String>,
    pub created_at: String,    // ISO timestamp
    pub completed_at: Option<String>,
    pub error: Option<String>,
    pub tokens_used: Option<u64>,
}

#[tauri::command]
pub async fn list_sub_agents(
    state: tauri::State<'_, AppState>,
) -> Result<Vec<SubAgentDto>, String> {
    let agents = state.sub_agents.lock().await;
    Ok(agents.clone())
}

#[tauri::command]
pub async fn spawn_sub_agent(
    role: String,
    task: String,
    context_files: Vec<String>,
    provider: String,
    state: tauri::State<'_, AppState>,
    app_handle: tauri::AppHandle,
) -> Result<SubAgentDto, String> {
    let id = format!("sa-{}", chrono::Utc::now().timestamp_millis());
    let agent = SubAgentDto {
        id: id.clone(),
        role: role.clone(),
        status: "working".into(),
        context_files: context_files.clone(),
        provider: provider.clone(),
        task_description: Some(task.clone()),
        result_summary: None,
        findings: vec![],
        files_modified: vec![],
        created_at: chrono::Utc::now().to_rfc3339(),
        completed_at: None,
        error: None,
        tokens_used: None,
    };

    {
        let mut agents = state.sub_agents.lock().await;
        agents.push(agent.clone());
    }

    // Clone Arc fields for the background task
    let sub_agents = state.sub_agents.clone();
    let chat_engine = state.chat_engine.clone();
    let workspace = state.workspace.clone();
    let agent_id = id.clone();
    let app = app_handle.clone();

    tokio::spawn(async move {
        let result = run_sub_agent_task(
            &workspace, &chat_engine, &agent_id, &role, &task, &context_files, &provider,
        ).await;

        let mut agents = sub_agents.lock().await;
        if let Some(agent) = agents.iter_mut().find(|a| a.id == agent_id) {
            match result {
                Ok((summary, findings, files)) => {
                    agent.status = "completed".into();
                    agent.result_summary = Some(summary);
                    agent.findings = findings;
                    agent.files_modified = files;
                    agent.completed_at = Some(chrono::Utc::now().to_rfc3339());
                }
                Err(e) => {
                    agent.status = "failed".into();
                    agent.error = Some(e);
                    agent.completed_at = Some(chrono::Utc::now().to_rfc3339());
                }
            }
        }
        // Emit event so frontend can refresh
        let _ = app.emit("subagent:updated", &agent_id);
    });

    Ok(agent) // Return immediately with "working" status
}

async fn run_sub_agent_task(
    workspace: &Arc<Mutex<Workspace>>,
    chat_engine: &Arc<Mutex<ChatEngine>>,
    _agent_id: &str,
    role: &str,
    task: &str,
    context_files: &[String],
    provider_name: &str,
) -> Result<(String, Vec<String>, Vec<String>), String> {
    let mut prompt = format!("You are a {} sub-agent. Your task:\n{}\n\n", role, task);

    // Read context files
    {
        let ws = workspace.lock().await;
        let root = ws.folders().first().cloned().unwrap_or_else(|| PathBuf::from("."));
        drop(ws);

        for file in context_files {
            let full_path = if file.starts_with('/') {
                file.clone()
            } else {
                format!("{}/{}", root.display(), file)
            };
            match std::fs::read_to_string(&full_path) {
                Ok(content) => {
                    let trimmed = if content.len() > 8000 {
                        format!("{}... (truncated)", &content[..8000])
                    } else {
                        content
                    };
                    prompt.push_str(&format!("=== {} ===\n{}\n\n", file, trimmed));
                }
                Err(_) => {
                    prompt.push_str(&format!("=== {} === (file not found)\n\n", file));
                }
            }
        }
    }

    prompt.push_str(
        "\nProvide your analysis in this exact format:\n\
         SUMMARY: A one-line summary of your findings\n\
         FINDINGS:\n- Finding 1\n- Finding 2\n...\n\
         FILES_MODIFIED: file1.rs, file2.rs (or NONE if no files were modified)\n"
    );

    let messages = vec![
        vibe_ai::Message {
            role: vibe_ai::MessageRole::User,
            content: prompt,
        },
    ];

    // Single lock: set provider then chat
    let response = {
        let mut engine = chat_engine.lock().await;
        let _ = engine.set_provider_by_name(provider_name);
        engine.chat(&messages, None).await.map_err(|e| e.to_string())?
    };

    // Parse response
    let mut summary = String::new();
    let mut findings = Vec::new();
    let mut files = Vec::new();
    let mut in_findings = false;

    for line in response.lines() {
        let line = line.trim();
        if line.starts_with("SUMMARY:") {
            summary = line.trim_start_matches("SUMMARY:").trim().to_string();
            in_findings = false;
        } else if line.starts_with("FINDINGS:") {
            in_findings = true;
        } else if line.starts_with("FILES_MODIFIED:") {
            in_findings = false;
            let files_str = line.trim_start_matches("FILES_MODIFIED:").trim();
            if files_str != "NONE" && !files_str.is_empty() {
                files = files_str.split(',').map(|s| s.trim().to_string()).filter(|s| !s.is_empty()).collect();
            }
        } else if in_findings && line.starts_with("- ") {
            findings.push(line.trim_start_matches("- ").to_string());
        }
    }

    if summary.is_empty() {
        summary = response.lines().next().unwrap_or("Task completed").to_string();
        if summary.len() > 200 {
            summary.truncate(200);
            summary.push_str("...");
        }
    }

    Ok((summary, findings, files))
}

#[tauri::command]
pub async fn dismiss_sub_agent(
    agent_id: String,
    state: tauri::State<'_, AppState>,
) -> Result<(), String> {
    let mut agents = state.sub_agents.lock().await;
    agents.retain(|a| a.id != agent_id);
    Ok(())
}

#[tauri::command]
pub async fn clear_completed_sub_agents(
    state: tauri::State<'_, AppState>,
) -> Result<(), String> {
    let mut agents = state.sub_agents.lock().await;
    agents.retain(|a| a.status == "working");
    Ok(())
}

// ── CI Status Check Commands ─────────────────────────────────────────────────

#[derive(Serialize, Clone)]
pub struct CiCheckSuite {
    pub id: String,
    pub name: String,
    pub state: String,
    pub branch: String,
    pub commit: String,
    pub duration: String,
    #[serde(rename = "checksCount")]
    pub checks_count: u32,
    #[serde(rename = "passCount")]
    pub pass_count: u32,
}

#[derive(Serialize, Clone)]
pub struct CiCheck {
    pub id: String,
    #[serde(rename = "suiteId")]
    pub suite_id: String,
    pub name: String,
    pub state: String,
    pub annotations: u32,
    pub duration: String,
    pub message: String,
}

#[derive(Serialize, Deserialize, Clone)]
pub struct CiCheckConfig {
    pub id: String,
    pub name: String,
    pub enabled: bool,
    pub required: bool,
    pub threshold: u32,
}

/// Detect CI configuration files in the workspace and return check suites.
#[tauri::command]
pub async fn get_ci_status(workspace: String) -> Result<Vec<CiCheckSuite>, String> {
    let ws = std::path::Path::new(&workspace);
    let mut suites = Vec::new();

    // Get current branch and commit from git
    let branch = tokio::process::Command::new("git")
        .args(["rev-parse", "--abbrev-ref", "HEAD"])
        .current_dir(&workspace)
        .output()
        .await
        .ok()
        .and_then(|o| if o.status.success() { Some(String::from_utf8_lossy(&o.stdout).trim().to_string()) } else { None })
        .unwrap_or_else(|| "unknown".to_string());

    let commit = tokio::process::Command::new("git")
        .args(["rev-parse", "--short", "HEAD"])
        .current_dir(&workspace)
        .output()
        .await
        .ok()
        .and_then(|o| if o.status.success() { Some(String::from_utf8_lossy(&o.stdout).trim().to_string()) } else { None })
        .unwrap_or_else(|| "0000000".to_string());

    let mut idx = 0u32;
    let mut add_suite = |name: &str, checks_count: u32| -> CiCheckSuite {
        idx += 1;
        CiCheckSuite {
            id: format!("s{idx}"),
            name: name.to_string(),
            state: "pending".to_string(),
            branch: branch.clone(),
            commit: commit.clone(),
            duration: "--".to_string(),
            checks_count,
            pass_count: 0,
        }
    };

    // GitHub Actions
    let gh_workflows = ws.join(".github").join("workflows");
    if gh_workflows.is_dir() {
        if let Ok(entries) = std::fs::read_dir(&gh_workflows) {
            let count = entries
                .filter_map(|e| e.ok())
                .filter(|e| {
                    let ext = e.path().extension().map(|x| x.to_string_lossy().to_string()).unwrap_or_default();
                    ext == "yml" || ext == "yaml"
                })
                .count() as u32;
            if count > 0 {
                suites.push(add_suite("GitHub Actions", count));
            }
        }
    }

    // GitLab CI
    if ws.join(".gitlab-ci.yml").exists() {
        suites.push(add_suite("GitLab CI", 1));
    }

    // Jenkinsfile
    if ws.join("Jenkinsfile").exists() {
        suites.push(add_suite("Jenkins", 1));
    }

    // CircleCI
    if ws.join(".circleci").join("config.yml").exists() {
        suites.push(add_suite("CircleCI", 1));
    }

    // Bitbucket Pipelines
    if ws.join("bitbucket-pipelines.yml").exists() {
        suites.push(add_suite("Bitbucket Pipelines", 1));
    }

    // Azure DevOps
    if ws.join("azure-pipelines.yml").exists() {
        suites.push(add_suite("Azure DevOps", 1));
    }

    // Travis CI
    if ws.join(".travis.yml").exists() {
        suites.push(add_suite("Travis CI", 1));
    }

    Ok(suites)
}

/// List individual check items derived from CI configuration files.
#[tauri::command]
pub async fn get_ci_checks(workspace: String) -> Result<Vec<CiCheck>, String> {
    let ws = std::path::Path::new(&workspace);
    let mut checks = Vec::new();
    let mut idx = 0u32;
    let mut suite_idx = 0u32;

    // GitHub Actions — one check per workflow file
    let gh_workflows = ws.join(".github").join("workflows");
    if gh_workflows.is_dir() {
        suite_idx += 1;
        let suite_id = format!("s{suite_idx}");
        if let Ok(entries) = std::fs::read_dir(&gh_workflows) {
            for entry in entries.flatten() {
                let path = entry.path();
                let ext = path.extension().map(|x| x.to_string_lossy().to_string()).unwrap_or_default();
                if ext == "yml" || ext == "yaml" {
                    idx += 1;
                    let name = path.file_stem()
                        .map(|s| s.to_string_lossy().to_string())
                        .unwrap_or_else(|| "workflow".to_string());
                    checks.push(CiCheck {
                        id: format!("c{idx}"),
                        suite_id: suite_id.clone(),
                        name,
                        state: "pending".to_string(),
                        annotations: 0,
                        duration: "--".to_string(),
                        message: "Detected from .github/workflows/".to_string(),
                    });
                }
            }
        }
    }

    // GitLab CI
    if ws.join(".gitlab-ci.yml").exists() {
        suite_idx += 1;
        idx += 1;
        checks.push(CiCheck {
            id: format!("c{idx}"),
            suite_id: format!("s{suite_idx}"),
            name: "GitLab CI Pipeline".to_string(),
            state: "pending".to_string(),
            annotations: 0,
            duration: "--".to_string(),
            message: "Detected .gitlab-ci.yml".to_string(),
        });
    }

    // Jenkinsfile
    if ws.join("Jenkinsfile").exists() {
        suite_idx += 1;
        idx += 1;
        checks.push(CiCheck {
            id: format!("c{idx}"),
            suite_id: format!("s{suite_idx}"),
            name: "Jenkinsfile Pipeline".to_string(),
            state: "pending".to_string(),
            annotations: 0,
            duration: "--".to_string(),
            message: "Detected Jenkinsfile".to_string(),
        });
    }

    // CircleCI
    if ws.join(".circleci").join("config.yml").exists() {
        suite_idx += 1;
        idx += 1;
        checks.push(CiCheck {
            id: format!("c{idx}"),
            suite_id: format!("s{suite_idx}"),
            name: "CircleCI Config".to_string(),
            state: "pending".to_string(),
            annotations: 0,
            duration: "--".to_string(),
            message: "Detected .circleci/config.yml".to_string(),
        });
    }

    // Bitbucket Pipelines
    if ws.join("bitbucket-pipelines.yml").exists() {
        suite_idx += 1;
        idx += 1;
        checks.push(CiCheck {
            id: format!("c{idx}"),
            suite_id: format!("s{suite_idx}"),
            name: "Bitbucket Pipeline".to_string(),
            state: "pending".to_string(),
            annotations: 0,
            duration: "--".to_string(),
            message: "Detected bitbucket-pipelines.yml".to_string(),
        });
    }

    // Azure DevOps
    if ws.join("azure-pipelines.yml").exists() {
        suite_idx += 1;
        idx += 1;
        checks.push(CiCheck {
            id: format!("c{idx}"),
            suite_id: format!("s{suite_idx}"),
            name: "Azure DevOps Pipeline".to_string(),
            state: "pending".to_string(),
            annotations: 0,
            duration: "--".to_string(),
            message: "Detected azure-pipelines.yml".to_string(),
        });
    }

    // Travis CI
    if ws.join(".travis.yml").exists() {
        suite_idx += 1;
        idx += 1;
        checks.push(CiCheck {
            id: format!("c{idx}"),
            suite_id: format!("s{suite_idx}"),
            name: "Travis CI Config".to_string(),
            state: "pending".to_string(),
            annotations: 0,
            duration: "--".to_string(),
            message: "Detected .travis.yml".to_string(),
        });
    }

    let _ = suite_idx; // suppress unused warning
    Ok(checks)
}

/// Return CI configuration summary (default checks that can be toggled).
#[tauri::command]
pub async fn get_ci_config(workspace: String) -> Result<Vec<CiCheckConfig>, String> {
    let ws = std::path::Path::new(&workspace);

    // Build a list of detected and common check configs
    let mut configs = Vec::new();
    let mut idx = 0u32;

    let mut add_cfg = |name: &str, enabled: bool, required: bool, threshold: u32| {
        idx += 1;
        configs.push(CiCheckConfig {
            id: format!("cfg{idx}"),
            name: name.to_string(),
            enabled,
            required,
            threshold,
        });
    };

    // Detect what tooling is present and offer relevant checks
    let has_cargo = ws.join("Cargo.toml").exists();
    let has_node = ws.join("package.json").exists();
    let has_python = ws.join("pyproject.toml").exists() || ws.join("setup.py").exists();

    // Universal checks
    add_cfg("Code Quality", true, true, 80);
    add_cfg("Secret Detection", true, true, 0);
    add_cfg("License Check", true, false, 0);

    if has_cargo {
        add_cfg("Cargo Test", true, true, 0);
        add_cfg("Cargo Clippy", true, false, 0);
        add_cfg("Cargo Fmt", true, false, 0);
    }
    if has_node {
        add_cfg("npm test", true, true, 0);
        add_cfg("ESLint", true, false, 0);
        add_cfg("Bundle Size", true, false, 5000);
    }
    if has_python {
        add_cfg("pytest", true, true, 0);
        add_cfg("flake8 / ruff", true, false, 0);
    }

    // Always offer these regardless of project type
    add_cfg("Dependency Audit", true, true, 0);
    add_cfg("SAST Analysis", true, false, 0);
    add_cfg("Benchmark Regression", false, false, 5);

    Ok(configs)
}

/// Trigger a local CI check (lint, test, fmt, etc.) and return (stdout, stderr, exit_code).
#[tauri::command]
pub async fn trigger_ci_check(
    workspace: String,
    check_name: String,
) -> Result<(String, String, i32), String> {
    let ws = std::path::Path::new(&workspace);

    // Map check names to commands
    let (program, args): (&str, Vec<&str>) = match check_name.as_str() {
        "Cargo Test" => ("cargo", vec!["test", "--workspace"]),
        "Cargo Clippy" => ("cargo", vec!["clippy", "--all-targets", "--", "-D", "warnings"]),
        "Cargo Fmt" => ("cargo", vec!["fmt", "--check"]),
        "npm test" => ("npm", vec!["test", "--", "--passWithNoTests"]),
        "ESLint" => ("npx", vec!["eslint", "."]),
        "pytest" => ("python", vec!["-m", "pytest"]),
        "flake8 / ruff" if ws.join("pyproject.toml").exists() => ("ruff", vec!["check", "."]),
        "flake8 / ruff" => ("flake8", vec!["."]),
        "Dependency Audit" if ws.join("Cargo.toml").exists() => ("cargo", vec!["audit"]),
        "Dependency Audit" if ws.join("package.json").exists() => ("npm", vec!["audit"]),
        "Dependency Audit" => ("echo", vec!["No dependency audit tool detected"]),
        "Secret Detection" => ("git", vec!["log", "--all", "-p", "-S", "PRIVATE_KEY", "--oneline", "-n", "1"]),
        "License Check" => ("echo", vec!["License check not yet configured"]),
        "Code Quality" => ("echo", vec!["Code quality check not yet configured"]),
        "SAST Analysis" => ("echo", vec!["SAST analysis not yet configured"]),
        "Benchmark Regression" => ("echo", vec!["Benchmark regression not yet configured"]),
        "Bundle Size" => ("echo", vec!["Bundle size check not yet configured"]),
        _ => ("echo", vec!["Unknown check"]),
    };

    let output = tokio::process::Command::new(program)
        .args(&args)
        .current_dir(&workspace)
        .output()
        .await
        .map_err(|e| format!("Failed to run {program}: {e}"))?;

    let stdout = String::from_utf8_lossy(&output.stdout).to_string();
    let stderr = String::from_utf8_lossy(&output.stderr).to_string();
    let code = output.status.code().unwrap_or(-1);

    Ok((stdout, stderr, code))
}

