/// Scaffold a new project from a template into a target directory
#[tauri::command]
pub async fn create_app_project(template_id: String, project_name: String, target_dir: String) -> Result<AppBuilderCreateResult, String> {
    if project_name.is_empty() { return Err("Project name cannot be empty".into()); }
    if !project_name.chars().all(|c| c.is_alphanumeric() || c == '-' || c == '_') {
        return Err(format!("Invalid project name: {project_name}"));
    }
    let project_dir = PathBuf::from(&target_dir).join(&project_name);
    tokio::fs::create_dir_all(&project_dir).await.map_err(|e| format!("Failed to create project directory: {e}"))?;
    let files: Vec<(&str, String)> = match template_id.as_str() {
        "react-spa" => vec![
            ("package.json", format!(r#"{{"name":"{}","private":true,"version":"0.1.0","type":"module","scripts":{{"dev":"vite","build":"tsc && vite build"}},"dependencies":{{"react":"^18.2.0","react-dom":"^18.2.0"}},"devDependencies":{{"@vitejs/plugin-react":"^4.0.0","typescript":"^5.0.0","vite":"^5.0.0","tailwindcss":"^3.4.0"}}}}"#, project_name)),
            ("src/App.tsx", format!("export default function App() {{\n  return <div className=\"min-h-screen\"><h1>{}</h1></div>;\n}}\n", project_name)),
            ("src/main.tsx", "import React from 'react';\nimport ReactDOM from 'react-dom/client';\nimport App from './App';\nReactDOM.createRoot(document.getElementById('root')!).render(<React.StrictMode><App /></React.StrictMode>);\n".into()),
            (".gitignore", "node_modules\ndist\n.env\n".into()),
        ],
        "rest-api" => vec![
            ("package.json", format!(r#"{{"name":"{}","version":"0.1.0","scripts":{{"dev":"tsx watch src/index.ts","build":"tsc"}},"dependencies":{{"express":"^4.18.0"}},"devDependencies":{{"@types/express":"^4.17.0","tsx":"^4.0.0","typescript":"^5.0.0"}}}}"#, project_name)),
            ("src/index.ts", "import express from 'express';\nconst app = express();\napp.use(express.json());\napp.get('/api/health', (_req, res) => res.json({ status: 'ok' }));\napp.listen(process.env.PORT || 3000);\n".into()),
            (".gitignore", "node_modules\ndist\n.env\n".into()),
        ],
        "nextjs-fullstack" => vec![
            ("package.json", format!(r#"{{"name":"{}","version":"0.1.0","scripts":{{"dev":"next dev","build":"next build"}},"dependencies":{{"next":"^14.0.0","react":"^18.2.0","react-dom":"^18.2.0"}}}}"#, project_name)),
            ("src/app/page.tsx", format!("export default function Home() {{\n  return <main><h1>{}</h1></main>;\n}}\n", project_name)),
            (".gitignore", "node_modules\n.next\n.env\n".into()),
        ],
        _ => vec![
            ("README.md", format!("# {}\n\nGenerated by VibeUI App Builder.\n", project_name)),
            (".gitignore", "node_modules\ndist\n.env\ntarget\n".into()),
        ],
    };
    let mut files_created = Vec::new();
    for (rel_path, content) in &files {
        let file_path = project_dir.join(rel_path);
        if let Some(parent) = file_path.parent() {
            tokio::fs::create_dir_all(parent).await.map_err(|e| format!("mkdir {}: {e}", parent.display()))?;
        }
        tokio::fs::write(&file_path, content).await.map_err(|e| format!("write {rel_path}: {e}"))?;
        files_created.push(rel_path.to_string());
    }
    let history_path = app_builder_history_path();
    if let Some(parent) = history_path.parent() { let _ = tokio::fs::create_dir_all(parent).await; }
    let mut history: Vec<AppBuilderHistoryEntry> = match tokio::fs::read_to_string(&history_path).await {
        Ok(data) => serde_json::from_str(&data).unwrap_or_default(),
        Err(_) => Vec::new(),
    };
    let now_ms = std::time::SystemTime::now().duration_since(std::time::UNIX_EPOCH).unwrap_or_default().as_millis();
    let now_s = std::time::SystemTime::now().duration_since(std::time::UNIX_EPOCH).unwrap_or_default().as_secs();
    history.push(AppBuilderHistoryEntry {
        id: format!("abh-{now_ms}"), name: project_name.clone(), template_id: template_id.clone(),
        target_dir: project_dir.to_string_lossy().to_string(), created_at: format!("{now_s}"), files: files_created.clone(),
    });
    if let Ok(json) = serde_json::to_string_pretty(&history) { let _ = tokio::fs::write(&history_path, json).await; }
    Ok(AppBuilderCreateResult {
        project_dir: project_dir.to_string_lossy().to_string(), files_created,
        message: format!("Project '{}' created with template '{}'.", project_name, template_id),
    })
}

/// Return past scaffolded projects from history file
#[tauri::command]
pub async fn get_app_builder_history() -> Result<Vec<AppBuilderHistoryEntry>, String> {
    let path = app_builder_history_path();
    match tokio::fs::read_to_string(&path).await {
        Ok(data) => serde_json::from_str(&data).map_err(|e| format!("Failed to parse history: {e}")),
        Err(_) => Ok(Vec::new()),
    }
}

/// AI-enhance a template config
#[tauri::command]
pub async fn enhance_app_template(idea: String, state: tauri::State<'_, AppState>) -> Result<AppBuilderEnhancedSpec, String> {
    if idea.trim().is_empty() { return Err("App idea cannot be empty".into()); }
    let title = idea.split(&['.', '\n'][..]).next().unwrap_or(&idea).trim().chars().take(60).collect::<String>();
    let title = if title.is_empty() { "My App".to_string() } else { title };
    let prompt = format!("Given this app idea, generate a JSON object with fields: title (string), userStories (array of 3-5 strings), techStack (array of strings), apiEndpoints (array of REST endpoint strings), uiComponents (array of strings), complexityEstimate (string). App idea: {}", idea);
    let chat_engine = state.chat_engine.lock().await;
    let messages = vec![Message { role: vibe_ai::provider::MessageRole::User, content: prompt }];
    let ai_result = chat_engine.chat(&messages, None).await;
    drop(chat_engine);
    if let Ok(response) = ai_result {
        let text = response.trim();
        let json_str = if let Some(start) = text.find('{') {
            if let Some(end) = text.rfind('}') { &text[start..=end] } else { text }
        } else { text };
        if let Ok(spec) = serde_json::from_str::<AppBuilderEnhancedSpec>(json_str) { return Ok(spec); }
    }
    let idea_lower = idea.to_lowercase();
    let mut tech_stack = vec!["TypeScript".to_string()];
    let mut api_endpoints = vec!["GET /api/health".to_string()];
    let mut ui_components = vec!["App".to_string(), "Sidebar".to_string()];
    if idea_lower.contains("react") || idea_lower.contains("frontend") || idea_lower.contains("dashboard") {
        tech_stack.extend(["React".into(), "Vite".into(), "TailwindCSS".into()]);
        ui_components.extend(["Dashboard".into(), "DataTable".into(), "Header".into()]);
    } else if idea_lower.contains("api") || idea_lower.contains("backend") || idea_lower.contains("server") {
        tech_stack.extend(["Node.js".into(), "Express".into(), "Prisma".into()]);
    } else {
        tech_stack.extend(["React".into(), "Node.js".into(), "PostgreSQL".into(), "TailwindCSS".into()]);
        ui_components.extend(["Dashboard".into(), "SettingsPanel".into()]);
    }
    if idea_lower.contains("auth") || idea_lower.contains("login") || idea_lower.contains("user") {
        api_endpoints.push("POST /api/auth/login".into());
        api_endpoints.push("POST /api/auth/register".into());
        ui_components.push("LoginForm".into());
    }
    if idea_lower.contains("data") || idea_lower.contains("crud") || idea_lower.contains("manage") {
        api_endpoints.extend(["GET /api/items".into(), "POST /api/items".into(), "PUT /api/items/:id".into(), "DELETE /api/items/:id".into()]);
    }
    let complexity = if idea.len() < 50 { "Low (~1 week for MVP)" } else if idea.len() < 200 { "Medium (~2-3 weeks for MVP)" } else { "High (~4-6 weeks for MVP)" };
    Ok(AppBuilderEnhancedSpec {
        title,
        user_stories: vec!["As a user, I can sign up and log in securely".into(), "As a user, I can view and manage my dashboard".into(), "As an admin, I can manage users and settings".into()],
        tech_stack, api_endpoints, ui_components, complexity_estimate: complexity.to_string(),
    })
}

// ── Batch Builder ────────────────────────────────────────────────────────────

fn batch_data_dir() -> Result<std::path::PathBuf, String> {
    project_data_dir("batch")
}

fn batch_read_json(filename: &str) -> serde_json::Value {
    let Ok(dir) = batch_data_dir() else { return serde_json::json!([]) };
    let path = dir.join(filename);
    std::fs::read_to_string(path)
        .ok()
        .and_then(|s| serde_json::from_str(&s).ok())
        .unwrap_or(serde_json::json!([]))
}

fn batch_write_json(filename: &str, data: &serde_json::Value) -> Result<(), String> {
    let dir = batch_data_dir()?;
    let path = dir.join(filename);
    let content = serde_json::to_string_pretty(data).map_err(|e| e.to_string())?;
    std::fs::write(path, content).map_err(|e| e.to_string())
}

/// Create a new batch run and persist it.
#[tauri::command]
pub async fn batch_create_run(spec: serde_json::Value) -> Result<serde_json::Value, String> {
    let mut runs = batch_read_json("runs.json");
    if !runs.is_array() { runs = serde_json::json!([]); }
    let idx = runs.as_array().map(|a| a.len()).unwrap_or(0) + 1;
    let id = format!("BR-{:03}", idx);
    let now = chrono::Utc::now().to_rfc3339();
    let mut run = spec.clone();
    if let Some(obj) = run.as_object_mut() {
        obj.insert("id".into(), serde_json::json!(id));
        obj.insert("status".into(), serde_json::json!("Queued"));
        obj.insert("createdAt".into(), serde_json::json!(now));
        obj.insert("progress".into(), serde_json::json!(0));
        obj.insert("elapsed".into(), serde_json::json!("0m 0s"));
        obj.insert("tokenUsed".into(), serde_json::json!(0));
        obj.insert("files".into(), serde_json::json!(0));
        obj.insert("lines".into(), serde_json::json!(0));
        obj.insert("qaScore".into(), serde_json::json!(0));
        obj.insert("logs".into(), serde_json::json!([]));
        obj.insert("findings".into(), serde_json::json!([]));
        obj.insert("agents".into(), serde_json::json!([]));
        obj.insert("phases".into(), serde_json::json!([]));
    }
    if let Some(arr) = runs.as_array_mut() { arr.push(run.clone()); }
    batch_write_json("runs.json", &runs)?;
    Ok(run)
}

/// List all batch runs (history).
#[tauri::command]
pub async fn batch_list_runs() -> Result<serde_json::Value, String> {
    Ok(batch_read_json("runs.json"))
}

/// Get a single batch run by ID.
#[tauri::command]
pub async fn batch_get_run(run_id: String) -> Result<serde_json::Value, String> {
    let runs = batch_read_json("runs.json");
    if let Some(arr) = runs.as_array() {
        if let Some(run) = arr.iter().find(|r| r.get("id").and_then(|v| v.as_str()) == Some(&run_id)) {
            return Ok(run.clone());
        }
    }
    Err(format!("Run {} not found", run_id))
}

/// Update a batch run's status and metrics.
#[tauri::command]
pub async fn batch_update_run(run_id: String, updates: serde_json::Value) -> Result<(), String> {
    let mut runs = batch_read_json("runs.json");
    if let Some(arr) = runs.as_array_mut() {
        if let Some(run) = arr.iter_mut().find(|r| r.get("id").and_then(|v| v.as_str()) == Some(&run_id)) {
            if let (Some(run_obj), Some(upd_obj)) = (run.as_object_mut(), updates.as_object()) {
                for (k, v) in upd_obj {
                    run_obj.insert(k.clone(), v.clone());
                }
            }
        }
    }
    batch_write_json("runs.json", &runs)
}

/// Delete a batch run.
#[tauri::command]
pub async fn batch_delete_run(run_id: String) -> Result<(), String> {
    let mut runs = batch_read_json("runs.json");
    if let Some(arr) = runs.as_array_mut() {
        arr.retain(|r| r.get("id").and_then(|v| v.as_str()) != Some(&run_id));
    }
    batch_write_json("runs.json", &runs)
}

/// Simulate running a batch — advances status through phases.
/// In a real implementation this would spawn agent tasks; here we generate
/// realistic incremental progress that the frontend polls.
#[tauri::command]
pub async fn batch_simulate_progress(run_id: String) -> Result<serde_json::Value, String> {
    let mut runs = batch_read_json("runs.json");
    let arr = runs.as_array_mut().ok_or("No runs")?;
    let run = arr.iter_mut()
        .find(|r| r.get("id").and_then(|v| v.as_str()) == Some(&run_id))
        .ok_or("Run not found")?;

    // Extract values before mutably borrowing
    let status = run.get("status").and_then(|v| v.as_str()).unwrap_or("Queued").to_string();
    let progress = run.get("progress").and_then(|v| v.as_u64()).unwrap_or(0);

    // Advance through statuses
    let (new_status, new_progress, phase_label) = match status.as_str() {
        "Queued" => ("Planning", 5u64, "Architecture Planning"),
        "Planning" => ("Generating", 15, "Generating Code"),
        "Generating" if progress < 50 => ("Generating", progress + 12, "Generating Code"),
        "Generating" => ("Validating", 55, "Validating Output"),
        "Validating" => ("Compiling", 65, "Compiling Project"),
        "Compiling" => ("Testing", 80, "Running Tests"),
        "Testing" if progress < 95 => ("Testing", progress + 8, "Running Tests"),
        "Testing" => ("Completed", 100, "All Phases Complete"),
        _ => ("Completed", progress, "Done"),
    };

    let files = (new_progress as f64 * 0.9) as u64;
    let lines = files * 135;
    let token_used = new_progress * 4800;

    if let Some(obj) = run.as_object_mut() {
        obj.insert("status".into(), serde_json::json!(new_status));
        obj.insert("progress".into(), serde_json::json!(new_progress));
        obj.insert("phaseLabel".into(), serde_json::json!(phase_label));
        obj.insert("files".into(), serde_json::json!(files));
        obj.insert("lines".into(), serde_json::json!(lines));
        obj.insert("tokenUsed".into(), serde_json::json!(token_used));
        // Generate a log entry for this step
        let now = chrono::Utc::now().to_rfc3339();
        let log = serde_json::json!({
            "level": if new_status == "Completed" { "Info" } else { "Debug" },
            "timestamp": now,
            "agentId": "System",
            "message": format!("Phase: {} — progress {}%", phase_label, new_progress),
        });
        if let Some(logs) = obj.get_mut("logs").and_then(|v| v.as_array_mut()) {
            logs.push(log);
        } else {
            obj.insert("logs".into(), serde_json::json!([log]));
        }
        if new_status == "Completed" {
            obj.insert("qaScore".into(), serde_json::json!(75 + (files % 20)));
            let duration_mins = 45 + (files % 30);
            obj.insert("duration".into(), serde_json::json!(format!("{}h {}m", duration_mins / 60, duration_mins % 60)));
            obj.insert("elapsed".into(), serde_json::json!(format!("{}m {}s", duration_mins, (files * 7) % 60)));
        }
    }

    let snapshot = run.clone();
    batch_write_json("runs.json", &runs)?;
    Ok(snapshot)
}

/// Save QA findings for a batch run.
#[tauri::command]
pub async fn batch_save_findings(run_id: String, findings: serde_json::Value) -> Result<(), String> {
    let mut runs = batch_read_json("runs.json");
    if let Some(arr) = runs.as_array_mut() {
        if let Some(run) = arr.iter_mut().find(|r| r.get("id").and_then(|v| v.as_str()) == Some(&run_id)) {
            if let Some(obj) = run.as_object_mut() {
                obj.insert("findings".into(), findings);
            }
        }
    }
    batch_write_json("runs.json", &runs)
}

/// Save migration config for a batch run.
#[tauri::command]
pub async fn batch_save_migration(run_id: String, migration: serde_json::Value) -> Result<(), String> {
    let mut runs = batch_read_json("runs.json");
    if let Some(arr) = runs.as_array_mut() {
        if let Some(run) = arr.iter_mut().find(|r| r.get("id").and_then(|v| v.as_str()) == Some(&run_id)) {
            if let Some(obj) = run.as_object_mut() {
                obj.insert("migration".into(), migration);
            }
        }
    }
    batch_write_json("runs.json", &runs)
}

// ── Cloud Autofix (persisted to ~/.vibeui/cloud-autofix.json) ────────────────

fn cloud_autofix_path() -> std::path::PathBuf {
    let home = std::env::var("HOME").unwrap_or_else(|_| ".".to_string());
    std::path::PathBuf::from(home).join(".vibeui").join("cloud-autofix.json")
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct AutofixAttempt {
    pub id: String,
    #[serde(rename = "type")]
    pub fix_type: String,
    pub description: String,
    pub confidence: u32,
    #[serde(rename = "testStatus")]
    pub test_status: String,
    #[serde(rename = "filesChanged")]
    pub files_changed: u32,
    pub status: String,
    #[serde(rename = "prNumber")]
    pub pr_number: String,
    #[serde(rename = "createdAt")]
    pub created_at: String,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct AutofixStats {
    #[serde(rename = "mergeRate")]
    pub merge_rate: f64,
    #[serde(rename = "totalAttempts")]
    pub total_attempts: u32,
    pub merged: u32,
    pub rejected: u32,
    pub pending: u32,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct AutofixConfig {
    #[serde(rename = "containerImage")]
    pub container_image: String,
    #[serde(rename = "timeoutMinutes")]
    pub timeout_minutes: u32,
    #[serde(rename = "cpuLimit")]
    pub cpu_limit: String,
    #[serde(rename = "memoryLimit")]
    pub memory_limit: String,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
struct CloudAutofixStore {
    attempts: Vec<AutofixAttempt>,
    config: AutofixConfig,
}

impl Default for CloudAutofixStore {
    fn default() -> Self {
        Self {
            attempts: vec![],
            config: AutofixConfig {
                container_image: "node:20-slim".to_string(),
                timeout_minutes: 10,
                cpu_limit: "2".to_string(),
                memory_limit: "4Gi".to_string(),
            },
        }
    }
}

async fn load_cloud_autofix_store() -> Result<CloudAutofixStore, String> {
    let path = cloud_autofix_path();
    if !path.exists() {
        return Ok(CloudAutofixStore::default());
    }
    let content = tokio::fs::read_to_string(&path).await
        .map_err(|e| format!("Read error: {e}"))?;
    serde_json::from_str::<CloudAutofixStore>(&content)
        .map_err(|e| format!("Parse error: {e}"))
}

async fn save_cloud_autofix_store(store: &CloudAutofixStore) -> Result<(), String> {
    let path = cloud_autofix_path();
    if let Some(parent) = path.parent() {
        tokio::fs::create_dir_all(parent).await
            .map_err(|e| format!("Mkdir error: {e}"))?;
    }
    let json = serde_json::to_string_pretty(store)
        .map_err(|e| format!("Serialize error: {e}"))?;
    tokio::fs::write(&path, json).await
        .map_err(|e| format!("Write error: {e}"))?;
    Ok(())
}

/// Return all autofix attempts.
#[tauri::command]
pub async fn list_autofix_attempts() -> Result<Vec<AutofixAttempt>, String> {
    let store = load_cloud_autofix_store().await?;
    Ok(store.attempts)
}

/// Return autofix statistics computed from persisted attempts.
#[tauri::command]
pub async fn get_autofix_stats() -> Result<AutofixStats, String> {
    let store = load_cloud_autofix_store().await?;
    let total = store.attempts.len() as u32;
    let merged = store.attempts.iter().filter(|a| a.status == "merged").count() as u32;
    let rejected = store.attempts.iter().filter(|a| a.status == "rejected").count() as u32;
    let pending = total - merged - rejected;
    let merge_rate = if total > 0 { (merged as f64 / total as f64) * 100.0 } else { 0.0 };
    Ok(AutofixStats { merge_rate, total_attempts: total, merged, rejected, pending })
}

/// Create a new autofix attempt for a pull request.
#[tauri::command]
pub async fn create_autofix_attempt(
    pr_number: String,
    fix_type: String,
    description: String,
    confidence: u32,
    files_changed: u32,
) -> Result<AutofixAttempt, String> {
    let mut store = load_cloud_autofix_store().await?;
    let attempt = AutofixAttempt {
        id: format!("af-{}", chrono::Utc::now().timestamp_millis()),
        fix_type,
        description,
        confidence,
        test_status: "pending".to_string(),
        files_changed,
        status: "pending".to_string(),
        pr_number,
        created_at: chrono::Utc::now().to_rfc3339(),
    };
    store.attempts.push(attempt.clone());
    save_cloud_autofix_store(&store).await?;
    Ok(attempt)
}

/// Update an autofix attempt's status (merged / rejected).
#[tauri::command]
pub async fn update_autofix_status(attempt_id: String, status: String) -> Result<AutofixAttempt, String> {
    let mut store = load_cloud_autofix_store().await?;
    let attempt = store.attempts.iter_mut().find(|a| a.id == attempt_id)
        .ok_or_else(|| format!("Attempt not found: {attempt_id}"))?;
    attempt.status = status;
    let snapshot = attempt.clone();
    save_cloud_autofix_store(&store).await?;
    Ok(snapshot)
}

/// Return autofix configuration (container image, timeout, resource limits).
#[tauri::command]
pub async fn get_autofix_config() -> Result<AutofixConfig, String> {
    let store = load_cloud_autofix_store().await?;
    Ok(store.config)
}

/// Save autofix configuration.
#[tauri::command]
pub async fn save_autofix_config(config: AutofixConfig) -> Result<(), String> {
    let mut store = load_cloud_autofix_store().await?;
    store.config = config;
    save_cloud_autofix_store(&store).await
}

// ── Team Governance (persisted to ~/.vibeui/team-governance.json) ────────────

fn governance_data_dir() -> Result<PathBuf, String> {
    let home = dirs::home_dir().ok_or("Cannot determine home directory")?;
    let dir = home.join(".vibeui");
    std::fs::create_dir_all(&dir).map_err(|e| e.to_string())?;
    Ok(dir)
}

fn governance_read() -> serde_json::Value {
    let Ok(dir) = governance_data_dir() else { return serde_json::json!({"plugins":[],"audit":[],"policies":{}}) };
    let path = dir.join("team-governance.json");
    std::fs::read_to_string(path)
        .ok()
        .and_then(|s| serde_json::from_str(&s).ok())
        .unwrap_or(serde_json::json!({"plugins":[],"audit":[],"policies":{}}))
}

fn governance_write(data: &serde_json::Value) -> Result<(), String> {
    let dir = governance_data_dir()?;
    let path = dir.join("team-governance.json");
    let content = serde_json::to_string_pretty(data).map_err(|e| e.to_string())?;
    std::fs::write(path, content).map_err(|e| e.to_string())
}

fn governance_append_audit(data: &mut serde_json::Value, action: &str, user: &str, detail: &str) {
    let now = chrono::Utc::now().format("%Y-%m-%d %H:%M").to_string();
    let entry = serde_json::json!({
        "timestamp": now,
        "action": action,
        "user": user,
        "detail": detail,
    });
    if let Some(arr) = data.get_mut("audit").and_then(|v| v.as_array_mut()) {
        arr.insert(0, entry);
    }
}

/// List all governance plugins with their approval status.
#[tauri::command]
pub async fn list_governance_plugins() -> Result<serde_json::Value, String> {
    let data = governance_read();
    Ok(data.get("plugins").cloned().unwrap_or(serde_json::json!([])))
}

/// Submit a new plugin for team approval.
#[tauri::command]
pub async fn submit_plugin_for_approval(
    name: String,
    version: String,
    visibility: String,
    author: String,
) -> Result<serde_json::Value, String> {
    let mut data = governance_read();
    let plugins = data.get("plugins").and_then(|v| v.as_array()).map(|a| a.len()).unwrap_or(0);
    let id = format!("gov-{}", plugins + 1);
    let plugin = serde_json::json!({
        "id": id,
        "name": name,
        "version": version,
        "visibility": visibility,
        "status": "Pending",
        "author": author,
    });
    if let Some(arr) = data.get_mut("plugins").and_then(|v| v.as_array_mut()) {
        arr.push(plugin.clone());
    }
    governance_append_audit(&mut data, "Plugin submitted", &author, &format!("{} v{}", name, version));
    governance_write(&data)?;
    Ok(plugin)
}

/// Approve a pending plugin by id.
#[tauri::command]
pub async fn approve_plugin(plugin_id: String, reviewer: String) -> Result<serde_json::Value, String> {
    let mut data = governance_read();
    let mut detail_str = String::new();
    if let Some(arr) = data.get_mut("plugins").and_then(|v| v.as_array_mut()) {
        if let Some(p) = arr.iter_mut().find(|p| p.get("id").and_then(|v| v.as_str()) == Some(&plugin_id)) {
            if let Some(obj) = p.as_object_mut() {
                let name = obj.get("name").and_then(|v| v.as_str()).unwrap_or("").to_string();
                let ver = obj.get("version").and_then(|v| v.as_str()).unwrap_or("").to_string();
                obj.insert("status".into(), serde_json::json!("Approved"));
                detail_str = format!("{} v{}", name, ver);
            }
        } else {
            return Err(format!("Plugin '{}' not found", plugin_id));
        }
    }
    governance_append_audit(&mut data, "Plugin approved", &reviewer, &detail_str);
    governance_write(&data)?;
    Ok(data.get("plugins").cloned().unwrap_or(serde_json::json!([])))
}

/// Reject a pending plugin by id.
#[tauri::command]
pub async fn reject_plugin(plugin_id: String, reviewer: String) -> Result<serde_json::Value, String> {
    let mut data = governance_read();
    let mut detail_str = String::new();
    if let Some(arr) = data.get_mut("plugins").and_then(|v| v.as_array_mut()) {
        if let Some(p) = arr.iter_mut().find(|p| p.get("id").and_then(|v| v.as_str()) == Some(&plugin_id)) {
            if let Some(obj) = p.as_object_mut() {
                let name = obj.get("name").and_then(|v| v.as_str()).unwrap_or("").to_string();
                let ver = obj.get("version").and_then(|v| v.as_str()).unwrap_or("").to_string();
                obj.insert("status".into(), serde_json::json!("Rejected"));
                detail_str = format!("{} v{}", name, ver);
            }
        } else {
            return Err(format!("Plugin '{}' not found", plugin_id));
        }
    }
    governance_append_audit(&mut data, "Plugin rejected", &reviewer, &detail_str);
    governance_write(&data)?;
    Ok(data.get("plugins").cloned().unwrap_or(serde_json::json!([])))
}

/// Return audit trail entries for governance actions.
#[tauri::command]
pub async fn get_governance_audit_log() -> Result<serde_json::Value, String> {
    let data = governance_read();
    Ok(data.get("audit").cloned().unwrap_or(serde_json::json!([])))
}

/// Return team governance policies/rules.
#[tauri::command]
pub async fn get_governance_policies() -> Result<serde_json::Value, String> {
    let data = governance_read();
    Ok(data.get("policies").cloned().unwrap_or(serde_json::json!({
        "requireApproval": true,
        "allowedCategories": "linting,formatting,testing,deployment",
        "maxSizeMb": 50,
        "requireShaPin": true,
    })))
}

// ── GitHub Actions Panel ─────────────────────────────────────────────────

fn gh_actions_data_dir() -> Result<std::path::PathBuf, String> {
    let home = std::env::var("HOME").map_err(|_| "HOME not set".to_string())?;
    let dir = std::path::PathBuf::from(home).join(".vibeui").join("gh-actions");
    std::fs::create_dir_all(&dir).map_err(|e| e.to_string())?;
    Ok(dir)
}

fn gh_actions_read_json(filename: &str) -> serde_json::Value {
    let Ok(dir) = gh_actions_data_dir() else { return serde_json::json!([]) };
    let path = dir.join(filename);
    std::fs::read_to_string(path)
        .ok()
        .and_then(|s| serde_json::from_str(&s).ok())
        .unwrap_or(serde_json::json!([]))
}

fn gh_actions_write_json(filename: &str, data: &serde_json::Value) -> Result<(), String> {
    let dir = gh_actions_data_dir()?;
    let path = dir.join(filename);
    let content = serde_json::to_string_pretty(data).map_err(|e| e.to_string())?;
    std::fs::write(path, content).map_err(|e| e.to_string())
}

#[derive(Serialize, Deserialize, Clone)]
pub struct GhWorkflowTemplate {
    pub id: String,
    pub name: String,
    pub description: String,
    #[serde(rename = "estimatedMinutes")]
    pub estimated_minutes: u32,
    pub category: String,
}

#[derive(Serialize, Deserialize, Clone)]
pub struct GhSecretEntry {
    pub name: String,
    pub description: String,
    pub required: bool,
}

#[derive(Deserialize)]
pub struct GhWorkflowConfig {
    pub name: String,
    pub triggers: Vec<String>,
    pub jobs: Vec<String>,
}

